window.trendingPapers = {
    "today": [{"paper": {"id": "2607.04033", "authors": [{"_id": "6a4c985925849b193a834362", "name": "Siyuan Li", "hidden": false}, {"_id": "6a4c985925849b193a834363", "name": "Jiabao Pan", "hidden": false}, {"_id": "6a4c985925849b193a834364", "name": "Yumou Liu", "hidden": false}, {"_id": "6a4c985925849b193a834365", "name": "Zhuoli Ouyang", "hidden": false}, {"_id": "6a4c985925849b193a834366", "name": "Xin Jin", "hidden": false}, {"_id": "6a4c985925849b193a834367", "name": "Xinglong Xu", "hidden": false}, {"_id": "6a4c985925849b193a834368", "name": "Jingxuan Wei", "hidden": false}, {"_id": "6a4c985925849b193a834369", "name": "Shengye Pang", "hidden": false}, {"_id": "6a4c985925849b193a83436a", "name": "Jintao Che", "hidden": false}, {"_id": "6a4c985925849b193a83436b", "name": "Xuanhe Zhou", "hidden": false}, {"_id": "6a4c985925849b193a83436c", "name": "Conghui He", "hidden": false}, {"_id": "6a4c985925849b193a83436d", "name": "Cheng Tan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64be296a46cc3cdfbb057f7e/fcymBQFAev-N5KfQ67hXj.png"], "publishedAt": "2026-07-04T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "OmniOpt: Taxonomy, Geometry, and Benchmarking of Modern Optimizers", "submittedOnDailyBy": {"_id": "64be296a46cc3cdfbb057f7e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64be296a46cc3cdfbb057f7e/jSHeNY2AcPifCZzJyFhr4.jpeg", "isPro": false, "fullname": "Cheng Tan", "user": "chengtan9907", "type": "user", "name": "chengtan9907"}, "summary": "Optimizer selection for large-scale model training has become a system-level design decision constrained jointly by compute, memory, tuning budget, and task diversity, yet the landscape of over one hundred methods remains fragmented. We therefore present OmniOpt, a unified survey and benchmark cookbook of optimizers for the research community. OmniOpt rests on four coupled components. First, we treat every optimizer update as a structured transformation through a five-stage meta-pipeline, and show that most methods engage only one or two of these stages. Second, we use norm-constrained linear minimization oracles (LMOs) to unify different optimizers. Third, these two views ground a dual-dimension taxonomy, one dimension assigning each method to a mechanism family and the other recording the measurable training objectives it aims to improve. Fourth, and at the core of this paper, we instantiate the full taxonomy in a unified cross-domain benchmark spanning representative optimizers, model scales, and training regimes from language model pretraining to image classification, systematically analyzing each method family across multiple effect objectives and laying out their trade-offs. OmniOpt thus supplies the research community with an operational coordinate system for selecting optimizers under explicit mechanism and objective assumptions, and charts a direction for the future development of the optimizer community.", "upvotes": 64, "discussionId": "6a4c985925849b193a83436e", "projectPage": "https://openraiser.github.io/OmniOpt/", "githubRepo": "https://github.com/OpenRaiser/OmniOpt", "githubRepoAddedBy": "user", "ai_summary": "OmniOpt presents a unified framework for optimizer selection in large-scale model training by combining meta-pipeline transformations, norm-constrained linear minimization oracles, and a cross-domain benchmark to systematically analyze optimizer families and their trade-offs across different training objectives and model scales.", "ai_keywords": ["optimizer selection", "large-scale model training", "meta-pipeline", "norm-constrained linear minimization oracles", "cross-domain benchmark", "optimizer families", "training objectives", "model scales", "systematic analysis", "trade-offs"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 28, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "summary_zh": "<ul>\n    <li>\u4f18\u5316\u5668\u9009\u62e9\u5728\u5927\u89c4\u6a21\u6a21\u578b\u8bad\u7ec3\u4e2d\u662f\u4e00\u4e2a\u7cfb\u7edf\u8bbe\u8ba1\u7684\u51b3\u7b56\uff0c\u53d7\u5230\u8ba1\u7b97\u3001\u5185\u5b58\u548c\u4efb\u52a1\u591a\u6837\u6027\u7684\u5f71\u54cd\u3002</li>\n    <li>OmniOpt\u662f\u4e00\u4e2a\u7edf\u4e00\u7684\u4f18\u5316\u5668\u8c03\u67e5\u548c\u57fa\u51c6\u5de5\u5177\uff0c\u4e3a\u7814\u7a76\u793e\u533a\u63d0\u4f9b\u53c2\u8003\u3002</li>\n    <li>OmniOpt\u5305\u62ec\u56db\u4e2a\u4e3b\u8981\u90e8\u5206\uff0c\u5176\u4e2d\u6bcf\u4e2a\u4f18\u5316\u5668\u7684\u66f4\u65b0\u88ab\u89c6\u4e3a\u7ed3\u6784\u5316\u53d8\u6362\uff0c\u901a\u8fc7\u4e94\u4e2a\u9636\u6bb5\u7684\u5143\u7ba1\u9053\u8fdb\u884c\u5904\u7406\u3002</li>\n    <li>\u8be5\u5de5\u5177\u4f7f\u7528\u7ea6\u675f\u7ebf\u6027\u6700\u5c0f\u5316oracle\u6765\u7edf\u4e00\u4e0d\u540c\u7684\u4f18\u5316\u5668\uff0c\u5e76\u5efa\u7acb\u4e86\u4e00\u4e2a\u53cc\u7ef4\u5206\u7c7b\u6cd5\u3002</li>\n    <li>OmniOpt\u63d0\u4f9b\u4e86\u4e00\u4e2a\u64cd\u4f5c\u5750\u6807\u7cfb\u7edf\uff0c\u5e2e\u52a9\u7814\u7a76\u4eba\u5458\u5728\u660e\u786e\u7684\u673a\u5236\u548c\u76ee\u6807\u5047\u8bbe\u4e0b\u9009\u62e9\u4f18\u5316\u5668\uff0c\u5e76\u6307\u5f15\u672a\u6765\u7684\u4f18\u5316\u5668\u53d1\u5c55\u65b9\u5411\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Optimizer selection for large models is a complex decision influenced by many factors like compute resources and task diversity.</li>\n    <li>OmniOpt is a comprehensive guide and benchmark for different optimizers aimed at researchers.</li>\n    <li>It includes a five-stage process to analyze how different optimizers work, showing that many only use a part of this process.</li>\n    <li>OmniOpt categorizes optimizers based on their mechanisms and the goals they try to achieve.</li>\n    <li>It provides a detailed benchmark for comparing optimizers across various tasks, helping researchers make better choices in their work.</li>\n</ul>"}, "publishedAt": "2026-07-03T20:00:00.000Z", "title": "OmniOpt: Taxonomy, Geometry, and Benchmarking of Modern Optimizers", "summary": "Optimizer selection for large-scale model training has become a system-level design decision constrained jointly by compute, memory, tuning budget, and task diversity, yet the landscape of over one hundred methods remains fragmented. We therefore present OmniOpt, a unified survey and benchmark cookbook of optimizers for the research community. OmniOpt rests on four coupled components. First, we treat every optimizer update as a structured transformation through a five-stage meta-pipeline, and show that most methods engage only one or two of these stages. Second, we use norm-constrained linear minimization oracles (LMOs) to unify different optimizers. Third, these two views ground a dual-dimension taxonomy, one dimension assigning each method to a mechanism family and the other recording the measurable training objectives it aims to improve. Fourth, and at the core of this paper, we instantiate the full taxonomy in a unified cross-domain benchmark spanning representative optimizers, model scales, and training regimes from language model pretraining to image classification, systematically analyzing each method family across multiple effect objectives and laying out their trade-offs. OmniOpt thus supplies the research community with an operational coordinate system for selecting optimizers under explicit mechanism and objective assumptions, and charts a direction for the future development of the optimizer community.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64be296a46cc3cdfbb057f7e/fcymBQFAev-N5KfQ67hXj.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04033.png", "numComments": 1, "submittedBy": {"_id": "64be296a46cc3cdfbb057f7e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64be296a46cc3cdfbb057f7e/jSHeNY2AcPifCZzJyFhr4.jpeg", "fullname": "Cheng Tan", "name": "chengtan9907", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04425", "authors": [{"_id": "6a4c6de625849b193a8340c5", "user": {"_id": "69e06fafde9dfdc5821f3854", "avatarUrl": "/avatars/414474811a19c5dfc3a121e29608b391.svg", "isPro": false, "fullname": "Lian", "user": "EliSpctre", "type": "user", "name": "EliSpctre"}, "name": "Niu Lian", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:48.669Z", "hidden": false}, {"_id": "6a4c6de625849b193a8340c6", "name": "Alan Chen", "hidden": false}, {"_id": "6a4c6de625849b193a8340c7", "name": "Zhehao Yu", "hidden": false}, {"_id": "6a4c6de625849b193a8340c8", "name": "Chengzhen Duan", "hidden": false}, {"_id": "6a4c6de625849b193a8340c9", "name": "Fazhan Liu", "hidden": false}, {"_id": "6a4c6de625849b193a8340ca", "name": "Hui Liu", "hidden": false}, {"_id": "6a4c6de625849b193a8340cb", "name": "Pei Fu", "hidden": false}, {"_id": "6a4c6de625849b193a8340cc", "name": "Jian Luan", "hidden": false}, {"_id": "6a4c6de625849b193a8340cd", "name": "Yaowei Wang", "hidden": false}, {"_id": "6a4c6de625849b193a8340ce", "name": "Shu-Tao Xia", "hidden": false}, {"_id": "6a4c6de625849b193a8340cf", "name": "Jinpeng Wang", "hidden": false}], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "UI-MOPD: Multi-Platform On-Policy Distillation for Continual GUI Agent Learning", "submittedOnDailyBy": {"_id": "65d70e775e971572da16c05b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65d70e775e971572da16c05b/8Cv71Clfk_C7k6U4yI6ln.jpeg", "isPro": false, "fullname": "Yuhong Dai", "user": "BroAlanTaps", "type": "user", "name": "BroAlanTaps"}, "summary": "Recent advances in multimodal foundation models and agent systems have driven GUI agents from single-platform task execution toward cross-platform interaction. However, building multi-platform GUI agents remains challenging. On one hand, high-quality and executable cross-platform interaction trajectories are still scarce, and existing data often suffer from limited platform coverage. On the other hand, different platforms exhibit distinct interaction conventions, making joint or continual training prone to behavioral pattern mixing, platform-specific capability degradation, and catastrophic forgetting. To address these challenges, we construct Uni-GUI, a high-quality cross-platform GUI interaction dataset, and propose UI-MOPD, the first method that incorporates multi-teacher on-policy distillation into continual learning for GUI agents. UI-MOPD dynamically selects a platform-specific teacher according to the current environment and transfers platform-specific behavioral priors to a shared policy through platform-conditioned distillation, enabling adaptation to new platforms while preserving capabilities on existing ones. Experiments on OSWorld and MobileWorld show that UI-MOPD achieves task success rates of 38.2% and 12.0%, respectively, demonstrating its effectiveness in balancing cross-platform capability retention and new-platform adaptation.\n  Project page: https://elispectre.github.io/UI-MOPD/.", "upvotes": 62, "discussionId": "6a4c6de625849b193a8340d0", "ai_summary": "Uni-GUI dataset and UI-MOPD method enable cross-platform GUI agent training by addressing limited data and platform-specific capability degradation through multi-teacher on-policy distillation.", "ai_keywords": ["multimodal foundation models", "agent systems", "GUI agents", "cross-platform interaction", "continual learning", "multi-teacher on-policy distillation", "platform-conditioned distillation", "behavioral pattern mixing", "catastrophic forgetting"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u7814\u7a76\u63a8\u52a8\u4e86\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\u548c\u4ee3\u7406\u7cfb\u7edf\u7684\u53d1\u5c55\uff0c\u4f7f\u5f97\u56fe\u5f62\u7528\u6237\u754c\u9762\uff08GUI\uff09\u4ee3\u7406\u80fd\u591f\u5728\u591a\u4e2a\u5e73\u53f0\u4e0a\u8fdb\u884c\u4e92\u52a8\u3002</li>\n    <li>\u6784\u5efa\u591a\u5e73\u53f0GUI\u4ee3\u7406\u9762\u4e34\u6311\u6218\uff0c\u5305\u62ec\u7f3a\u4e4f\u9ad8\u8d28\u91cf\u7684\u53ef\u6267\u884c\u8de8\u5e73\u53f0\u4e92\u52a8\u6570\u636e\u548c\u4e0d\u540c\u5e73\u53f0\u7684\u4e92\u52a8\u89c4\u8303\u5dee\u5f02\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e9b\u95ee\u9898\uff0c\u7814\u7a76\u8005\u4eec\u6784\u5efa\u4e86Uni-GUI\u6570\u636e\u96c6\uff0c\u5e76\u63d0\u51fa\u4e86UI-MOPD\u65b9\u6cd5\uff0c\u8fd9\u662f\u4e00\u79cd\u7ed3\u5408\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u7684\u6301\u7eed\u5b66\u4e60\u65b9\u6cd5\u3002</li>\n    <li>UI-MOPD\u6839\u636e\u5f53\u524d\u73af\u5883\u52a8\u6001\u9009\u62e9\u5e73\u53f0\u7279\u5b9a\u7684\u6559\u5e08\uff0c\u5e76\u901a\u8fc7\u5e73\u53f0\u6761\u4ef6\u84b8\u998f\u5c06\u884c\u4e3a\u5148\u9a8c\u4f20\u9012\u5230\u5171\u4eab\u7b56\u7565\uff0c\u4ee5\u9002\u5e94\u65b0\u5e73\u53f0\u3002</li>\n    <li>\u5728OSWorld\u548cMobileWorld\u4e0a\u7684\u5b9e\u9a8c\u8868\u660e\uff0cUI-MOPD\u5728\u8de8\u5e73\u53f0\u80fd\u529b\u4fdd\u6301\u548c\u65b0\u5e73\u53f0\u9002\u5e94\u65b9\u9762\u8868\u73b0\u6709\u6548\uff0c\u4efb\u52a1\u6210\u529f\u7387\u5206\u522b\u4e3a38.2%\u548c12.0%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent developments in GUI agents allow them to work across different platforms, but creating effective multi-platform agents is still difficult.</li>\n    <li>Challenges include a lack of high-quality interaction data for various platforms and differences in how each platform operates.</li>\n    <li>To tackle these challenges, researchers created Uni-GUI, a dataset for cross-platform GUI interactions, and introduced a new learning method called UI-MOPD.</li>\n    <li>UI-MOPD uses multiple teachers to help GUI agents learn from specific platforms, allowing them to adapt to new ones without losing skills on existing platforms.</li>\n    <li>Tests on two platforms showed that UI-MOPD significantly improves the ability of agents to succeed in tasks across different environments.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "UI-MOPD: Multi-Platform On-Policy Distillation for Continual GUI Agent Learning", "summary": "Recent advances in multimodal foundation models and agent systems have driven GUI agents from single-platform task execution toward cross-platform interaction. However, building multi-platform GUI agents remains challenging. On one hand, high-quality and executable cross-platform interaction trajectories are still scarce, and existing data often suffer from limited platform coverage. On the other hand, different platforms exhibit distinct interaction conventions, making joint or continual training prone to behavioral pattern mixing, platform-specific capability degradation, and catastrophic forgetting. To address these challenges, we construct Uni-GUI, a high-quality cross-platform GUI interaction dataset, and propose UI-MOPD, the first method that incorporates multi-teacher on-policy distillation into continual learning for GUI agents. UI-MOPD dynamically selects a platform-specific teacher according to the current environment and transfers platform-specific behavioral priors to a shared policy through platform-conditioned distillation, enabling adaptation to new platforms while preserving capabilities on existing ones. Experiments on OSWorld and MobileWorld show that UI-MOPD achieves task success rates of 38.2% and 12.0%, respectively, demonstrating its effectiveness in balancing cross-platform capability retention and new-platform adaptation.\n  Project page: https://elispectre.github.io/UI-MOPD/.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04425.png", "numComments": 1, "submittedBy": {"_id": "65d70e775e971572da16c05b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65d70e775e971572da16c05b/8Cv71Clfk_C7k6U4yI6ln.jpeg", "fullname": "Yuhong Dai", "name": "BroAlanTaps", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04438", "authors": [{"_id": "6a4c62a325849b193a834020", "name": "Lingao Xiao", "hidden": false}, {"_id": "6a4c62a325849b193a834021", "name": "Yalun Dai", "hidden": false}, {"_id": "6a4c62a325849b193a834022", "name": "Yangyu Huang", "hidden": false}, {"_id": "6a4c62a325849b193a834023", "name": "Qihao Zhao", "hidden": false}, {"_id": "6a4c62a325849b193a834024", "name": "Wenshan Wu", "hidden": false}, {"_id": "6a4c62a325849b193a834025", "name": "Hugo He", "hidden": false}, {"_id": "6a4c62a325849b193a834026", "name": "Ruishuo Chen", "hidden": false}, {"_id": "6a4c62a325849b193a834027", "name": "Jin Jiang", "hidden": false}, {"_id": "6a4c62a325849b193a834028", "name": "Qianli Ma", "hidden": false}, {"_id": "6a4c62a325849b193a834029", "name": "Jiahuan Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a83402a", "name": "Xin Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a83402b", "name": "Ying Xin", "hidden": false}, {"_id": "6a4c62a325849b193a83402c", "name": "Yang Ou", "hidden": false}, {"_id": "6a4c62a325849b193a83402d", "name": "Yan Xia", "hidden": false}, {"_id": "6a4c62a325849b193a83402e", "name": "Scarlett Li", "hidden": false}, {"_id": "6a4c62a325849b193a83402f", "name": "Longbo Huang", "hidden": false}, {"_id": "6a4c62a325849b193a834030", "name": "Zhipeng Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a834031", "name": "Yang He", "hidden": false}, {"_id": "6a4c62a325849b193a834032", "name": "Yap Kim Hui", "hidden": false}, {"_id": "6a4c62a325849b193a834033", "name": "Yan Lu", "hidden": false}], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "ResearchStudio-Reel: Automate the Last Mile of Research from Paper to Poster, Video, and Blog", "submittedOnDailyBy": {"_id": "64c66647725ffa04b2fd6c94", "avatarUrl": "/avatars/620f63f27fa1e90423b0dc22aa8e5809.svg", "isPro": false, "fullname": "yangyu huang", "user": "yangyu90", "type": "user", "name": "yangyu90"}, "summary": "Research dissemination, turning a paper into a poster, a talk video, and a blog post, is still a manual last mile. Prior automation treats each artifact in isolation that each re-extract the paper from scratch, usually ship one-way renders the author cannot reopen in PowerPoint or Word, and gates quality on soft VLM-preference scores that plateau while load-bearing sections still read as empty. We argue this last mile is best built as a composition of skills: thin agent-readable contracts that share one upstream extractor and wrap deterministic primitives in a measured-fill loop whose exits are hard pass/fail render gates. We instantiate this as ResearchStudio-Reel, five Claude Code and Codex skills organized into one shared extractor (Paper2Assets), three editable generators (Paper2Poster, Paper2Video, Paper2Blog), and one interactive convergence layer (Paper2Reel). Paper2Assets extracts each paper once into a shared bundle that can be reused by every downstream skill; The three generators produce a print-ready poster, a synchronized talk video, and a bilingual blog that stay factually consistent and round-trip through PowerPoint or Word; Paper2Reel then binds all three into a self-contained HTML viewer whose section-level clicks jump the video, slides, captions, and blog to matching content. On the Paper2Poster benchmark, our posters lead every aesthetic and information sub-criterion against both prior automated systems and single-shot frontier LLMs, surpassing the authors' own on aesthetics under two held-out VLM judges and winning overall on 84% to 93% of papers; capability audits further show that, by uniquely pairing narration-aligned on-slide highlights with a bilingual blog gated by layout-aware DOCX repair, ResearchStudio-Reel is the only pipeline to ship all three editable artifacts. Project is available at https://aka.ms/ResearchStudio", "upvotes": 48, "discussionId": "6a4c62a325849b193a834034", "projectPage": "https://aka.ms/ResearchStudio", "ai_summary": "ResearchStudio-Reel automates research dissemination by composing specialized skills around a shared paper extractor, generating consistent and editable artifacts including posters, videos, and blogs with hard pass/fail quality gates.", "ai_keywords": ["research dissemination", "automated artifact generation", "paper extraction", "poster generation", "talk video creation", "blog post writing", "VLM preference scores", "deterministic primitives", "measured-fill loop", "render gates", "paper-to-assets extractor", "editable generators", "interactive convergence layer", "HTML viewer", "section-level navigation", "layout-aware DOCX repair", "capability audit"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "summary_zh": "<ul>\n    <li>\u7814\u7a76\u4f20\u64ad\u4ecd\u9700\u624b\u52a8\u5904\u7406\uff0c\u5c06\u8bba\u6587\u8f6c\u4e3a\u6d77\u62a5\u3001\u89c6\u9891\u548c\u535a\u5ba2\u3002</li>\n    <li>\u73b0\u6709\u7684\u81ea\u52a8\u5316\u65b9\u6cd5\u5c06\u6bcf\u4e2a\u4f5c\u54c1\u89c6\u4e3a\u72ec\u7acb\u7684\uff0c\u91cd\u65b0\u63d0\u53d6\u8bba\u6587\uff0c\u65e0\u6cd5\u5728PowerPoint\u6216Word\u4e2d\u7f16\u8f91\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e00\u79cd\u65b0\u65b9\u6cd5\uff0c\u4f7f\u7528\u5171\u4eab\u63d0\u53d6\u5668\u548c\u53ef\u7f16\u8f91\u751f\u6210\u5668\uff0c\u786e\u4fdd\u8d28\u91cf\u548c\u4e00\u81f4\u6027\u3002</li>\n    <li>ResearchStudio-Reel\u6574\u5408\u4e86\u591a\u4e2a\u6280\u80fd\uff0c\u751f\u6210\u7684\u6d77\u62a5\u3001\u89c6\u9891\u548c\u535a\u5ba2\u4e4b\u95f4\u4fdd\u6301\u4e00\u81f4\uff0c\u5e76\u53ef\u4ee5\u76f8\u4e92\u94fe\u63a5\u3002</li>\n    <li>\u5728\u6d77\u62a5\u7684\u8bc4\u4f30\u4e2d\uff0c\u6211\u4eec\u7684\u65b9\u6cd5\u5728\u7f8e\u89c2\u548c\u4fe1\u606f\u51c6\u786e\u6027\u4e0a\u8d85\u8fc7\u4e86\u5176\u4ed6\u7cfb\u7edf\uff0c\u63d0\u4f9b\u53ef\u7f16\u8f91\u7684\u6210\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Research dissemination needs improvement; current automation creates separate artifacts from papers without reuse.</li>\n    <li>This study introduces ResearchStudio-Reel, a system that uses one extractor for all outputs: a poster, video, and blog post.</li>\n    <li>Each output is editable and maintains factual consistency, allowing easy updates and formats like PowerPoint or Word.</li>\n    <li>The new posters outperform previous automated systems and show better aesthetics, winning against authors' own designs in most cases.</li>\n    <li>ResearchStudio-Reel uniquely provides a way to create and share all three types of content together in a cohesive HTML viewer.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "ResearchStudio-Reel: Automate the Last Mile of Research from Paper to Poster, Video, and Blog", "summary": "Research dissemination, turning a paper into a poster, a talk video, and a blog post, is still a manual last mile. Prior automation treats each artifact in isolation that each re-extract the paper from scratch, usually ship one-way renders the author cannot reopen in PowerPoint or Word, and gates quality on soft VLM-preference scores that plateau while load-bearing sections still read as empty. We argue this last mile is best built as a composition of skills: thin agent-readable contracts that share one upstream extractor and wrap deterministic primitives in a measured-fill loop whose exits are hard pass/fail render gates. We instantiate this as ResearchStudio-Reel, five Claude Code and Codex skills organized into one shared extractor (Paper2Assets), three editable generators (Paper2Poster, Paper2Video, Paper2Blog), and one interactive convergence layer (Paper2Reel). Paper2Assets extracts each paper once into a shared bundle that can be reused by every downstream skill; The three generators produce a print-ready poster, a synchronized talk video, and a bilingual blog that stay factually consistent and round-trip through PowerPoint or Word; Paper2Reel then binds all three into a self-contained HTML viewer whose section-level clicks jump the video, slides, captions, and blog to matching content. On the Paper2Poster benchmark, our posters lead every aesthetic and information sub-criterion against both prior automated systems and single-shot frontier LLMs, surpassing the authors' own on aesthetics under two held-out VLM judges and winning overall on 84% to 93% of papers; capability audits further show that, by uniquely pairing narration-aligned on-slide highlights with a bilingual blog gated by layout-aware DOCX repair, ResearchStudio-Reel is the only pipeline to ship all three editable artifacts. Project is available at https://aka.ms/ResearchStudio", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04438.png", "numComments": 1, "submittedBy": {"_id": "64c66647725ffa04b2fd6c94", "avatarUrl": "/avatars/620f63f27fa1e90423b0dc22aa8e5809.svg", "fullname": "yangyu huang", "name": "yangyu90", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.05373", "authors": [{"_id": "6a4c7b9a25849b193a83420d", "user": {"_id": "659765e22235d4056ba80c0a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/659765e22235d4056ba80c0a/dATESmijLO3CpD1sCMezg.jpeg", "isPro": true, "fullname": "Gao Sensen", "user": "Sensen02", "type": "user", "name": "Sensen02"}, "name": "Sensen Gao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:05.204Z", "hidden": false}, {"_id": "6a4c7b9a25849b193a83420e", "name": "Zhaoqing Wang", "hidden": false}, {"_id": "6a4c7b9a25849b193a83420f", "user": {"_id": "652f52a07636538890b2132b", "avatarUrl": "/avatars/ac9e39e8bdb21c9d5aab2e3912e23bb4.svg", "isPro": false, "fullname": "Cao", "user": "Belta", "type": "user", "name": "Belta"}, "name": "Qihang Cao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:03.424Z", "hidden": false}, {"_id": "6a4c7b9a25849b193a834210", "name": "Dongdong Yu", "hidden": false}, {"_id": "6a4c7b9a25849b193a834211", "name": "Changhu Wang", "hidden": false}, {"_id": "6a4c7b9a25849b193a834212", "name": "Jia-Wang Bian", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/eZc0n0VWyqyIeKdOzMwrE.mp4"], "publishedAt": "2026-07-06T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "PixWorld: Unifying 3D Scene Generation and Reconstruction in Pixel Space", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "3D reconstruction and generation are commonly tackled by separate paradigms: pixel-based regression for reconstruction, and latent diffusion for generation. Recent works attempt to unify them in latent space, but with notable drawbacks: the diffusion objective is defined on latent features rather than the underlying 3D representation, and both branches suffer from information loss introduced by latent encoding, while requiring a pretrained Variational Autoencoder (VAE) or Representation Autoencoder (RAE). In this paper, we reformulate these two tasks under a unified pixel-space diffusion paradigm and introduce PixWorld, a single model that jointly addresses 3D reconstruction and generation. By supervising diffusion directly on rendered images, PixWorld removes the above limitations and aligns optimization with 3D scene fidelity. Beyond photometric and perceptual supervision that operates at the 2D image level and lacks 3D geometric awareness, we further introduce a geometry perception loss that aligns rendered views with their ground truth in the geometry-aware feature space of a pretrained 3D foundation model, providing 3D structural supervision. PixWorld consistently outperforms prior latent-space generation methods and matches state-of-the-art reconstruction methods, demonstrating the superiority of a unified pixel-space approach.", "upvotes": 46, "discussionId": "6a4c7b9a25849b193a834213", "projectPage": "https://sensengao.github.io/PixWorld/", "githubRepo": "https://github.com/SensenGao/PixWorld", "githubRepoAddedBy": "user", "ai_summary": "PixWorld presents a unified pixel-space diffusion approach for 3D reconstruction and generation that overcomes limitations of latent-space methods through direct image-level supervision and geometry-aware feature alignment.", "ai_keywords": ["3D reconstruction", "3D generation", "latent space", "pixel space", "diffusion models", "Variational Autoencoder", "Representation Autoencoder", "3D foundation model", "geometry perception loss", "rendered images", "3D scene fidelity"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 60, "organization": {"_id": "6508b28cf36bb51c50faad98", "name": "NanyangTechnologicalUniversity", "fullname": "Nanyang Technological University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZPD1fvei0bcIGeDXxeSkn.png"}, "summary_zh": "<ul>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86\u4e00\u79cd\u540d\u4e3aPixWorld\u7684\u6a21\u578b\uff0c\u7528\u4e8e\u540c\u65f6\u8fdb\u884c3D\u91cd\u5efa\u548c\u751f\u6210\u3002</li>\n    <li>PixWorld\u901a\u8fc7\u76f4\u63a5\u5728\u6e32\u67d3\u56fe\u50cf\u4e0a\u8fdb\u884c\u6269\u6563\u76d1\u7763\uff0c\u514b\u670d\u4e86\u4f20\u7edf\u65b9\u6cd5\u7684\u5c40\u9650\u6027\u3002</li>\n    <li>\u5f15\u5165\u4e86\u4e00\u79cd\u51e0\u4f55\u611f\u77e5\u635f\u5931\uff0c\u4f7f\u5f97\u751f\u6210\u7684\u89c6\u56fe\u4e0e\u771f\u5b9e\u7684\u51e0\u4f55\u7279\u5f81\u5bf9\u9f50\uff0c\u63d0\u4f9b\u4e863D\u7ed3\u6784\u76d1\u7763\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5728\u6027\u80fd\u4e0a\u8d85\u8fc7\u4e86\u5148\u524d\u7684\u6f5c\u5728\u7a7a\u95f4\u751f\u6210\u65b9\u6cd5\uff0c\u5e76\u4e0e\u6700\u5148\u8fdb\u7684\u91cd\u5efa\u65b9\u6cd5\u76f8\u5339\u914d\u3002</li>\n    <li>\u901a\u8fc7\u7edf\u4e00\u7684\u50cf\u7d20\u7a7a\u95f4\u65b9\u6cd5\uff0cPixWorld\u57283D\u573a\u666f\u4fdd\u771f\u5ea6\u4e0a\u5b9e\u73b0\u4e86\u4f18\u5316\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>3D reconstruction and generation are usually done separately using different methods, but this paper presents a new approach called PixWorld that combines them.</li>\n    <li>Previous methods faced issues like loss of information and reliance on complex models, which PixWorld aims to overcome.</li>\n    <li>PixWorld works directly with rendered images, improving the quality of 3D scene representation.</li>\n    <li>It introduces a new loss function that helps align 3D geometry with rendered images, enhancing accuracy.</li>\n    <li>The results show that PixWorld performs better than previous methods, offering a more effective way to handle 3D tasks.</li>\n</ul>"}, "publishedAt": "2026-07-05T20:00:00.000Z", "title": "PixWorld: Unifying 3D Scene Generation and Reconstruction in Pixel Space", "summary": "3D reconstruction and generation are commonly tackled by separate paradigms: pixel-based regression for reconstruction, and latent diffusion for generation. Recent works attempt to unify them in latent space, but with notable drawbacks: the diffusion objective is defined on latent features rather than the underlying 3D representation, and both branches suffer from information loss introduced by latent encoding, while requiring a pretrained Variational Autoencoder (VAE) or Representation Autoencoder (RAE). In this paper, we reformulate these two tasks under a unified pixel-space diffusion paradigm and introduce PixWorld, a single model that jointly addresses 3D reconstruction and generation. By supervising diffusion directly on rendered images, PixWorld removes the above limitations and aligns optimization with 3D scene fidelity. Beyond photometric and perceptual supervision that operates at the 2D image level and lacks 3D geometric awareness, we further introduce a geometry perception loss that aligns rendered views with their ground truth in the geometry-aware feature space of a pretrained 3D foundation model, providing 3D structural supervision. PixWorld consistently outperforms prior latent-space generation methods and matches state-of-the-art reconstruction methods, demonstrating the superiority of a unified pixel-space approach.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/eZc0n0VWyqyIeKdOzMwrE.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.05373.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 329, "isUserFollowing": false}, "organization": {"_id": "6508b28cf36bb51c50faad98", "name": "NanyangTechnologicalUniversity", "fullname": "Nanyang Technological University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZPD1fvei0bcIGeDXxeSkn.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04439", "authors": [{"_id": "6a4c5adf25849b193a833fd1", "user": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "isPro": false, "fullname": "Qihao Zhao", "user": "fistyyyy", "type": "user", "name": "fistyyyy"}, "name": "Qihao Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:12:17.157Z", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd2", "name": "Yangyu Huang", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd3", "name": "Yalun Dai", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd4", "name": "Lingao Xiao", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd5", "name": "Jianjun Gao", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd6", "name": "Xin Zhang", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd7", "name": "Wenshan Wu", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd8", "name": "Scarlett Li", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd9", "name": "Yang He", "hidden": false}, {"_id": "6a4c5adf25849b193a833fda", "name": "Yan Lu", "hidden": false}, {"_id": "6a4c5adf25849b193a833fdb", "name": "Yap Kim Hui", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/MDoRDZtb3QpHIytJQBTD5.mp4", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/95tKjcpM-MTgx3C5m4lqg.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/knPM5EC_CLs-0klHvD02y.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/D4hgPM0W71Cj94MbhfU6h.gif"], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "ResearchStudio-Idea: An Evidence-Grounded Research-Ideation Skill Suite from ML Conference Outcomes", "submittedOnDailyBy": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "isPro": false, "fullname": "Qihao Zhao", "user": "fistyyyy", "type": "user", "name": "fistyyyy"}, "summary": "Large language models have made research ideation increasingly accessible, yet effective idea development requires more than generating candidate directions. Researchers must ground a problem in current literature, identify meaningful bottlenecks, differentiate from existing solutions, and evaluate risks before committing to implementation. We present ResearchStudio-Idea as a reusable skill suite for this first mile of research ideation. The suite includes Paper-Search, a standalone multi-source literature search skill; Scoop-Check, a standalone prior-art collision checker for novelty claims; and IdeaSpark, the end-to-end skill that composes evidence grounding, pattern-guided generation, collision retrieval, audit, and idea-card rendering into one workflow. IdeaSpark is constructed from a corpus of 1,947 machine learning conference papers collected from ICLR, ICML, and NeurIPS between 2021 and 2025, including Oral papers, a separately tracked high-citation subset, and rejected submissions. Analysis of these outcomes reveals 31 recurring ideation sub-patterns, consolidated into 15 reusable ideation patterns. Each pattern is operationalized as a structured card containing research contexts, bottleneck types, differentiation strategies, supporting precedents, and common failure modes. Given a research problem and an evidence bundle, IdeaSpark evaluates evidence readiness, reconstructs the surrounding research context, identifies unresolved bottlenecks, selects relevant patterns, instantiates one candidate direction, retrieves potentially conflicting prior work, and performs outcome-informed auditing. This workflow transforms reusable ideation patterns into traceable research proposals. Blind automated-judge evaluations show that IdeaSpark consistently produces stronger research proposals than no-skill and generic-skill baselines while maintaining competitive novelty.", "upvotes": 40, "discussionId": "6a4c5ae025849b193a833fdc", "projectPage": "https://aka.ms/ResearchStudio", "githubRepo": "https://github.com/microsoft/ResearchStudio", "githubRepoAddedBy": "user", "ai_summary": "ResearchStudio-Idea provides a skill suite for effective research ideation that combines literature search, novelty checking, and pattern-guided generation to produce traceable research proposals.", "ai_keywords": ["research ideation", "literature search", "prior-art collision checker", "pattern-guided generation", "evidence grounding", "idea-card rendering", "reusable ideation patterns", "research context", "bottleneck identification", "differentiation strategies", "prior work retrieval", "outcome-informed auditing"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 181, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "summary_zh": "<ul>\n  <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u4f7f\u7814\u7a76\u521b\u610f\u66f4\u5bb9\u6613\u83b7\u53d6\uff0c\u4f46\u6709\u6548\u7684\u521b\u610f\u53d1\u5c55\u9700\u8981\u66f4\u591a\u6b65\u9aa4\u3002</li>\n  <li>ResearchStudio-Idea\u662f\u4e00\u4e2a\u53ef\u91cd\u590d\u4f7f\u7528\u7684\u5de5\u5177\u5957\u4ef6\uff0c\u5e2e\u52a9\u7814\u7a76\u4eba\u5458\u4ece\u751f\u6210\u60f3\u6cd5\u5230\u5b9e\u65bd\u7684\u8fc7\u7a0b\u3002</li>\n  <li>\u8be5\u5957\u4ef6\u5305\u62ec\u6587\u732e\u641c\u7d22\u5de5\u5177Paper-Search\u548c\u65b0\u9896\u6027\u68c0\u67e5\u5de5\u5177Scoop-Check\uff0c\u4ee5\u53ca\u6574\u5408\u591a\u4e2a\u529f\u80fd\u7684IdeaSpark\u3002</li>\n  <li>IdeaSpark\u5229\u7528\u4ece2021\u52302025\u5e74\u6536\u96c6\u76841947\u7bc7\u673a\u5668\u5b66\u4e60\u4f1a\u8bae\u8bba\u6587\uff0c\u5206\u6790\u51fa31\u79cd\u53cd\u590d\u51fa\u73b0\u7684\u521b\u610f\u5b50\u6a21\u5f0f\u3002</li>\n  <li>IdeaSpark\u80fd\u591f\u8bc4\u4f30\u8bc1\u636e\u7684\u51c6\u5907\u60c5\u51b5\uff0c\u8bc6\u522b\u74f6\u9888\uff0c\u5e76\u751f\u6210\u53ef\u8ffd\u8e2a\u7684\u7814\u7a76\u63d0\u6848\uff0c\u6548\u679c\u4f18\u4e8e\u4f20\u7edf\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language models help generate research ideas, but developing those ideas requires more steps.</li>\n    <li>ResearchStudio-Idea is a toolkit designed to assist in the early stages of research ideation.</li>\n    <li>The toolkit includes tools for literature searching, checking for originality, and a comprehensive workflow for creating research proposals.</li>\n    <li>IdeaSpark analyzes a large dataset of machine learning papers to identify common patterns and helps structure research proposals.</li>\n    <li>Tests show that IdeaSpark produces better research proposals compared to other methods while still being original.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "ResearchStudio-Idea: An Evidence-Grounded Research-Ideation Skill Suite from ML Conference Outcomes", "summary": "Large language models have made research ideation increasingly accessible, yet effective idea development requires more than generating candidate directions. Researchers must ground a problem in current literature, identify meaningful bottlenecks, differentiate from existing solutions, and evaluate risks before committing to implementation. We present ResearchStudio-Idea as a reusable skill suite for this first mile of research ideation. The suite includes Paper-Search, a standalone multi-source literature search skill; Scoop-Check, a standalone prior-art collision checker for novelty claims; and IdeaSpark, the end-to-end skill that composes evidence grounding, pattern-guided generation, collision retrieval, audit, and idea-card rendering into one workflow. IdeaSpark is constructed from a corpus of 1,947 machine learning conference papers collected from ICLR, ICML, and NeurIPS between 2021 and 2025, including Oral papers, a separately tracked high-citation subset, and rejected submissions. Analysis of these outcomes reveals 31 recurring ideation sub-patterns, consolidated into 15 reusable ideation patterns. Each pattern is operationalized as a structured card containing research contexts, bottleneck types, differentiation strategies, supporting precedents, and common failure modes. Given a research problem and an evidence bundle, IdeaSpark evaluates evidence readiness, reconstructs the surrounding research context, identifies unresolved bottlenecks, selects relevant patterns, instantiates one candidate direction, retrieves potentially conflicting prior work, and performs outcome-informed auditing. This workflow transforms reusable ideation patterns into traceable research proposals. Blind automated-judge evaluations show that IdeaSpark consistently produces stronger research proposals than no-skill and generic-skill baselines while maintaining competitive novelty.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/MDoRDZtb3QpHIytJQBTD5.mp4", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/95tKjcpM-MTgx3C5m4lqg.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/knPM5EC_CLs-0klHvD02y.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/D4hgPM0W71Cj94MbhfU6h.gif"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04439.png", "numComments": 1, "submittedBy": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "fullname": "Qihao Zhao", "name": "fistyyyy", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.03973", "authors": [{"_id": "6a4cdda725849b193a834559", "user": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "isPro": false, "fullname": "Matan Avitan", "user": "MatanAvitan", "type": "user", "name": "MatanAvitan"}, "name": "Matan Avitan", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:10:26.755Z", "hidden": false}, {"_id": "6a4cdda725849b193a83455a", "name": "Yoav Goldberg", "hidden": false}, {"_id": "6a4cdda725849b193a83455b", "name": "Yanai Elazar", "hidden": false}], "publishedAt": "2026-07-04T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "MANCE: Manifold Aware Concept Erasure", "submittedOnDailyBy": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "isPro": false, "fullname": "Matan Avitan", "user": "MatanAvitan", "type": "user", "name": "MatanAvitan"}, "summary": "Concept erasure aims to remove a target concept from a representation while preserving the other information encoded in it. This is difficult because representations encode many concepts that are often correlated with the erasure target, so removing the target risks damaging them. We propose the Manifold Constraint Hypothesis (MCH): if natural representations concentrate on a structured, lower-dimensional manifold, then interventions should be constrained to that manifold and better preserve other information encoded in the representation during interventions. We instantiate MCH in a new concept erasure method: MANifold aware Concept Erasure (MANCE). MANCE performs iterative updates to the representations using signals from a classifier that predicts a target concept. We estimate the manifold using representations obtained from natural inputs, and then we project the concept removal update to the estimated manifold. We perform extensive evaluation on 119 settings spanning text and vision, including 13 language models, three NLP concepts, and 40 CelebA-CLIP attributes. Employing MANCE on top of previous methods shows consistent improved leakage results. We also introduce MANCE+ and MANCE++, which prepend a closed-form erasure algorithm before employing MANCE, achieving better leakage--surgicality tradeoffs relative to matched full-space updates. MANCE++, our best method, achieves state-of-the-art results on nonlinear concept erasure. These results support MCH in the erasure setting: interventions should be constrained to the natural representation manifold.", "upvotes": 32, "discussionId": "6a4cdda725849b193a83455c", "githubRepo": "https://github.com/MatanAvitan/mance", "githubRepoAddedBy": "user", "ai_summary": "Manifold constraint hypothesis enables improved concept erasure by projecting updates onto estimated representation manifolds, achieving state-of-the-art results in nonlinear concept removal.", "ai_keywords": ["concept erasure", "manifold constraint hypothesis", "representation manifold", "iterative updates", "classifier prediction", "projection", "natural representations", "nonlinear concept erasure", "surgicality"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 2, "organization": {"_id": "634a981ccf84e1cc3f610ca1", "name": "barilan", "fullname": "Bar-Ilan University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/MRvtAhVBzuzijH-vDGBjr.png"}, "summary_zh": "<ul>\n    <li>\u6982\u5ff5\u6d88\u9664\u65e8\u5728\u4ece\u8868\u793a\u4e2d\u79fb\u9664\u76ee\u6807\u6982\u5ff5\uff0c\u540c\u65f6\u4fdd\u7559\u5176\u4ed6\u4fe1\u606f\uff0c\u8fd9\u5f88\u56f0\u96be\uff0c\u56e0\u4e3a\u8868\u793a\u4e2d\u5f80\u5f80\u6709\u8bb8\u591a\u4e0e\u76ee\u6807\u6982\u5ff5\u76f8\u5173\u7684\u6982\u5ff5\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u6d41\u5f62\u7ea6\u675f\u5047\u8bbe\uff08MCH\uff09\uff0c\u8ba4\u4e3a\u81ea\u7136\u8868\u793a\u96c6\u4e2d\u5728\u4e00\u4e2a\u7ed3\u6784\u5316\u7684\u4f4e\u7ef4\u6d41\u5f62\u4e0a\uff0c\u56e0\u6b64\u5e72\u9884\u5e94\u8be5\u9650\u5236\u5728\u8fd9\u4e2a\u6d41\u5f62\u4e0a\uff0c\u4ee5\u66f4\u597d\u5730\u4fdd\u7559\u5176\u4ed6\u4fe1\u606f\u3002</li>\n    <li>\u6211\u4eec\u57fa\u4e8eMCH\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u6982\u5ff5\u6d88\u9664\u65b9\u6cd5\uff0c\u79f0\u4e3aMANifold aware Concept Erasure\uff08MANCE\uff09\uff0c\u901a\u8fc7\u5206\u7c7b\u5668\u7684\u4fe1\u53f7\u8fdb\u884c\u8fed\u4ee3\u66f4\u65b0\u3002</li>\n    <li>MANCE\u5728119\u4e2a\u8bbe\u7f6e\u4e2d\u8fdb\u884c\u4e86\u5e7f\u6cdb\u8bc4\u4f30\uff0c\u5305\u62ec\u6587\u672c\u548c\u89c6\u89c9\u4efb\u52a1\uff0c\u7ed3\u679c\u663e\u793a\u5728\u6cc4\u6f0f\u7ed3\u679c\u4e0a\u6709\u663e\u8457\u6539\u8fdb\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u4ecb\u7ecd\u4e86MANCE+\u548cMANCE++\uff0c\u524d\u8005\u5728\u4f7f\u7528MANCE\u4e4b\u524d\u5f15\u5165\u4e86\u5c01\u95ed\u5f62\u5f0f\u7684\u6d88\u9664\u7b97\u6cd5\uff0c\u540e\u8005\u662f\u6211\u4eec\u6700\u597d\u7684\u65b9\u6cd5\uff0c\u5728\u975e\u7ebf\u6027\u6982\u5ff5\u6d88\u9664\u4e0a\u8fbe\u5230\u4e86\u6700\u5148\u8fdb\u7684\u7ed3\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Concept erasure tries to remove specific information from a data representation while keeping other relevant details intact.</li>\n    <li>The Manifold Constraint Hypothesis (MCH) suggests that if data representations are organized in a lower-dimensional space, targeted changes should stay within that space to avoid losing other important information.</li>\n    <li>We developed a new method called MANifold aware Concept Erasure (MANCE) that updates data representations while using insights from a classifier to ensure better erasure without damaging other information.</li>\n    <li>MANCE was tested extensively across different models and tasks, showing improved results in preventing unwanted information leakage compared to previous methods.</li>\n    <li>We also introduced enhanced versions, MANCE+ and MANCE++, which further improve the balance between effective erasure and preserving important details, with MANCE++ achieving the best results in nonlinear concept erasure.</li>\n</ul>"}, "publishedAt": "2026-07-03T20:00:00.000Z", "title": "MANCE: Manifold Aware Concept Erasure", "summary": "Concept erasure aims to remove a target concept from a representation while preserving the other information encoded in it. This is difficult because representations encode many concepts that are often correlated with the erasure target, so removing the target risks damaging them. We propose the Manifold Constraint Hypothesis (MCH): if natural representations concentrate on a structured, lower-dimensional manifold, then interventions should be constrained to that manifold and better preserve other information encoded in the representation during interventions. We instantiate MCH in a new concept erasure method: MANifold aware Concept Erasure (MANCE). MANCE performs iterative updates to the representations using signals from a classifier that predicts a target concept. We estimate the manifold using representations obtained from natural inputs, and then we project the concept removal update to the estimated manifold. We perform extensive evaluation on 119 settings spanning text and vision, including 13 language models, three NLP concepts, and 40 CelebA-CLIP attributes. Employing MANCE on top of previous methods shows consistent improved leakage results. We also introduce MANCE+ and MANCE++, which prepend a closed-form erasure algorithm before employing MANCE, achieving better leakage--surgicality tradeoffs relative to matched full-space updates. MANCE++, our best method, achieves state-of-the-art results on nonlinear concept erasure. These results support MCH in the erasure setting: interventions should be constrained to the natural representation manifold.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.03973.png", "numComments": 2, "submittedBy": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "fullname": "Matan Avitan", "name": "MatanAvitan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "634a981ccf84e1cc3f610ca1", "name": "barilan", "fullname": "Bar-Ilan University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/MRvtAhVBzuzijH-vDGBjr.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.02642", "authors": [{"_id": "6a4c64d625849b193a834046", "name": "GigaWorld Team", "hidden": false}, {"_id": "6a4c64d625849b193a834047", "user": {"_id": "64f020a42a7a94b68c0df99c", "avatarUrl": "/avatars/39315929c3675039f9a7662e7b60ad04.svg", "isPro": false, "fullname": "maangyuan", "user": "maay21", "type": "user", "name": "maay21"}, "name": "Angyuan Ma", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:12:09.489Z", "hidden": false}, {"_id": "6a4c64d625849b193a834048", "name": "Boyuan Wang", "hidden": false}, {"_id": "6a4c64d625849b193a834049", "name": "Bohan Li", "hidden": false}, {"_id": "6a4c64d625849b193a83404a", "name": "Chaojun Ni", "hidden": false}, {"_id": "6a4c64d625849b193a83404b", "name": "Guo Li", "hidden": false}, {"_id": "6a4c64d625849b193a83404c", "name": "Guan Huang", "hidden": false}, {"_id": "6a4c64d625849b193a83404d", "name": "Guosheng Zhao", "hidden": false}, {"_id": "6a4c64d625849b193a83404e", "name": "Hao Li", "hidden": false}, {"_id": "6a4c64d625849b193a83404f", "name": "Hengtao Li", "hidden": false}, {"_id": "6a4c64d625849b193a834050", "name": "Jingyu Liu", "hidden": false}, {"_id": "6a4c64d625849b193a834051", "name": "Jiwen Lu", "hidden": false}, {"_id": "6a4c64d625849b193a834052", "name": "Qiuping Deng", "hidden": false}, {"_id": "6a4c64d625849b193a834053", "name": "Tingdong Yu", "hidden": false}, {"_id": "6a4c64d625849b193a834054", "name": "Xuancheng Xu", "hidden": false}, {"_id": "6a4c64d625849b193a834055", "name": "Xinyu Zhou", "hidden": false}, {"_id": "6a4c64d625849b193a834056", "name": "Xiuwei Xu", "hidden": false}, {"_id": "6a4c64d625849b193a834057", "name": "Xinze Chen", "hidden": false}, {"_id": "6a4c64d625849b193a834058", "user": {"_id": "6426616ea5ec4a5cbc535634", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6426616ea5ec4a5cbc535634/5IfSFYd9QOxz8K9QmBCst.png", "isPro": false, "fullname": "JeffWang", "user": "Jeff-Wang", "type": "user", "name": "Jeff-Wang"}, "name": "Xiaofeng Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:12:13.375Z", "hidden": false}, {"_id": "6a4c64d625849b193a834059", "name": "Xiaoyu Tian", "hidden": false}, {"_id": "6a4c64d625849b193a83405a", "user": {"_id": "644012cf3e0374802e174f7c", "avatarUrl": "/avatars/0f4a4bd6f96ce193871843e1d01439e8.svg", "isPro": false, "fullname": "Yang Wang", "user": "supermodelteam", "type": "user", "name": "supermodelteam"}, "name": "Yang Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:12:11.475Z", "hidden": false}, {"_id": "6a4c64d625849b193a83405b", "name": "Yifan Chang", "hidden": false}, {"_id": "6a4c64d625849b193a83405c", "name": "Yukun Zhou", "hidden": false}, {"_id": "6a4c64d625849b193a83405d", "name": "Yun Ye", "hidden": false}, {"_id": "6a4c64d625849b193a83405e", "name": "Zhenyu Wu", "hidden": false}, {"_id": "6a4c64d625849b193a83405f", "name": "Zhanqian Wu", "hidden": false}, {"_id": "6a4c64d625849b193a834060", "name": "Zheng Zhu", "hidden": false}], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "GigaWorld-1: A Roadmap to Build World Models for Robot Policy Evaluation", "submittedOnDailyBy": {"_id": "6426616ea5ec4a5cbc535634", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6426616ea5ec4a5cbc535634/5IfSFYd9QOxz8K9QmBCst.png", "isPro": false, "fullname": "JeffWang", "user": "Jeff-Wang", "type": "user", "name": "Jeff-Wang"}, "summary": "Evaluating embodied robot foundation models remains a critical bottleneck; unlike large language models efficiently assessed via digital benchmarks, robotic policies require slow, costly real-world rollouts limited by hardware and human supervision, which has driven interest in world models as surrogate policy evaluators, yet the key properties that make a world model reliable for policy assessment remain poorly understood. This work presents a systematic study of world models for robotic policy evaluation and introduces WMBench, a benchmark constructed from real-robot teleoperation data and matched policy rollouts covering diverse manipulation tasks to enable controlled comparisons across model families, action encodings, rollout horizons, and evaluation metrics. Using WMBench, we analyze 7 video world models, 4 action representation schemes, and over 324,000 simulated policy rollouts paired with real robot executions, further enriching our analysis with large-scale community submissions from the CVPR 2026 GigaBrain Challenge, curated synthetic trajectories, and a training videos spanning more than 12,000 hours. Our experiments deliver three core insights: evaluator quality is dominated by long-horizon, action-faithful rollout consistency rather than short-term visual realism; pretraining gains stem not only from data scale but from balancing general world knowledge with robot-specific controllability; and architectural choices including action encoding, memory design, and evaluator-focused post-training strongly determine alignment with real-world robot behavior. Drawing on these results, we derive a practical design roadmap and realize it in GigaWorld-1, a world model specially optimized for policy evaluation, and we fully release our code, models, datasets, and toolkits to advance scalable evaluation research for embodied foundation models.", "upvotes": 31, "discussionId": "6a4c64d625849b193a834061", "projectPage": "https://open-gigaai.github.io/giga-world-1/", "githubRepo": "https://github.com/open-gigaai/giga-world-1", "githubRepoAddedBy": "user", "ai_summary": "World models for robotic policy evaluation are systematically studied through a new benchmark, revealing that long-horizon rollout consistency and robot-specific controllability are more important than short-term visual realism for reliable policy assessment.", "ai_keywords": ["world models", "robotic policies", "policy evaluation", "real-robot teleoperation", "video world models", "action representation schemes", "rollout horizons", "simulation", "real-world robot behavior", "GigaWorld-1"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 145, "organization": {"_id": "68d6587936e2de9610d9f5f0", "name": "open-gigaai", "fullname": "GigaAI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68d6394328e169473e90e4a6/zUK7FKr_8XqrN0aFUgsD-.png"}, "summary_zh": "<ul>\n    <li>\u8bc4\u4f30\u673a\u5668\u4eba\u57fa\u7840\u6a21\u578b\u9762\u4e34\u6311\u6218\uff0c\u4f20\u7edf\u7684\u65b9\u6cd5\u8017\u65f6\u4e14\u6210\u672c\u9ad8\u3002</li>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86WMBench\u57fa\u51c6\uff0c\u57fa\u4e8e\u771f\u5b9e\u673a\u5668\u4eba\u9065\u63a7\u6570\u636e\uff0c\u6db5\u76d6\u591a\u79cd\u64cd\u4f5c\u4efb\u52a1\u3002</li>\n    <li>\u901a\u8fc7WMBench\u5206\u6790\u4e86\u591a\u79cd\u4e16\u754c\u6a21\u578b\u548c\u7b56\u7565\u6267\u884c\uff0c\u53d1\u73b0\u8bc4\u4f30\u8d28\u91cf\u4e0e\u957f\u671f\u4e00\u81f4\u6027\u66f4\u76f8\u5173\u3002</li>\n    <li>\u9884\u8bad\u7ec3\u6548\u679c\u4e0d\u4ec5\u53d7\u6570\u636e\u89c4\u6a21\u5f71\u54cd\uff0c\u8fd8\u4e0e\u673a\u5668\u4eba\u7279\u5b9a\u53ef\u63a7\u6027\u5e73\u8861\u6709\u5173\u3002</li>\n    <li>\u7814\u7a76\u7ed3\u679c\u5e2e\u52a9\u8bbe\u8ba1\u4e86GigaWorld-1\uff0c\u4e00\u4e2a\u4e13\u4e3a\u653f\u7b56\u8bc4\u4f30\u4f18\u5316\u7684\u4e16\u754c\u6a21\u578b\uff0c\u5e76\u53d1\u5e03\u4e86\u76f8\u5173\u4ee3\u7801\u548c\u6570\u636e\u96c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Evaluating robotic models is challenging because it requires expensive real-world tests, unlike digital benchmarks for language models.</li>\n    <li>This research introduces WMBench, a benchmark for comparing different world models in robotic policy evaluation using real-world data.</li>\n    <li>WMBench includes a large dataset of real robot actions and simulated rollouts for various manipulation tasks.</li>\n    <li>Key findings show that long-term consistency in robot actions is more important than short-term visual accuracy for evaluation.</li>\n    <li>The study provides a roadmap for designing better world models and introduces GigaWorld-1, a new model for improved policy evaluation.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "GigaWorld-1: A Roadmap to Build World Models for Robot Policy Evaluation", "summary": "Evaluating embodied robot foundation models remains a critical bottleneck; unlike large language models efficiently assessed via digital benchmarks, robotic policies require slow, costly real-world rollouts limited by hardware and human supervision, which has driven interest in world models as surrogate policy evaluators, yet the key properties that make a world model reliable for policy assessment remain poorly understood. This work presents a systematic study of world models for robotic policy evaluation and introduces WMBench, a benchmark constructed from real-robot teleoperation data and matched policy rollouts covering diverse manipulation tasks to enable controlled comparisons across model families, action encodings, rollout horizons, and evaluation metrics. Using WMBench, we analyze 7 video world models, 4 action representation schemes, and over 324,000 simulated policy rollouts paired with real robot executions, further enriching our analysis with large-scale community submissions from the CVPR 2026 GigaBrain Challenge, curated synthetic trajectories, and a training videos spanning more than 12,000 hours. Our experiments deliver three core insights: evaluator quality is dominated by long-horizon, action-faithful rollout consistency rather than short-term visual realism; pretraining gains stem not only from data scale but from balancing general world knowledge with robot-specific controllability; and architectural choices including action encoding, memory design, and evaluator-focused post-training strongly determine alignment with real-world robot behavior. Drawing on these results, we derive a practical design roadmap and realize it in GigaWorld-1, a world model specially optimized for policy evaluation, and we fully release our code, models, datasets, and toolkits to advance scalable evaluation research for embodied foundation models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02642.png", "numComments": 1, "submittedBy": {"_id": "6426616ea5ec4a5cbc535634", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6426616ea5ec4a5cbc535634/5IfSFYd9QOxz8K9QmBCst.png", "fullname": "JeffWang", "name": "Jeff-Wang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "organization": {"_id": "68d6587936e2de9610d9f5f0", "name": "open-gigaai", "fullname": "GigaAI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68d6394328e169473e90e4a6/zUK7FKr_8XqrN0aFUgsD-.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.05247", "authors": [{"_id": "6a4c71ad25849b193a83410f", "name": "Zelin Fu", "hidden": false}, {"_id": "6a4c71ad25849b193a834110", "name": "Bin Tan", "hidden": false}, {"_id": "6a4c71ad25849b193a834111", "name": "Changjiang Sun", "hidden": false}, {"_id": "6a4c71ad25849b193a834112", "name": "Shaohui Liu", "hidden": false}, {"_id": "6a4c71ad25849b193a834113", "name": "Kecheng Zheng", "hidden": false}, {"_id": "6a4c71ad25849b193a834114", "name": "Yinghao Xu", "hidden": false}, {"_id": "6a4c71ad25849b193a834115", "name": "Xing Zhu", "hidden": false}, {"_id": "6a4c71ad25849b193a834116", "name": "Yujun Shen", "hidden": false}, {"_id": "6a4c71ad25849b193a834117", "user": {"_id": "6485ce5ec7f19728a49df17a", "avatarUrl": "/avatars/e83966e6906c1d0f151300981e30f85a.svg", "isPro": true, "fullname": "Nan", "user": "cherubicxn", "type": "user", "name": "cherubicxn"}, "name": "Nan Xue", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:39.054Z", "hidden": false}], "publishedAt": "2026-07-06T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "Vision Pretraining for Dense Spatial Perception", "submittedOnDailyBy": {"_id": "6485ce5ec7f19728a49df17a", "avatarUrl": "/avatars/e83966e6906c1d0f151300981e30f85a.svg", "isPro": true, "fullname": "Nan", "user": "cherubicxn", "type": "user", "name": "cherubicxn"}, "summary": "Dense spatial perception is essential for physical intelligence, where visual systems are expected to recover structured, metric, and actionable representations from pixel observations. Modern visual foundation models tend to prioritize semantic invariance, often at the expense of detailed spatial understanding. In this work, we study vision pretraining through a boundary-centric lens, motivated by the premise that boundaries and shape discontinuities offer essential cues for perceiving geometric properties. Concretely, we propose masked boundary modeling, a self-supervised paradigm that dynamically learns sub-pixel boundary representations and subsequently leverages the discovered boundary-bearing tokens as masked targets to facilitate dense visual token learning. By scaling this framework, we develop LingBot-Vision and demonstrate its efficacy across a diverse set of downstream vision tasks with DINOv3 as a strong baseline. Remarkably, LingBot-Vision drives the progression from LingBot-Depth 1.0 to LingBot-Depth 2.0 for depth completion, and thereby yields enhanced depth estimation, a key pillar for embodied artificial intelligence. Our findings reveal that boundary modeling goes beyond simple line segments and instead serves as a scalable pretraining principle for learning spatially structured visual representations.", "upvotes": 30, "discussionId": "6a4c71ae25849b193a834118", "projectPage": "https://technology.robbyant.com/lingbot-vision", "githubRepo": "https://github.com/Robbyant/lingbot-vision", "githubRepoAddedBy": "user", "ai_summary": "Boundary modeling enables dense spatial perception by learning sub-pixel representations that enhance depth estimation and support embodied AI applications.", "ai_keywords": ["boundary modeling", "masked boundary modeling", "visual foundation models", "spatial perception", "depth completion", "embodied artificial intelligence", "DINOv3", "dense visual token learning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 290, "organization": {"_id": "69709f892cd08371c1011a2e", "name": "robbyant", "fullname": "Robbyant", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67aeffda7330db26f93cd62f/ZTuImney4XzRmBHyUL47F.png"}, "summary_zh": "<ul>\n    <li>\u5bc6\u96c6\u7a7a\u95f4\u611f\u77e5\u5bf9\u7269\u7406\u667a\u80fd\u5f88\u91cd\u8981\uff0c\u89c6\u89c9\u7cfb\u7edf\u9700\u8981\u4ece\u50cf\u7d20\u89c2\u5bdf\u4e2d\u6062\u590d\u7ed3\u6784\u5316\u548c\u53ef\u64cd\u4f5c\u7684\u8868\u793a\u3002</li>\n    <li>\u73b0\u4ee3\u89c6\u89c9\u6a21\u578b\u5e38\u5e38\u91cd\u89c6\u8bed\u4e49\u4e0d\u53d8\u6027\uff0c\u4f46\u53ef\u80fd\u5ffd\u89c6\u8be6\u7ec6\u7684\u7a7a\u95f4\u7406\u89e3\u3002</li>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86\u4e00\u79cd\u8fb9\u754c\u4e2d\u5fc3\u7684\u89c6\u89d2\uff0c\u8ba4\u4e3a\u8fb9\u754c\u548c\u5f62\u72b6\u4e0d\u8fde\u7eed\u6027\u662f\u7406\u89e3\u51e0\u4f55\u7279\u6027\u7684\u5173\u952e\u7ebf\u7d22\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u63a9\u853d\u8fb9\u754c\u5efa\u6a21\u7684\u81ea\u76d1\u7763\u65b9\u6cd5\uff0c\u80fd\u591f\u52a8\u6001\u5b66\u4e60\u4e9a\u50cf\u7d20\u8fb9\u754c\u8868\u793a\uff0c\u5e76\u5229\u7528\u8fd9\u4e9b\u8fb9\u754c\u4f5c\u4e3a\u76ee\u6807\u8fdb\u884c\u5bc6\u96c6\u89c6\u89c9\u5b66\u4e60\u3002</li>\n    <li>LingBot-Vision\u5728\u591a\u4e2a\u89c6\u89c9\u4efb\u52a1\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u6539\u5584\u4e86\u6df1\u5ea6\u4f30\u8ba1\uff0c\u8fd9\u662f\u4f53\u73b0\u4eba\u5de5\u667a\u80fd\u7684\u91cd\u8981\u57fa\u7840\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Dense spatial perception is important for physical intelligence and requires visual systems to interpret detailed information from images.</li>\n    <li>Current visual models often focus more on general meanings rather than detailed spatial understanding.</li>\n    <li>This study introduces a method called masked boundary modeling, which focuses on learning important shapes and boundaries in images.</li>\n    <li>The researchers developed a new model, LingBot-Vision, which improves performance on various vision tasks and enhances depth estimation.</li>\n    <li>The findings suggest that focusing on boundaries can effectively help in learning structured visual representations for better artificial intelligence understanding.</li>\n</ul>"}, "publishedAt": "2026-07-05T20:00:00.000Z", "title": "Vision Pretraining for Dense Spatial Perception", "summary": "Dense spatial perception is essential for physical intelligence, where visual systems are expected to recover structured, metric, and actionable representations from pixel observations. Modern visual foundation models tend to prioritize semantic invariance, often at the expense of detailed spatial understanding. In this work, we study vision pretraining through a boundary-centric lens, motivated by the premise that boundaries and shape discontinuities offer essential cues for perceiving geometric properties. Concretely, we propose masked boundary modeling, a self-supervised paradigm that dynamically learns sub-pixel boundary representations and subsequently leverages the discovered boundary-bearing tokens as masked targets to facilitate dense visual token learning. By scaling this framework, we develop LingBot-Vision and demonstrate its efficacy across a diverse set of downstream vision tasks with DINOv3 as a strong baseline. Remarkably, LingBot-Vision drives the progression from LingBot-Depth 1.0 to LingBot-Depth 2.0 for depth completion, and thereby yields enhanced depth estimation, a key pillar for embodied artificial intelligence. Our findings reveal that boundary modeling goes beyond simple line segments and instead serves as a scalable pretraining principle for learning spatially structured visual representations.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.05247.png", "numComments": 1, "submittedBy": {"_id": "6485ce5ec7f19728a49df17a", "avatarUrl": "/avatars/e83966e6906c1d0f151300981e30f85a.svg", "fullname": "Nan", "name": "cherubicxn", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "69709f892cd08371c1011a2e", "name": "robbyant", "fullname": "Robbyant", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67aeffda7330db26f93cd62f/ZTuImney4XzRmBHyUL47F.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.04443", "authors": [{"_id": "6a4c5f6625849b193a833ff1", "name": "Lianghua Huang", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff2", "name": "Zhi-Fan Wu", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff3", "name": "Yupeng Shi", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff4", "name": "Wei Wang", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff5", "name": "Mengyang Feng", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff6", "name": "Junjie He", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff7", "name": "Chen-Wei Xie", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff8", "name": "Yu Liu", "hidden": false}, {"_id": "6a4c5f6625849b193a833ff9", "name": "Jingren Zhou", "hidden": false}, {"_id": "6a4c5f6625849b193a833ffa", "name": "Ang Wang", "hidden": false}, {"_id": "6a4c5f6625849b193a833ffb", "name": "Bang Zhang", "hidden": false}, {"_id": "6a4c5f6625849b193a833ffc", "name": "Baole Ai", "hidden": false}, {"_id": "6a4c5f6625849b193a833ffd", "name": "Chen Liang", "hidden": false}, {"_id": "6a4c5f6625849b193a833ffe", "name": "Cheng Yu", "hidden": false}, {"_id": "6a4c5f6625849b193a833fff", "name": "Chongyang Zhong", "hidden": false}, {"_id": "6a4c5f6625849b193a834000", "name": "Jinwei Qi", "hidden": false}, {"_id": "6a4c5f6625849b193a834001", "name": "Kai Zhu", "hidden": false}, {"_id": "6a4c5f6625849b193a834002", "name": "Pandeng Li", "hidden": false}, {"_id": "6a4c5f6625849b193a834003", "name": "Peng Zhang", "hidden": false}, {"_id": "6a4c5f6625849b193a834004", "name": "Wenyuan Zhang", "hidden": false}, {"_id": "6a4c5f6625849b193a834005", "name": "Xinhua Cheng", "hidden": false}, {"_id": "6a4c5f6625849b193a834006", "name": "Yitong Huang", "hidden": false}, {"_id": "6a4c5f6625849b193a834007", "name": "Yun Zheng", "hidden": false}, {"_id": "6a4c5f6625849b193a834008", "name": "Yuxiang Bao", "hidden": false}, {"_id": "6a4c5f6625849b193a834009", "name": "Yuzheng Wang", "hidden": false}, {"_id": "6a4c5f6625849b193a83400a", "name": "Zoubin Bi", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/u4BuVOD7pttMTbQ8u1m87.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/tbW9vra8ivsiYpkWrE7dJ.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/b6UkvflioEhKz4AV5pEoo.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/ynvOSvWNTVPEp9j0zP5IX.mp4"], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "Wan-Streamer v0.2: Higher Resolution, Same Latency", "submittedOnDailyBy": {"_id": "6522cf31777019ca30d85725", "avatarUrl": "/avatars/a180b096e438e429d445b68fe703e43f.svg", "isPro": false, "fullname": "Lianghua Huang", "user": "lhhuang", "type": "user", "name": "lhhuang"}, "summary": "We present Wan-Streamer v0.2, a latency-preserving upgrade of the native-streaming, end-to-end audio-visual interaction model. v0.2 keeps the v0.1 modeling formulation, but raises the interactive output stream from 192x336 to 640x368 while preserving approximately 200 ms model-side signal-to-signal latency at 25 FPS. The higher-resolution stream supports scene-grounded mid-shot agents whose posture, gaze, hands, nearby objects, and local scene layout remain legible during real-time conversation. To support the larger visual stream without adding user-visible delay, v0.2 keeps the thinker as a single-GPU low-latency path for streaming perception, the short language/state Transformer pass that builds the generation cache, and final decoding. The performer becomes a multi-GPU Ulysses-style context-parallel group for the expensive next-unit latent generation. Each performer rank writes incoming K/V into a pre-sharded local cache. The long high-resolution latent video sequence is split across ranks for denoising and gathered through Ulysses communication, while the much shorter audio latent sequence is generated without sequence sharding. In this split, the thinker's language/state computation reaches the performer only as K/V conditioning, so no separate language sequence has to be communicated inside the performer group. This concentrates additional hardware on visual generation while preserving the compact thinker-performer boundary, keeping total remote interaction latency at approximately 550 ms when a 350 ms bidirectional network budget is included.", "upvotes": 24, "discussionId": "6a4c5f6625849b193a83400b", "projectPage": "https://wan-streamer.com/", "ai_summary": "Wan-Streamer v0.2 enhances audio-visual interaction by increasing visual resolution while maintaining low latency through optimized thinker-performer architecture with multi-GPU parallel processing.", "ai_keywords": ["streaming perception", "Transformer", "generation cache", "final decoding", "Ulysses-style context-parallel group", "pre-sharded local cache", "denoising", "Ulysses communication", "visual generation", "audio latent sequence", "language/state computation", "K/V conditioning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "67bc7cd418dd753c02a82684", "name": "Wan-AI", "fullname": "Wan-AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67b610677ea7952def8b29c6/N6jQbbeaa_FcUY-wI1dgG.png"}, "summary_zh": "<ul>\n    <li>\u63a8\u51fa\u4e86Wan-Streamer v0.2\uff0c\u8fd9\u662f\u4e00\u4e2a\u6539\u8fdb\u7684\u97f3\u89c6\u9891\u4e92\u52a8\u6a21\u578b\uff0c\u5ef6\u8fdf\u4fdd\u6301\u4e0d\u53d8\u3002</li>\n    <li>\u65b0\u7248\u672c\u5c06\u4e92\u52a8\u8f93\u51fa\u6d41\u7684\u5206\u8fa8\u7387\u4ece192x336\u63d0\u5347\u5230640x368\uff0c\u540c\u65f6\u4fdd\u6301\u7ea6200\u6beb\u79d2\u7684\u4fe1\u53f7\u5ef6\u8fdf\uff0c\u5e27\u7387\u4e3a25 FPS\u3002</li>\n    <li>\u66f4\u9ad8\u7684\u5206\u8fa8\u7387\u652f\u6301\u5728\u5b9e\u65f6\u5bf9\u8bdd\u4e2d\u6e05\u6670\u663e\u793a\u573a\u666f\u4e2d\u7684\u4e2d\u666f\u4ee3\u7406\u7684\u59ff\u52bf\u3001\u89c6\u7ebf\u3001\u624b\u52bf\u53ca\u5468\u56f4\u7269\u4f53\u3002</li>\n    <li>\u901a\u8fc7\u4f7f\u7528\u5355GPU\u4f4e\u5ef6\u8fdf\u8def\u5f84\u5904\u7406\u611f\u77e5\uff0cv0.2\u907f\u514d\u4e86\u7528\u6237\u53ef\u89c1\u7684\u5ef6\u8fdf\u3002</li>\n    <li>\u4fdd\u6301\u4e86\u7d27\u51d1\u7684\u601d\u8003\u8005\u4e0e\u6267\u884c\u8005\u8fb9\u754c\uff0c\u786e\u4fdd\u603b\u7684\u8fdc\u7a0b\u4e92\u52a8\u5ef6\u8fdf\u7ea6\u4e3a550\u6beb\u79d2\uff0c\u5305\u62ec350\u6beb\u79d2\u7684\u53cc\u5411\u7f51\u7edc\u9884\u7b97\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Wan-Streamer v0.2 is an upgrade to an audio-visual interaction model that maintains low latency.</li>\n    <li>The output video resolution has improved from 192x336 to 640x368 while keeping signal delays around 200 ms at 25 frames per second.</li>\n    <li>This higher resolution allows for clearer visuals of characters' actions and surroundings during conversations.</li>\n    <li>The model uses a single GPU for fast processing and a multi-GPU setup for complex video generation, ensuring no extra delays for users.</li>\n    <li>Total interaction latency is kept around 550 ms, factoring in network delays.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "Wan-Streamer v0.2: Higher Resolution, Same Latency", "summary": "We present Wan-Streamer v0.2, a latency-preserving upgrade of the native-streaming, end-to-end audio-visual interaction model. v0.2 keeps the v0.1 modeling formulation, but raises the interactive output stream from 192x336 to 640x368 while preserving approximately 200 ms model-side signal-to-signal latency at 25 FPS. The higher-resolution stream supports scene-grounded mid-shot agents whose posture, gaze, hands, nearby objects, and local scene layout remain legible during real-time conversation. To support the larger visual stream without adding user-visible delay, v0.2 keeps the thinker as a single-GPU low-latency path for streaming perception, the short language/state Transformer pass that builds the generation cache, and final decoding. The performer becomes a multi-GPU Ulysses-style context-parallel group for the expensive next-unit latent generation. Each performer rank writes incoming K/V into a pre-sharded local cache. The long high-resolution latent video sequence is split across ranks for denoising and gathered through Ulysses communication, while the much shorter audio latent sequence is generated without sequence sharding. In this split, the thinker's language/state computation reaches the performer only as K/V conditioning, so no separate language sequence has to be communicated inside the performer group. This concentrates additional hardware on visual generation while preserving the compact thinker-performer boundary, keeping total remote interaction latency at approximately 550 ms when a 350 ms bidirectional network budget is included.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/u4BuVOD7pttMTbQ8u1m87.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/tbW9vra8ivsiYpkWrE7dJ.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/b6UkvflioEhKz4AV5pEoo.mp4", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/ynvOSvWNTVPEp9j0zP5IX.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04443.png", "numComments": 1, "submittedBy": {"_id": "6522cf31777019ca30d85725", "avatarUrl": "/avatars/a180b096e438e429d445b68fe703e43f.svg", "fullname": "Lianghua Huang", "name": "lhhuang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "67bc7cd418dd753c02a82684", "name": "Wan-AI", "fullname": "Wan-AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67b610677ea7952def8b29c6/N6jQbbeaa_FcUY-wI1dgG.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.02646", "authors": [{"_id": "6a4c791e25849b193a83417c", "name": "Heqing Yang", "hidden": false}, {"_id": "6a4c791e25849b193a83417d", "name": "Yang Yi", "hidden": false}, {"_id": "6a4c791e25849b193a83417e", "name": "Liyao Wang", "hidden": false}, {"_id": "6a4c791e25849b193a83417f", "name": "Linqing Zhong", "hidden": false}, {"_id": "6a4c791e25849b193a834180", "name": "Donglin Yang", "hidden": false}, {"_id": "6a4c791e25849b193a834181", "name": "Ruipu Wu", "hidden": false}, {"_id": "6a4c791e25849b193a834182", "name": "Zitong Bai", "hidden": false}, {"_id": "6a4c791e25849b193a834183", "name": "Fengjiao Chen", "hidden": false}, {"_id": "6a4c791e25849b193a834184", "name": "Manyuan Zhang", "hidden": false}, {"_id": "6a4c791e25849b193a834185", "name": "Linjiang Huang", "hidden": false}, {"_id": "6a4c791e25849b193a834186", "name": "Si Liu", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65fc7c824d36be78e66ba92d/WGaseoy5VE0a1kyLjbuYg.mp4"], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "EVA-Client: A Unified Data Collection, Inference, and Deployment Framework for Embodied Policies on Real Robots", "submittedOnDailyBy": {"_id": "65fc7c824d36be78e66ba92d", "avatarUrl": "/avatars/d4a55c820cae533f91724e062427516a.svg", "isPro": false, "fullname": "Linjiang Huang", "user": "LjHuang", "type": "user", "name": "LjHuang"}, "summary": "We present EVA-Client, an open-source framework for deployment, data collection, and evaluation of trained manipulation policies on real robots. Sitting between a policy server and the physical hardware, EVA-Client unifies the real-robot stages of the policy iteration loop within a single codebase. It makes three contributions. First, a component-decoupled architecture in which robot backends, inference strategies, and transport middlewares form an orthogonal grid: adding a robot or a strategy touches only its own layer. Second, inspectable execution through Debug, Collect, and Eval workflows, with modes ranging from open-loop simulation to continuous real-time control. Third, every evaluation run doubles as a data collection, recording full rollouts in training-ready format alongside exhaustive logs and a side-by-side comparison viewer, so each evaluation feeds the next round of training rather than ending as an unrecorded impression. EVA-Client further consolidates major real-time inference strategies, synchronous and asynchronous execution, ACT-style temporal ensembling, Real-Time Chunking, and a naive-async ablation baseline, behind a single configuration surface.", "upvotes": 23, "discussionId": "6a4c791e25849b193a834187", "projectPage": "https://colalab.net/projects/eva-client/", "githubRepo": "https://github.com/Noietch/EVA-CLIENT", "githubRepoAddedBy": "user", "ai_summary": "EVA-Client is an open-source framework that unifies real-robot policy deployment, data collection, and evaluation through a component-decoupled architecture with inspectable execution workflows.", "ai_keywords": ["policy iteration loop", "robot backends", "inference strategies", "transport middlewares", "debug workflow", "collect workflow", "eval workflow", "real-time control", "synchronous execution", "asynchronous execution", "temporal ensembling", "real-time chunking", "naive-async ablation baseline"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 40, "summary_zh": "<ul>\n    <li>EVA-Client\u662f\u4e00\u4e2a\u5f00\u6e90\u6846\u67b6\uff0c\u7528\u4e8e\u5728\u771f\u5b9e\u673a\u5668\u4eba\u4e0a\u90e8\u7f72\u3001\u6536\u96c6\u6570\u636e\u548c\u8bc4\u4f30\u8bad\u7ec3\u597d\u7684\u64cd\u4f5c\u7b56\u7565\u3002</li>\n    <li>\u5b83\u5c06\u7b56\u7565\u670d\u52a1\u5668\u548c\u7269\u7406\u786c\u4ef6\u6574\u5408\u5728\u4e00\u4e2a\u4ee3\u7801\u5e93\u4e2d\uff0c\u7b80\u5316\u4e86\u771f\u5b9e\u673a\u5668\u4eba\u64cd\u4f5c\u7684\u8fc7\u7a0b\u3002</li>\n    <li>\u6846\u67b6\u7684\u67b6\u6784\u4f7f\u5f97\u53ef\u4ee5\u72ec\u7acb\u6dfb\u52a0\u673a\u5668\u4eba\u6216\u7b56\u7565\uff0c\u800c\u4e0d\u5f71\u54cd\u5176\u4ed6\u90e8\u5206\u3002</li>\n    <li>\u63d0\u4f9b\u4e86\u53ef\u68c0\u67e5\u7684\u6267\u884c\u6d41\u7a0b\uff0c\u5305\u62ec\u8c03\u8bd5\u3001\u6570\u636e\u6536\u96c6\u548c\u8bc4\u4f30\u6a21\u5f0f\uff0c\u652f\u6301\u4ece\u6a21\u62df\u5230\u5b9e\u65f6\u63a7\u5236\u7684\u591a\u79cd\u6a21\u5f0f\u3002</li>\n    <li>\u6bcf\u6b21\u8bc4\u4f30\u90fd\u4f1a\u6536\u96c6\u5b8c\u6574\u7684\u6570\u636e\u5e76\u8bb0\u5f55\u65e5\u5fd7\uff0c\u4e3a\u540e\u7eed\u8bad\u7ec3\u63d0\u4f9b\u652f\u6301\uff0c\u800c\u4e0d\u662f\u4ec5\u4ec5\u4f5c\u4e3a\u4e00\u6b21\u6027\u8bc4\u4f30\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>EVA-Client is an open-source tool designed to help deploy, collect data, and evaluate robot manipulation policies.</li>\n    <li>It connects the policy server and physical robots, allowing for a unified approach to testing and improving robot performance.</li>\n    <li>The framework features a flexible design that makes it easy to add new robots or strategies without affecting other parts.</li>\n    <li>It includes workflows for debugging, data collection, and evaluation, enabling various types of testing from simulations to real-time control.</li>\n    <li>Each evaluation not only assesses performance but also collects useful data for future training, improving the learning process for robots.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "EVA-Client: A Unified Data Collection, Inference, and Deployment Framework for Embodied Policies on Real Robots", "summary": "We present EVA-Client, an open-source framework for deployment, data collection, and evaluation of trained manipulation policies on real robots. Sitting between a policy server and the physical hardware, EVA-Client unifies the real-robot stages of the policy iteration loop within a single codebase. It makes three contributions. First, a component-decoupled architecture in which robot backends, inference strategies, and transport middlewares form an orthogonal grid: adding a robot or a strategy touches only its own layer. Second, inspectable execution through Debug, Collect, and Eval workflows, with modes ranging from open-loop simulation to continuous real-time control. Third, every evaluation run doubles as a data collection, recording full rollouts in training-ready format alongside exhaustive logs and a side-by-side comparison viewer, so each evaluation feeds the next round of training rather than ending as an unrecorded impression. EVA-Client further consolidates major real-time inference strategies, synchronous and asynchronous execution, ACT-style temporal ensembling, Real-Time Chunking, and a naive-async ablation baseline, behind a single configuration surface.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65fc7c824d36be78e66ba92d/WGaseoy5VE0a1kyLjbuYg.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02646.png", "numComments": 1, "submittedBy": {"_id": "65fc7c824d36be78e66ba92d", "avatarUrl": "/avatars/d4a55c820cae533f91724e062427516a.svg", "fullname": "Linjiang Huang", "name": "LjHuang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2607.04033", "authors": [{"_id": "6a4c985925849b193a834362", "name": "Siyuan Li", "hidden": false}, {"_id": "6a4c985925849b193a834363", "name": "Jiabao Pan", "hidden": false}, {"_id": "6a4c985925849b193a834364", "name": "Yumou Liu", "hidden": false}, {"_id": "6a4c985925849b193a834365", "name": "Zhuoli Ouyang", "hidden": false}, {"_id": "6a4c985925849b193a834366", "name": "Xin Jin", "hidden": false}, {"_id": "6a4c985925849b193a834367", "name": "Xinglong Xu", "hidden": false}, {"_id": "6a4c985925849b193a834368", "name": "Jingxuan Wei", "hidden": false}, {"_id": "6a4c985925849b193a834369", "name": "Shengye Pang", "hidden": false}, {"_id": "6a4c985925849b193a83436a", "name": "Jintao Che", "hidden": false}, {"_id": "6a4c985925849b193a83436b", "name": "Xuanhe Zhou", "hidden": false}, {"_id": "6a4c985925849b193a83436c", "name": "Conghui He", "hidden": false}, {"_id": "6a4c985925849b193a83436d", "name": "Cheng Tan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64be296a46cc3cdfbb057f7e/fcymBQFAev-N5KfQ67hXj.png"], "publishedAt": "2026-07-04T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "OmniOpt: Taxonomy, Geometry, and Benchmarking of Modern Optimizers", "submittedOnDailyBy": {"_id": "64be296a46cc3cdfbb057f7e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64be296a46cc3cdfbb057f7e/jSHeNY2AcPifCZzJyFhr4.jpeg", "isPro": false, "fullname": "Cheng Tan", "user": "chengtan9907", "type": "user", "name": "chengtan9907"}, "summary": "Optimizer selection for large-scale model training has become a system-level design decision constrained jointly by compute, memory, tuning budget, and task diversity, yet the landscape of over one hundred methods remains fragmented. We therefore present OmniOpt, a unified survey and benchmark cookbook of optimizers for the research community. OmniOpt rests on four coupled components. First, we treat every optimizer update as a structured transformation through a five-stage meta-pipeline, and show that most methods engage only one or two of these stages. Second, we use norm-constrained linear minimization oracles (LMOs) to unify different optimizers. Third, these two views ground a dual-dimension taxonomy, one dimension assigning each method to a mechanism family and the other recording the measurable training objectives it aims to improve. Fourth, and at the core of this paper, we instantiate the full taxonomy in a unified cross-domain benchmark spanning representative optimizers, model scales, and training regimes from language model pretraining to image classification, systematically analyzing each method family across multiple effect objectives and laying out their trade-offs. OmniOpt thus supplies the research community with an operational coordinate system for selecting optimizers under explicit mechanism and objective assumptions, and charts a direction for the future development of the optimizer community.", "upvotes": 64, "discussionId": "6a4c985925849b193a83436e", "projectPage": "https://openraiser.github.io/OmniOpt/", "githubRepo": "https://github.com/OpenRaiser/OmniOpt", "githubRepoAddedBy": "user", "ai_summary": "OmniOpt presents a unified framework for optimizer selection in large-scale model training by combining meta-pipeline transformations, norm-constrained linear minimization oracles, and a cross-domain benchmark to systematically analyze optimizer families and their trade-offs across different training objectives and model scales.", "ai_keywords": ["optimizer selection", "large-scale model training", "meta-pipeline", "norm-constrained linear minimization oracles", "cross-domain benchmark", "optimizer families", "training objectives", "model scales", "systematic analysis", "trade-offs"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 28, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "summary_zh": "<ul>\n    <li>\u4f18\u5316\u5668\u9009\u62e9\u5728\u5927\u89c4\u6a21\u6a21\u578b\u8bad\u7ec3\u4e2d\u662f\u4e00\u4e2a\u7cfb\u7edf\u8bbe\u8ba1\u7684\u51b3\u7b56\uff0c\u53d7\u5230\u8ba1\u7b97\u3001\u5185\u5b58\u548c\u4efb\u52a1\u591a\u6837\u6027\u7684\u5f71\u54cd\u3002</li>\n    <li>OmniOpt\u662f\u4e00\u4e2a\u7edf\u4e00\u7684\u4f18\u5316\u5668\u8c03\u67e5\u548c\u57fa\u51c6\u5de5\u5177\uff0c\u4e3a\u7814\u7a76\u793e\u533a\u63d0\u4f9b\u53c2\u8003\u3002</li>\n    <li>OmniOpt\u5305\u62ec\u56db\u4e2a\u4e3b\u8981\u90e8\u5206\uff0c\u5176\u4e2d\u6bcf\u4e2a\u4f18\u5316\u5668\u7684\u66f4\u65b0\u88ab\u89c6\u4e3a\u7ed3\u6784\u5316\u53d8\u6362\uff0c\u901a\u8fc7\u4e94\u4e2a\u9636\u6bb5\u7684\u5143\u7ba1\u9053\u8fdb\u884c\u5904\u7406\u3002</li>\n    <li>\u8be5\u5de5\u5177\u4f7f\u7528\u7ea6\u675f\u7ebf\u6027\u6700\u5c0f\u5316oracle\u6765\u7edf\u4e00\u4e0d\u540c\u7684\u4f18\u5316\u5668\uff0c\u5e76\u5efa\u7acb\u4e86\u4e00\u4e2a\u53cc\u7ef4\u5206\u7c7b\u6cd5\u3002</li>\n    <li>OmniOpt\u63d0\u4f9b\u4e86\u4e00\u4e2a\u64cd\u4f5c\u5750\u6807\u7cfb\u7edf\uff0c\u5e2e\u52a9\u7814\u7a76\u4eba\u5458\u5728\u660e\u786e\u7684\u673a\u5236\u548c\u76ee\u6807\u5047\u8bbe\u4e0b\u9009\u62e9\u4f18\u5316\u5668\uff0c\u5e76\u6307\u5f15\u672a\u6765\u7684\u4f18\u5316\u5668\u53d1\u5c55\u65b9\u5411\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Optimizer selection for large models is a complex decision influenced by many factors like compute resources and task diversity.</li>\n    <li>OmniOpt is a comprehensive guide and benchmark for different optimizers aimed at researchers.</li>\n    <li>It includes a five-stage process to analyze how different optimizers work, showing that many only use a part of this process.</li>\n    <li>OmniOpt categorizes optimizers based on their mechanisms and the goals they try to achieve.</li>\n    <li>It provides a detailed benchmark for comparing optimizers across various tasks, helping researchers make better choices in their work.</li>\n</ul>"}, "publishedAt": "2026-07-03T20:00:00.000Z", "title": "OmniOpt: Taxonomy, Geometry, and Benchmarking of Modern Optimizers", "summary": "Optimizer selection for large-scale model training has become a system-level design decision constrained jointly by compute, memory, tuning budget, and task diversity, yet the landscape of over one hundred methods remains fragmented. We therefore present OmniOpt, a unified survey and benchmark cookbook of optimizers for the research community. OmniOpt rests on four coupled components. First, we treat every optimizer update as a structured transformation through a five-stage meta-pipeline, and show that most methods engage only one or two of these stages. Second, we use norm-constrained linear minimization oracles (LMOs) to unify different optimizers. Third, these two views ground a dual-dimension taxonomy, one dimension assigning each method to a mechanism family and the other recording the measurable training objectives it aims to improve. Fourth, and at the core of this paper, we instantiate the full taxonomy in a unified cross-domain benchmark spanning representative optimizers, model scales, and training regimes from language model pretraining to image classification, systematically analyzing each method family across multiple effect objectives and laying out their trade-offs. OmniOpt thus supplies the research community with an operational coordinate system for selecting optimizers under explicit mechanism and objective assumptions, and charts a direction for the future development of the optimizer community.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64be296a46cc3cdfbb057f7e/fcymBQFAev-N5KfQ67hXj.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04033.png", "numComments": 1, "submittedBy": {"_id": "64be296a46cc3cdfbb057f7e", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64be296a46cc3cdfbb057f7e/jSHeNY2AcPifCZzJyFhr4.jpeg", "fullname": "Cheng Tan", "name": "chengtan9907", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04425", "authors": [{"_id": "6a4c6de625849b193a8340c5", "user": {"_id": "69e06fafde9dfdc5821f3854", "avatarUrl": "/avatars/414474811a19c5dfc3a121e29608b391.svg", "isPro": false, "fullname": "Lian", "user": "EliSpctre", "type": "user", "name": "EliSpctre"}, "name": "Niu Lian", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:48.669Z", "hidden": false}, {"_id": "6a4c6de625849b193a8340c6", "name": "Alan Chen", "hidden": false}, {"_id": "6a4c6de625849b193a8340c7", "name": "Zhehao Yu", "hidden": false}, {"_id": "6a4c6de625849b193a8340c8", "name": "Chengzhen Duan", "hidden": false}, {"_id": "6a4c6de625849b193a8340c9", "name": "Fazhan Liu", "hidden": false}, {"_id": "6a4c6de625849b193a8340ca", "name": "Hui Liu", "hidden": false}, {"_id": "6a4c6de625849b193a8340cb", "name": "Pei Fu", "hidden": false}, {"_id": "6a4c6de625849b193a8340cc", "name": "Jian Luan", "hidden": false}, {"_id": "6a4c6de625849b193a8340cd", "name": "Yaowei Wang", "hidden": false}, {"_id": "6a4c6de625849b193a8340ce", "name": "Shu-Tao Xia", "hidden": false}, {"_id": "6a4c6de625849b193a8340cf", "name": "Jinpeng Wang", "hidden": false}], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "UI-MOPD: Multi-Platform On-Policy Distillation for Continual GUI Agent Learning", "submittedOnDailyBy": {"_id": "65d70e775e971572da16c05b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65d70e775e971572da16c05b/8Cv71Clfk_C7k6U4yI6ln.jpeg", "isPro": false, "fullname": "Yuhong Dai", "user": "BroAlanTaps", "type": "user", "name": "BroAlanTaps"}, "summary": "Recent advances in multimodal foundation models and agent systems have driven GUI agents from single-platform task execution toward cross-platform interaction. However, building multi-platform GUI agents remains challenging. On one hand, high-quality and executable cross-platform interaction trajectories are still scarce, and existing data often suffer from limited platform coverage. On the other hand, different platforms exhibit distinct interaction conventions, making joint or continual training prone to behavioral pattern mixing, platform-specific capability degradation, and catastrophic forgetting. To address these challenges, we construct Uni-GUI, a high-quality cross-platform GUI interaction dataset, and propose UI-MOPD, the first method that incorporates multi-teacher on-policy distillation into continual learning for GUI agents. UI-MOPD dynamically selects a platform-specific teacher according to the current environment and transfers platform-specific behavioral priors to a shared policy through platform-conditioned distillation, enabling adaptation to new platforms while preserving capabilities on existing ones. Experiments on OSWorld and MobileWorld show that UI-MOPD achieves task success rates of 38.2% and 12.0%, respectively, demonstrating its effectiveness in balancing cross-platform capability retention and new-platform adaptation.\n  Project page: https://elispectre.github.io/UI-MOPD/.", "upvotes": 62, "discussionId": "6a4c6de625849b193a8340d0", "ai_summary": "Uni-GUI dataset and UI-MOPD method enable cross-platform GUI agent training by addressing limited data and platform-specific capability degradation through multi-teacher on-policy distillation.", "ai_keywords": ["multimodal foundation models", "agent systems", "GUI agents", "cross-platform interaction", "continual learning", "multi-teacher on-policy distillation", "platform-conditioned distillation", "behavioral pattern mixing", "catastrophic forgetting"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u7814\u7a76\u63a8\u52a8\u4e86\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\u548c\u4ee3\u7406\u7cfb\u7edf\u7684\u53d1\u5c55\uff0c\u4f7f\u5f97\u56fe\u5f62\u7528\u6237\u754c\u9762\uff08GUI\uff09\u4ee3\u7406\u80fd\u591f\u5728\u591a\u4e2a\u5e73\u53f0\u4e0a\u8fdb\u884c\u4e92\u52a8\u3002</li>\n    <li>\u6784\u5efa\u591a\u5e73\u53f0GUI\u4ee3\u7406\u9762\u4e34\u6311\u6218\uff0c\u5305\u62ec\u7f3a\u4e4f\u9ad8\u8d28\u91cf\u7684\u53ef\u6267\u884c\u8de8\u5e73\u53f0\u4e92\u52a8\u6570\u636e\u548c\u4e0d\u540c\u5e73\u53f0\u7684\u4e92\u52a8\u89c4\u8303\u5dee\u5f02\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e9b\u95ee\u9898\uff0c\u7814\u7a76\u8005\u4eec\u6784\u5efa\u4e86Uni-GUI\u6570\u636e\u96c6\uff0c\u5e76\u63d0\u51fa\u4e86UI-MOPD\u65b9\u6cd5\uff0c\u8fd9\u662f\u4e00\u79cd\u7ed3\u5408\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u7684\u6301\u7eed\u5b66\u4e60\u65b9\u6cd5\u3002</li>\n    <li>UI-MOPD\u6839\u636e\u5f53\u524d\u73af\u5883\u52a8\u6001\u9009\u62e9\u5e73\u53f0\u7279\u5b9a\u7684\u6559\u5e08\uff0c\u5e76\u901a\u8fc7\u5e73\u53f0\u6761\u4ef6\u84b8\u998f\u5c06\u884c\u4e3a\u5148\u9a8c\u4f20\u9012\u5230\u5171\u4eab\u7b56\u7565\uff0c\u4ee5\u9002\u5e94\u65b0\u5e73\u53f0\u3002</li>\n    <li>\u5728OSWorld\u548cMobileWorld\u4e0a\u7684\u5b9e\u9a8c\u8868\u660e\uff0cUI-MOPD\u5728\u8de8\u5e73\u53f0\u80fd\u529b\u4fdd\u6301\u548c\u65b0\u5e73\u53f0\u9002\u5e94\u65b9\u9762\u8868\u73b0\u6709\u6548\uff0c\u4efb\u52a1\u6210\u529f\u7387\u5206\u522b\u4e3a38.2%\u548c12.0%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent developments in GUI agents allow them to work across different platforms, but creating effective multi-platform agents is still difficult.</li>\n    <li>Challenges include a lack of high-quality interaction data for various platforms and differences in how each platform operates.</li>\n    <li>To tackle these challenges, researchers created Uni-GUI, a dataset for cross-platform GUI interactions, and introduced a new learning method called UI-MOPD.</li>\n    <li>UI-MOPD uses multiple teachers to help GUI agents learn from specific platforms, allowing them to adapt to new ones without losing skills on existing platforms.</li>\n    <li>Tests on two platforms showed that UI-MOPD significantly improves the ability of agents to succeed in tasks across different environments.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "UI-MOPD: Multi-Platform On-Policy Distillation for Continual GUI Agent Learning", "summary": "Recent advances in multimodal foundation models and agent systems have driven GUI agents from single-platform task execution toward cross-platform interaction. However, building multi-platform GUI agents remains challenging. On one hand, high-quality and executable cross-platform interaction trajectories are still scarce, and existing data often suffer from limited platform coverage. On the other hand, different platforms exhibit distinct interaction conventions, making joint or continual training prone to behavioral pattern mixing, platform-specific capability degradation, and catastrophic forgetting. To address these challenges, we construct Uni-GUI, a high-quality cross-platform GUI interaction dataset, and propose UI-MOPD, the first method that incorporates multi-teacher on-policy distillation into continual learning for GUI agents. UI-MOPD dynamically selects a platform-specific teacher according to the current environment and transfers platform-specific behavioral priors to a shared policy through platform-conditioned distillation, enabling adaptation to new platforms while preserving capabilities on existing ones. Experiments on OSWorld and MobileWorld show that UI-MOPD achieves task success rates of 38.2% and 12.0%, respectively, demonstrating its effectiveness in balancing cross-platform capability retention and new-platform adaptation.\n  Project page: https://elispectre.github.io/UI-MOPD/.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04425.png", "numComments": 1, "submittedBy": {"_id": "65d70e775e971572da16c05b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65d70e775e971572da16c05b/8Cv71Clfk_C7k6U4yI6ln.jpeg", "fullname": "Yuhong Dai", "name": "BroAlanTaps", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2607.02512", "authors": [{"_id": "6a4712d46ee372f6920de276", "name": "Wentao Zhang", "hidden": false}, {"_id": "6a4712d46ee372f6920de277", "name": "Liliana Hotsko", "hidden": false}, {"_id": "6a4712d46ee372f6920de278", "name": "Woojeong Kim", "hidden": false}, {"_id": "6a4712d46ee372f6920de279", "name": "Pengyu Nie", "hidden": false}, {"_id": "6a4712d46ee372f6920de27a", "name": "Stuart Shieber", "hidden": false}, {"_id": "6a4712d46ee372f6920de27b", "name": "Yuntian Deng", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/DH3lU8-hbyZWRqfSacODD.gif", "https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/W2Xef_bIMFzQiSojtgz2i.gif", "https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/ipYvADQRDJEz7f2zqZg0M.gif"], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-03T00:00:00.000Z", "title": "Program-as-Weights: A Programming Paradigm for Fuzzy Functions", "submittedOnDailyBy": {"_id": "63081e15a670ed10f9d44229", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/63081e15a670ed10f9d44229/w1b9uq-9774bMMgJbSPsS.jpeg", "isPro": true, "fullname": "Yuntian Deng", "user": "yuntian-deng", "type": "user", "name": "yuntian-deng"}, "summary": "Many everyday programming tasks resist clean rule-based implementation, such as alerting on important log lines, repairing malformed JSON, or ranking search results by intent, and are increasingly outsourced to large language model APIs at the cost of locality, reproducibility, and price. We propose fuzzy-function programming: compiling such a function from a natural-language specification into a compact, locally-executable neural artifact. We instantiate this paradigm with Program-as-Weights (PAW), in which a 4B compiler trained on FuzzyBench, a 10M-example dataset we release, emits parameter-efficient adapters for a frozen, lightweight interpreter. A 0.6B Qwen3 interpreter executing PAW programs matches the performance of direct prompting of Qwen3-32B, while using roughly one fiftieth of the inference memory and running at 30 tokens/s on a MacBook M3. PAW reframes the foundation model from a per-input problem solver into a tool builder: invoked once per function definition, it produces a small reusable artifact whose subsequent calls per function application are cheap and offline.", "upvotes": 56, "discussionId": "6a4712d46ee372f6920de27c", "projectPage": "https://programasweights.com/", "githubRepo": "https://github.com/programasweights/programasweights-python", "githubRepoAddedBy": "user", "ai_summary": "Fuzzy-function programming compiles natural-language specifications into compact neural artifacts using a 4B compiler and 0.6B interpreter, achieving efficient, local execution with reduced memory usage and faster inference.", "ai_keywords": ["Program-as-Weights", "FuzzyBench", "parameter-efficient adapters", "frozen interpreter", "neural artifact", "foundation model", "tool builder"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 99, "organization": {"_id": "6230c3ced93e84e2338765f3", "name": "UWaterloo", "fullname": "University of Waterloo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1647363004040-6230c34bacb94a81eec91ed5.png"}, "summary_zh": "<ul>\n    <li>\u5f88\u591a\u65e5\u5e38\u7f16\u7a0b\u4efb\u52a1\u96be\u4ee5\u7528\u7b80\u5355\u7684\u89c4\u5219\u5b9e\u73b0\uff0c\u6bd4\u5982\u91cd\u8981\u65e5\u5fd7\u7684\u63d0\u9192\u3001\u4fee\u590d\u4e0d\u89c4\u8303\u7684JSON\u6216\u6839\u636e\u610f\u56fe\u6392\u540d\u641c\u7d22\u7ed3\u679c\u3002</li>\n    <li>\u8fd9\u4e9b\u4efb\u52a1\u8d8a\u6765\u8d8a\u591a\u5730\u4f9d\u8d56\u5927\u578b\u8bed\u8a00\u6a21\u578bAPI\uff0c\u4f46\u4f1a\u5e26\u6765\u672c\u5730\u6027\u3001\u53ef\u91cd\u590d\u6027\u548c\u6210\u672c\u4e0a\u7684\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u6a21\u7cca\u51fd\u6570\u7f16\u7a0b\u7684\u65b9\u6cd5\uff0c\u5c06\u81ea\u7136\u8bed\u8a00\u63cf\u8ff0\u7684\u51fd\u6570\u7f16\u8bd1\u6210\u7d27\u51d1\u7684\u3001\u53ef\u672c\u5730\u6267\u884c\u7684\u795e\u7ecf\u7f51\u7edc\u5bf9\u8c61\u3002</li>\n    <li>\u6211\u4eec\u7528\u201c\u6743\u91cd\u4f5c\u4e3a\u7a0b\u5e8f\u201d\uff08PAW\uff09\u6765\u5b9e\u73b0\u8fd9\u4e00\u7406\u5ff5\uff0c\u4f7f\u7528\u4e00\u4e2a\u5728FuzzyBench\u4e0a\u8bad\u7ec3\u76844B\u7f16\u8bd1\u5668\u751f\u6210\u9ad8\u6548\u7684\u9002\u914d\u5668\u3002</li>\n    <li>PAW\u4f7f\u57fa\u7840\u6a21\u578b\u4ece\u5355\u4e2a\u8f93\u5165\u7684\u95ee\u9898\u6c42\u89e3\u8005\u8f6c\u53d8\u4e3a\u5de5\u5177\u6784\u5efa\u8005\uff0c\u751f\u6210\u7684\u5c0f\u578b\u53ef\u91cd\u7528\u5bf9\u8c61\u5728\u540e\u7eed\u8c03\u7528\u65f6\u6210\u672c\u4f4e\u4e14\u53ef\u4ee5\u79bb\u7ebf\u4f7f\u7528\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Many programming tasks are hard to automate with strict rules and are often handled by large language model APIs, which can be costly and less reliable.</li>\n    <li>We introduce fuzzy-function programming, which creates a function based on a natural-language description that can run locally and efficiently.</li>\n    <li>Our method, called Program-as-Weights (PAW), uses a specific compiler trained on a large dataset we created called FuzzyBench.</li>\n    <li>A smaller interpreter can execute PAW programs with performance similar to a much larger model, but it uses significantly less memory and is faster.</li>\n    <li>PAW allows for the creation of small, reusable programming tools, making repeated function calls cheaper and able to be run offline.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "Program-as-Weights: A Programming Paradigm for Fuzzy Functions", "summary": "Many everyday programming tasks resist clean rule-based implementation, such as alerting on important log lines, repairing malformed JSON, or ranking search results by intent, and are increasingly outsourced to large language model APIs at the cost of locality, reproducibility, and price. We propose fuzzy-function programming: compiling such a function from a natural-language specification into a compact, locally-executable neural artifact. We instantiate this paradigm with Program-as-Weights (PAW), in which a 4B compiler trained on FuzzyBench, a 10M-example dataset we release, emits parameter-efficient adapters for a frozen, lightweight interpreter. A 0.6B Qwen3 interpreter executing PAW programs matches the performance of direct prompting of Qwen3-32B, while using roughly one fiftieth of the inference memory and running at 30 tokens/s on a MacBook M3. PAW reframes the foundation model from a per-input problem solver into a tool builder: invoked once per function definition, it produces a small reusable artifact whose subsequent calls per function application are cheap and offline.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/DH3lU8-hbyZWRqfSacODD.gif", "https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/W2Xef_bIMFzQiSojtgz2i.gif", "https://cdn-uploads.huggingface.co/production/uploads/63081e15a670ed10f9d44229/ipYvADQRDJEz7f2zqZg0M.gif"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02512.png", "numComments": 2, "submittedBy": {"_id": "63081e15a670ed10f9d44229", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/63081e15a670ed10f9d44229/w1b9uq-9774bMMgJbSPsS.jpeg", "fullname": "Yuntian Deng", "name": "yuntian-deng", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 271, "isUserFollowing": false}, "organization": {"_id": "6230c3ced93e84e2338765f3", "name": "UWaterloo", "fullname": "University of Waterloo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1647363004040-6230c34bacb94a81eec91ed5.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04438", "authors": [{"_id": "6a4c62a325849b193a834020", "name": "Lingao Xiao", "hidden": false}, {"_id": "6a4c62a325849b193a834021", "name": "Yalun Dai", "hidden": false}, {"_id": "6a4c62a325849b193a834022", "name": "Yangyu Huang", "hidden": false}, {"_id": "6a4c62a325849b193a834023", "name": "Qihao Zhao", "hidden": false}, {"_id": "6a4c62a325849b193a834024", "name": "Wenshan Wu", "hidden": false}, {"_id": "6a4c62a325849b193a834025", "name": "Hugo He", "hidden": false}, {"_id": "6a4c62a325849b193a834026", "name": "Ruishuo Chen", "hidden": false}, {"_id": "6a4c62a325849b193a834027", "name": "Jin Jiang", "hidden": false}, {"_id": "6a4c62a325849b193a834028", "name": "Qianli Ma", "hidden": false}, {"_id": "6a4c62a325849b193a834029", "name": "Jiahuan Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a83402a", "name": "Xin Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a83402b", "name": "Ying Xin", "hidden": false}, {"_id": "6a4c62a325849b193a83402c", "name": "Yang Ou", "hidden": false}, {"_id": "6a4c62a325849b193a83402d", "name": "Yan Xia", "hidden": false}, {"_id": "6a4c62a325849b193a83402e", "name": "Scarlett Li", "hidden": false}, {"_id": "6a4c62a325849b193a83402f", "name": "Longbo Huang", "hidden": false}, {"_id": "6a4c62a325849b193a834030", "name": "Zhipeng Zhang", "hidden": false}, {"_id": "6a4c62a325849b193a834031", "name": "Yang He", "hidden": false}, {"_id": "6a4c62a325849b193a834032", "name": "Yap Kim Hui", "hidden": false}, {"_id": "6a4c62a325849b193a834033", "name": "Yan Lu", "hidden": false}], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "ResearchStudio-Reel: Automate the Last Mile of Research from Paper to Poster, Video, and Blog", "submittedOnDailyBy": {"_id": "64c66647725ffa04b2fd6c94", "avatarUrl": "/avatars/620f63f27fa1e90423b0dc22aa8e5809.svg", "isPro": false, "fullname": "yangyu huang", "user": "yangyu90", "type": "user", "name": "yangyu90"}, "summary": "Research dissemination, turning a paper into a poster, a talk video, and a blog post, is still a manual last mile. Prior automation treats each artifact in isolation that each re-extract the paper from scratch, usually ship one-way renders the author cannot reopen in PowerPoint or Word, and gates quality on soft VLM-preference scores that plateau while load-bearing sections still read as empty. We argue this last mile is best built as a composition of skills: thin agent-readable contracts that share one upstream extractor and wrap deterministic primitives in a measured-fill loop whose exits are hard pass/fail render gates. We instantiate this as ResearchStudio-Reel, five Claude Code and Codex skills organized into one shared extractor (Paper2Assets), three editable generators (Paper2Poster, Paper2Video, Paper2Blog), and one interactive convergence layer (Paper2Reel). Paper2Assets extracts each paper once into a shared bundle that can be reused by every downstream skill; The three generators produce a print-ready poster, a synchronized talk video, and a bilingual blog that stay factually consistent and round-trip through PowerPoint or Word; Paper2Reel then binds all three into a self-contained HTML viewer whose section-level clicks jump the video, slides, captions, and blog to matching content. On the Paper2Poster benchmark, our posters lead every aesthetic and information sub-criterion against both prior automated systems and single-shot frontier LLMs, surpassing the authors' own on aesthetics under two held-out VLM judges and winning overall on 84% to 93% of papers; capability audits further show that, by uniquely pairing narration-aligned on-slide highlights with a bilingual blog gated by layout-aware DOCX repair, ResearchStudio-Reel is the only pipeline to ship all three editable artifacts. Project is available at https://aka.ms/ResearchStudio", "upvotes": 48, "discussionId": "6a4c62a325849b193a834034", "projectPage": "https://aka.ms/ResearchStudio", "ai_summary": "ResearchStudio-Reel automates research dissemination by composing specialized skills around a shared paper extractor, generating consistent and editable artifacts including posters, videos, and blogs with hard pass/fail quality gates.", "ai_keywords": ["research dissemination", "automated artifact generation", "paper extraction", "poster generation", "talk video creation", "blog post writing", "VLM preference scores", "deterministic primitives", "measured-fill loop", "render gates", "paper-to-assets extractor", "editable generators", "interactive convergence layer", "HTML viewer", "section-level navigation", "layout-aware DOCX repair", "capability audit"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "summary_zh": "<ul>\n    <li>\u7814\u7a76\u4f20\u64ad\u4ecd\u9700\u624b\u52a8\u5904\u7406\uff0c\u5c06\u8bba\u6587\u8f6c\u4e3a\u6d77\u62a5\u3001\u89c6\u9891\u548c\u535a\u5ba2\u3002</li>\n    <li>\u73b0\u6709\u7684\u81ea\u52a8\u5316\u65b9\u6cd5\u5c06\u6bcf\u4e2a\u4f5c\u54c1\u89c6\u4e3a\u72ec\u7acb\u7684\uff0c\u91cd\u65b0\u63d0\u53d6\u8bba\u6587\uff0c\u65e0\u6cd5\u5728PowerPoint\u6216Word\u4e2d\u7f16\u8f91\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e00\u79cd\u65b0\u65b9\u6cd5\uff0c\u4f7f\u7528\u5171\u4eab\u63d0\u53d6\u5668\u548c\u53ef\u7f16\u8f91\u751f\u6210\u5668\uff0c\u786e\u4fdd\u8d28\u91cf\u548c\u4e00\u81f4\u6027\u3002</li>\n    <li>ResearchStudio-Reel\u6574\u5408\u4e86\u591a\u4e2a\u6280\u80fd\uff0c\u751f\u6210\u7684\u6d77\u62a5\u3001\u89c6\u9891\u548c\u535a\u5ba2\u4e4b\u95f4\u4fdd\u6301\u4e00\u81f4\uff0c\u5e76\u53ef\u4ee5\u76f8\u4e92\u94fe\u63a5\u3002</li>\n    <li>\u5728\u6d77\u62a5\u7684\u8bc4\u4f30\u4e2d\uff0c\u6211\u4eec\u7684\u65b9\u6cd5\u5728\u7f8e\u89c2\u548c\u4fe1\u606f\u51c6\u786e\u6027\u4e0a\u8d85\u8fc7\u4e86\u5176\u4ed6\u7cfb\u7edf\uff0c\u63d0\u4f9b\u53ef\u7f16\u8f91\u7684\u6210\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Research dissemination needs improvement; current automation creates separate artifacts from papers without reuse.</li>\n    <li>This study introduces ResearchStudio-Reel, a system that uses one extractor for all outputs: a poster, video, and blog post.</li>\n    <li>Each output is editable and maintains factual consistency, allowing easy updates and formats like PowerPoint or Word.</li>\n    <li>The new posters outperform previous automated systems and show better aesthetics, winning against authors' own designs in most cases.</li>\n    <li>ResearchStudio-Reel uniquely provides a way to create and share all three types of content together in a cohesive HTML viewer.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "ResearchStudio-Reel: Automate the Last Mile of Research from Paper to Poster, Video, and Blog", "summary": "Research dissemination, turning a paper into a poster, a talk video, and a blog post, is still a manual last mile. Prior automation treats each artifact in isolation that each re-extract the paper from scratch, usually ship one-way renders the author cannot reopen in PowerPoint or Word, and gates quality on soft VLM-preference scores that plateau while load-bearing sections still read as empty. We argue this last mile is best built as a composition of skills: thin agent-readable contracts that share one upstream extractor and wrap deterministic primitives in a measured-fill loop whose exits are hard pass/fail render gates. We instantiate this as ResearchStudio-Reel, five Claude Code and Codex skills organized into one shared extractor (Paper2Assets), three editable generators (Paper2Poster, Paper2Video, Paper2Blog), and one interactive convergence layer (Paper2Reel). Paper2Assets extracts each paper once into a shared bundle that can be reused by every downstream skill; The three generators produce a print-ready poster, a synchronized talk video, and a bilingual blog that stay factually consistent and round-trip through PowerPoint or Word; Paper2Reel then binds all three into a self-contained HTML viewer whose section-level clicks jump the video, slides, captions, and blog to matching content. On the Paper2Poster benchmark, our posters lead every aesthetic and information sub-criterion against both prior automated systems and single-shot frontier LLMs, surpassing the authors' own on aesthetics under two held-out VLM judges and winning overall on 84% to 93% of papers; capability audits further show that, by uniquely pairing narration-aligned on-slide highlights with a bilingual blog gated by layout-aware DOCX repair, ResearchStudio-Reel is the only pipeline to ship all three editable artifacts. Project is available at https://aka.ms/ResearchStudio", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04438.png", "numComments": 1, "submittedBy": {"_id": "64c66647725ffa04b2fd6c94", "avatarUrl": "/avatars/620f63f27fa1e90423b0dc22aa8e5809.svg", "fullname": "yangyu huang", "name": "yangyu90", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.05373", "authors": [{"_id": "6a4c7b9a25849b193a83420d", "user": {"_id": "659765e22235d4056ba80c0a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/659765e22235d4056ba80c0a/dATESmijLO3CpD1sCMezg.jpeg", "isPro": true, "fullname": "Gao Sensen", "user": "Sensen02", "type": "user", "name": "Sensen02"}, "name": "Sensen Gao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:05.204Z", "hidden": false}, {"_id": "6a4c7b9a25849b193a83420e", "name": "Zhaoqing Wang", "hidden": false}, {"_id": "6a4c7b9a25849b193a83420f", "user": {"_id": "652f52a07636538890b2132b", "avatarUrl": "/avatars/ac9e39e8bdb21c9d5aab2e3912e23bb4.svg", "isPro": false, "fullname": "Cao", "user": "Belta", "type": "user", "name": "Belta"}, "name": "Qihang Cao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:11:03.424Z", "hidden": false}, {"_id": "6a4c7b9a25849b193a834210", "name": "Dongdong Yu", "hidden": false}, {"_id": "6a4c7b9a25849b193a834211", "name": "Changhu Wang", "hidden": false}, {"_id": "6a4c7b9a25849b193a834212", "name": "Jia-Wang Bian", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/eZc0n0VWyqyIeKdOzMwrE.mp4"], "publishedAt": "2026-07-06T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "PixWorld: Unifying 3D Scene Generation and Reconstruction in Pixel Space", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "3D reconstruction and generation are commonly tackled by separate paradigms: pixel-based regression for reconstruction, and latent diffusion for generation. Recent works attempt to unify them in latent space, but with notable drawbacks: the diffusion objective is defined on latent features rather than the underlying 3D representation, and both branches suffer from information loss introduced by latent encoding, while requiring a pretrained Variational Autoencoder (VAE) or Representation Autoencoder (RAE). In this paper, we reformulate these two tasks under a unified pixel-space diffusion paradigm and introduce PixWorld, a single model that jointly addresses 3D reconstruction and generation. By supervising diffusion directly on rendered images, PixWorld removes the above limitations and aligns optimization with 3D scene fidelity. Beyond photometric and perceptual supervision that operates at the 2D image level and lacks 3D geometric awareness, we further introduce a geometry perception loss that aligns rendered views with their ground truth in the geometry-aware feature space of a pretrained 3D foundation model, providing 3D structural supervision. PixWorld consistently outperforms prior latent-space generation methods and matches state-of-the-art reconstruction methods, demonstrating the superiority of a unified pixel-space approach.", "upvotes": 46, "discussionId": "6a4c7b9a25849b193a834213", "projectPage": "https://sensengao.github.io/PixWorld/", "githubRepo": "https://github.com/SensenGao/PixWorld", "githubRepoAddedBy": "user", "ai_summary": "PixWorld presents a unified pixel-space diffusion approach for 3D reconstruction and generation that overcomes limitations of latent-space methods through direct image-level supervision and geometry-aware feature alignment.", "ai_keywords": ["3D reconstruction", "3D generation", "latent space", "pixel space", "diffusion models", "Variational Autoencoder", "Representation Autoencoder", "3D foundation model", "geometry perception loss", "rendered images", "3D scene fidelity"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 60, "organization": {"_id": "6508b28cf36bb51c50faad98", "name": "NanyangTechnologicalUniversity", "fullname": "Nanyang Technological University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZPD1fvei0bcIGeDXxeSkn.png"}, "summary_zh": "<ul>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86\u4e00\u79cd\u540d\u4e3aPixWorld\u7684\u6a21\u578b\uff0c\u7528\u4e8e\u540c\u65f6\u8fdb\u884c3D\u91cd\u5efa\u548c\u751f\u6210\u3002</li>\n    <li>PixWorld\u901a\u8fc7\u76f4\u63a5\u5728\u6e32\u67d3\u56fe\u50cf\u4e0a\u8fdb\u884c\u6269\u6563\u76d1\u7763\uff0c\u514b\u670d\u4e86\u4f20\u7edf\u65b9\u6cd5\u7684\u5c40\u9650\u6027\u3002</li>\n    <li>\u5f15\u5165\u4e86\u4e00\u79cd\u51e0\u4f55\u611f\u77e5\u635f\u5931\uff0c\u4f7f\u5f97\u751f\u6210\u7684\u89c6\u56fe\u4e0e\u771f\u5b9e\u7684\u51e0\u4f55\u7279\u5f81\u5bf9\u9f50\uff0c\u63d0\u4f9b\u4e863D\u7ed3\u6784\u76d1\u7763\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5728\u6027\u80fd\u4e0a\u8d85\u8fc7\u4e86\u5148\u524d\u7684\u6f5c\u5728\u7a7a\u95f4\u751f\u6210\u65b9\u6cd5\uff0c\u5e76\u4e0e\u6700\u5148\u8fdb\u7684\u91cd\u5efa\u65b9\u6cd5\u76f8\u5339\u914d\u3002</li>\n    <li>\u901a\u8fc7\u7edf\u4e00\u7684\u50cf\u7d20\u7a7a\u95f4\u65b9\u6cd5\uff0cPixWorld\u57283D\u573a\u666f\u4fdd\u771f\u5ea6\u4e0a\u5b9e\u73b0\u4e86\u4f18\u5316\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>3D reconstruction and generation are usually done separately using different methods, but this paper presents a new approach called PixWorld that combines them.</li>\n    <li>Previous methods faced issues like loss of information and reliance on complex models, which PixWorld aims to overcome.</li>\n    <li>PixWorld works directly with rendered images, improving the quality of 3D scene representation.</li>\n    <li>It introduces a new loss function that helps align 3D geometry with rendered images, enhancing accuracy.</li>\n    <li>The results show that PixWorld performs better than previous methods, offering a more effective way to handle 3D tasks.</li>\n</ul>"}, "publishedAt": "2026-07-05T20:00:00.000Z", "title": "PixWorld: Unifying 3D Scene Generation and Reconstruction in Pixel Space", "summary": "3D reconstruction and generation are commonly tackled by separate paradigms: pixel-based regression for reconstruction, and latent diffusion for generation. Recent works attempt to unify them in latent space, but with notable drawbacks: the diffusion objective is defined on latent features rather than the underlying 3D representation, and both branches suffer from information loss introduced by latent encoding, while requiring a pretrained Variational Autoencoder (VAE) or Representation Autoencoder (RAE). In this paper, we reformulate these two tasks under a unified pixel-space diffusion paradigm and introduce PixWorld, a single model that jointly addresses 3D reconstruction and generation. By supervising diffusion directly on rendered images, PixWorld removes the above limitations and aligns optimization with 3D scene fidelity. Beyond photometric and perceptual supervision that operates at the 2D image level and lacks 3D geometric awareness, we further introduce a geometry perception loss that aligns rendered views with their ground truth in the geometry-aware feature space of a pretrained 3D foundation model, providing 3D structural supervision. PixWorld consistently outperforms prior latent-space generation methods and matches state-of-the-art reconstruction methods, demonstrating the superiority of a unified pixel-space approach.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/eZc0n0VWyqyIeKdOzMwrE.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.05373.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 329, "isUserFollowing": false}, "organization": {"_id": "6508b28cf36bb51c50faad98", "name": "NanyangTechnologicalUniversity", "fullname": "Nanyang Technological University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZPD1fvei0bcIGeDXxeSkn.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.04439", "authors": [{"_id": "6a4c5adf25849b193a833fd1", "user": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "isPro": false, "fullname": "Qihao Zhao", "user": "fistyyyy", "type": "user", "name": "fistyyyy"}, "name": "Qihao Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:12:17.157Z", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd2", "name": "Yangyu Huang", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd3", "name": "Yalun Dai", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd4", "name": "Lingao Xiao", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd5", "name": "Jianjun Gao", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd6", "name": "Xin Zhang", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd7", "name": "Wenshan Wu", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd8", "name": "Scarlett Li", "hidden": false}, {"_id": "6a4c5adf25849b193a833fd9", "name": "Yang He", "hidden": false}, {"_id": "6a4c5adf25849b193a833fda", "name": "Yan Lu", "hidden": false}, {"_id": "6a4c5adf25849b193a833fdb", "name": "Yap Kim Hui", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/MDoRDZtb3QpHIytJQBTD5.mp4", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/95tKjcpM-MTgx3C5m4lqg.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/knPM5EC_CLs-0klHvD02y.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/D4hgPM0W71Cj94MbhfU6h.gif"], "publishedAt": "2026-07-05T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "ResearchStudio-Idea: An Evidence-Grounded Research-Ideation Skill Suite from ML Conference Outcomes", "submittedOnDailyBy": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "isPro": false, "fullname": "Qihao Zhao", "user": "fistyyyy", "type": "user", "name": "fistyyyy"}, "summary": "Large language models have made research ideation increasingly accessible, yet effective idea development requires more than generating candidate directions. Researchers must ground a problem in current literature, identify meaningful bottlenecks, differentiate from existing solutions, and evaluate risks before committing to implementation. We present ResearchStudio-Idea as a reusable skill suite for this first mile of research ideation. The suite includes Paper-Search, a standalone multi-source literature search skill; Scoop-Check, a standalone prior-art collision checker for novelty claims; and IdeaSpark, the end-to-end skill that composes evidence grounding, pattern-guided generation, collision retrieval, audit, and idea-card rendering into one workflow. IdeaSpark is constructed from a corpus of 1,947 machine learning conference papers collected from ICLR, ICML, and NeurIPS between 2021 and 2025, including Oral papers, a separately tracked high-citation subset, and rejected submissions. Analysis of these outcomes reveals 31 recurring ideation sub-patterns, consolidated into 15 reusable ideation patterns. Each pattern is operationalized as a structured card containing research contexts, bottleneck types, differentiation strategies, supporting precedents, and common failure modes. Given a research problem and an evidence bundle, IdeaSpark evaluates evidence readiness, reconstructs the surrounding research context, identifies unresolved bottlenecks, selects relevant patterns, instantiates one candidate direction, retrieves potentially conflicting prior work, and performs outcome-informed auditing. This workflow transforms reusable ideation patterns into traceable research proposals. Blind automated-judge evaluations show that IdeaSpark consistently produces stronger research proposals than no-skill and generic-skill baselines while maintaining competitive novelty.", "upvotes": 40, "discussionId": "6a4c5ae025849b193a833fdc", "projectPage": "https://aka.ms/ResearchStudio", "githubRepo": "https://github.com/microsoft/ResearchStudio", "githubRepoAddedBy": "user", "ai_summary": "ResearchStudio-Idea provides a skill suite for effective research ideation that combines literature search, novelty checking, and pattern-guided generation to produce traceable research proposals.", "ai_keywords": ["research ideation", "literature search", "prior-art collision checker", "pattern-guided generation", "evidence grounding", "idea-card rendering", "reusable ideation patterns", "research context", "bottleneck identification", "differentiation strategies", "prior work retrieval", "outcome-informed auditing"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 181, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "summary_zh": "<ul>\n  <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u4f7f\u7814\u7a76\u521b\u610f\u66f4\u5bb9\u6613\u83b7\u53d6\uff0c\u4f46\u6709\u6548\u7684\u521b\u610f\u53d1\u5c55\u9700\u8981\u66f4\u591a\u6b65\u9aa4\u3002</li>\n  <li>ResearchStudio-Idea\u662f\u4e00\u4e2a\u53ef\u91cd\u590d\u4f7f\u7528\u7684\u5de5\u5177\u5957\u4ef6\uff0c\u5e2e\u52a9\u7814\u7a76\u4eba\u5458\u4ece\u751f\u6210\u60f3\u6cd5\u5230\u5b9e\u65bd\u7684\u8fc7\u7a0b\u3002</li>\n  <li>\u8be5\u5957\u4ef6\u5305\u62ec\u6587\u732e\u641c\u7d22\u5de5\u5177Paper-Search\u548c\u65b0\u9896\u6027\u68c0\u67e5\u5de5\u5177Scoop-Check\uff0c\u4ee5\u53ca\u6574\u5408\u591a\u4e2a\u529f\u80fd\u7684IdeaSpark\u3002</li>\n  <li>IdeaSpark\u5229\u7528\u4ece2021\u52302025\u5e74\u6536\u96c6\u76841947\u7bc7\u673a\u5668\u5b66\u4e60\u4f1a\u8bae\u8bba\u6587\uff0c\u5206\u6790\u51fa31\u79cd\u53cd\u590d\u51fa\u73b0\u7684\u521b\u610f\u5b50\u6a21\u5f0f\u3002</li>\n  <li>IdeaSpark\u80fd\u591f\u8bc4\u4f30\u8bc1\u636e\u7684\u51c6\u5907\u60c5\u51b5\uff0c\u8bc6\u522b\u74f6\u9888\uff0c\u5e76\u751f\u6210\u53ef\u8ffd\u8e2a\u7684\u7814\u7a76\u63d0\u6848\uff0c\u6548\u679c\u4f18\u4e8e\u4f20\u7edf\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language models help generate research ideas, but developing those ideas requires more steps.</li>\n    <li>ResearchStudio-Idea is a toolkit designed to assist in the early stages of research ideation.</li>\n    <li>The toolkit includes tools for literature searching, checking for originality, and a comprehensive workflow for creating research proposals.</li>\n    <li>IdeaSpark analyzes a large dataset of machine learning papers to identify common patterns and helps structure research proposals.</li>\n    <li>Tests show that IdeaSpark produces better research proposals compared to other methods while still being original.</li>\n</ul>"}, "publishedAt": "2026-07-04T20:00:00.000Z", "title": "ResearchStudio-Idea: An Evidence-Grounded Research-Ideation Skill Suite from ML Conference Outcomes", "summary": "Large language models have made research ideation increasingly accessible, yet effective idea development requires more than generating candidate directions. Researchers must ground a problem in current literature, identify meaningful bottlenecks, differentiate from existing solutions, and evaluate risks before committing to implementation. We present ResearchStudio-Idea as a reusable skill suite for this first mile of research ideation. The suite includes Paper-Search, a standalone multi-source literature search skill; Scoop-Check, a standalone prior-art collision checker for novelty claims; and IdeaSpark, the end-to-end skill that composes evidence grounding, pattern-guided generation, collision retrieval, audit, and idea-card rendering into one workflow. IdeaSpark is constructed from a corpus of 1,947 machine learning conference papers collected from ICLR, ICML, and NeurIPS between 2021 and 2025, including Oral papers, a separately tracked high-citation subset, and rejected submissions. Analysis of these outcomes reveals 31 recurring ideation sub-patterns, consolidated into 15 reusable ideation patterns. Each pattern is operationalized as a structured card containing research contexts, bottleneck types, differentiation strategies, supporting precedents, and common failure modes. Given a research problem and an evidence bundle, IdeaSpark evaluates evidence readiness, reconstructs the surrounding research context, identifies unresolved bottlenecks, selects relevant patterns, instantiates one candidate direction, retrieves potentially conflicting prior work, and performs outcome-informed auditing. This workflow transforms reusable ideation patterns into traceable research proposals. Blind automated-judge evaluations show that IdeaSpark consistently produces stronger research proposals than no-skill and generic-skill baselines while maintaining competitive novelty.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/MDoRDZtb3QpHIytJQBTD5.mp4", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/95tKjcpM-MTgx3C5m4lqg.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/knPM5EC_CLs-0klHvD02y.png", "https://cdn-uploads.huggingface.co/production/uploads/665fc7da4058eea6b2209b67/D4hgPM0W71Cj94MbhfU6h.gif"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.04439.png", "numComments": 1, "submittedBy": {"_id": "665fc7da4058eea6b2209b67", "avatarUrl": "/avatars/665db54d3877400c1d55b416637cd02f.svg", "fullname": "Qihao Zhao", "name": "fistyyyy", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "5e6485f787403103f9f1055e", "name": "microsoft", "fullname": "Microsoft", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1583646260758-5e64858c87403103f9f1055d.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.02440", "authors": [{"_id": "6a47557d6ee372f6920de3fa", "name": "Zhilin Wang", "hidden": false}, {"_id": "6a47557d6ee372f6920de3fb", "name": "Han Song", "hidden": false}, {"_id": "6a47557d6ee372f6920de3fc", "name": "Runzhe Zhan", "hidden": false}, {"_id": "6a47557d6ee372f6920de3fd", "name": "Jusen Du", "hidden": false}, {"_id": "6a47557d6ee372f6920de3fe", "name": "Jiacheng Chen", "hidden": false}, {"_id": "6a47557d6ee372f6920de3ff", "name": "Tianle Li", "hidden": false}, {"_id": "6a47557d6ee372f6920de400", "name": "Qingyu Yin", "hidden": false}, {"_id": "6a47557d6ee372f6920de401", "name": "Yulun Wu", "hidden": false}, {"_id": "6a47557d6ee372f6920de402", "name": "Zhennan Shen", "hidden": false}, {"_id": "6a47557d6ee372f6920de403", "name": "Tong Zhu", "hidden": false}, {"_id": "6a47557d6ee372f6920de404", "name": "Yanshu Li", "hidden": false}, {"_id": "6a47557d6ee372f6920de405", "name": "Guanjie Chen", "hidden": false}, {"_id": "6a47557d6ee372f6920de406", "name": "Derek F. Wong", "hidden": false}, {"_id": "6a47557d6ee372f6920de407", "name": "Yafu Li", "hidden": false}, {"_id": "6a47557d6ee372f6920de408", "name": "Yu Cheng", "hidden": false}, {"_id": "6a47557d6ee372f6920de409", "name": "Yang Yang", "hidden": false}], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-03T00:00:00.000Z", "title": "EvoPolicyGym: Evaluating Autonomous Policy Evolution in Interactive Environments", "submittedOnDailyBy": {"_id": "6453cb22908e259483c0a061", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6453cb22908e259483c0a061/ABwBd4mL-q8ktAceEE-Ub.jpeg", "isPro": false, "fullname": "MikaStars39", "user": "MikaStars39", "type": "user", "name": "MikaStars39"}, "summary": "Autonomous agents are increasingly expected to improve executable policies through feedback, yet existing evaluations often collapse this process into a final score or confound it with open-ended software-engineering progress. We introduce Autonomous Policy Evolution, a controlled evaluation setting in which a harness-model agent repeatedly edits an executable policy system under a fixed interaction budget. We instantiate this setting in EvoPolicyGym, a benchmark built from compact interactive RL environments that evaluates how agents iteratively improve explored policies. On the EvoPolicyGym suite, GPT-5.5 achieves the strongest aggregate rank score and top-two performance on all 16 environments. Beyond leaderboard results, EvoPolicyGym also provides trajectory-level diagnostics that distinguish how agents allocate budget, convert feedback into parametric tuning. These analyses show that strong autonomous policy evolution depends not only on isolated task wins, but on discovering task-appropriate mechanisms and refining policies under bounded feedback.", "upvotes": 39, "discussionId": "6a47557d6ee372f6920de40a", "ai_summary": "Autonomous agents evaluate policy improvement through iterative editing within fixed budgets, revealing that successful policy evolution requires both task-specific mechanisms and feedback-constrained refinement.", "ai_keywords": ["autonomous agents", "executable policies", "policy evolution", "reinforcement learning", "trajectory-level diagnostics", "parametric tuning", "task-appropriate mechanisms"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u81ea\u4e3b\u4ee3\u7406\u88ab\u671f\u671b\u901a\u8fc7\u53cd\u9988\u6539\u5584\u53ef\u6267\u884c\u7b56\u7565\uff0c\u4f46\u73b0\u6709\u8bc4\u4f30\u5f80\u5f80\u7b80\u5316\u4e3a\u6700\u7ec8\u5f97\u5206\u3002</li>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86\u81ea\u4e3b\u7b56\u7565\u6f14\u5316\uff08Autonomous Policy Evolution\uff09\uff0c\u5728\u56fa\u5b9a\u7684\u4e92\u52a8\u9884\u7b97\u4e0b\uff0c\u4ee3\u7406\u53cd\u590d\u7f16\u8f91\u53ef\u6267\u884c\u7b56\u7565\u7cfb\u7edf\u3002</li>\n    <li>EvoPolicyGym\u662f\u4e00\u4e2a\u57fa\u51c6\u6d4b\u8bd5\uff0c\u901a\u8fc7\u7d27\u51d1\u7684\u4e92\u52a8\u5f3a\u5316\u5b66\u4e60\u73af\u5883\u8bc4\u4f30\u4ee3\u7406\u5982\u4f55\u9010\u6b65\u6539\u5584\u7b56\u7565\u3002</li>\n    <li>\u5728EvoPolicyGym\u4e2d\uff0cGPT-5.5\u572816\u4e2a\u73af\u5883\u4e2d\u8868\u73b0\u6700\u4f73\uff0c\u83b7\u5f97\u4e86\u6700\u9ad8\u7684\u7efc\u5408\u6392\u540d\u5206\u6570\u3002</li>\n    <li>EvoPolicyGym\u8fd8\u63d0\u4f9b\u4e86\u9010\u8f68\u8ff9\u7684\u8bca\u65ad\uff0c\u663e\u793a\u51fa\u5f3a\u5927\u7684\u81ea\u4e3b\u7b56\u7565\u6f14\u5316\u4f9d\u8d56\u4e8e\u53d1\u73b0\u9002\u5f53\u7684\u4efb\u52a1\u673a\u5236\u548c\u5728\u6709\u9650\u53cd\u9988\u4e0b\u4f18\u5316\u7b56\u7565\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Autonomous agents are expected to improve their decision-making policies based on feedback.</li>\n    <li>The study introduces a new evaluation method called Autonomous Policy Evolution to assess this improvement process.</li>\n    <li>EvoPolicyGym is a benchmark created to test how agents can iteratively enhance their policies in interactive environments.</li>\n    <li>GPT-5.5 performed the best in EvoPolicyGym, achieving high scores across all tested environments.</li>\n    <li>The evaluation offers detailed insights into how agents use their resources and adjust their strategies based on feedback.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "EvoPolicyGym: Evaluating Autonomous Policy Evolution in Interactive Environments", "summary": "Autonomous agents are increasingly expected to improve executable policies through feedback, yet existing evaluations often collapse this process into a final score or confound it with open-ended software-engineering progress. We introduce Autonomous Policy Evolution, a controlled evaluation setting in which a harness-model agent repeatedly edits an executable policy system under a fixed interaction budget. We instantiate this setting in EvoPolicyGym, a benchmark built from compact interactive RL environments that evaluates how agents iteratively improve explored policies. On the EvoPolicyGym suite, GPT-5.5 achieves the strongest aggregate rank score and top-two performance on all 16 environments. Beyond leaderboard results, EvoPolicyGym also provides trajectory-level diagnostics that distinguish how agents allocate budget, convert feedback into parametric tuning. These analyses show that strong autonomous policy evolution depends not only on isolated task wins, but on discovering task-appropriate mechanisms and refining policies under bounded feedback.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02440.png", "numComments": 1, "submittedBy": {"_id": "6453cb22908e259483c0a061", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6453cb22908e259483c0a061/ABwBd4mL-q8ktAceEE-Ub.jpeg", "fullname": "MikaStars39", "name": "MikaStars39", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 12, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2607.02255", "authors": [{"_id": "6a4737d06ee372f6920de3a5", "name": "Xiangchen Cheng", "hidden": false}, {"_id": "6a4737d06ee372f6920de3a6", "name": "Yunwei Jiang", "hidden": false}, {"_id": "6a4737d06ee372f6920de3a7", "name": "Jianwen Sun", "hidden": false}, {"_id": "6a4737d06ee372f6920de3a8", "name": "Zizhen Li", "hidden": false}, {"_id": "6a4737d06ee372f6920de3a9", "name": "Chuanhao Li", "hidden": false}, {"_id": "6a4737d06ee372f6920de3aa", "name": "Xiangcheng Cao", "hidden": false}, {"_id": "6a4737d06ee372f6920de3ab", "name": "Yihao Liu", "hidden": false}, {"_id": "6a4737d06ee372f6920de3ac", "name": "Fanrui Zhang", "hidden": false}, {"_id": "6a4737d06ee372f6920de3ad", "name": "Li Jin", "hidden": false}, {"_id": "6a4737d06ee372f6920de3ae", "name": "Kaipeng Zhang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65f1713552c38a91e0a445e8/VfdW9Ibqn4VsFUc2vbBDG.mp4"], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-03T00:00:00.000Z", "title": "AgenticSTS: A Bounded-Memory Testbed for Long-Horizon LLM Agents", "submittedOnDailyBy": {"_id": "65f1713552c38a91e0a445e8", "avatarUrl": "/avatars/47ab3ada51c9b9976ac1cd0c4301c373.svg", "isPro": false, "fullname": "kaipeng", "user": "kpzhang996", "type": "user", "name": "kpzhang996"}, "summary": "Memory for a long-horizon LLM agent is a contract about what each future decision is allowed to see. The simplest contract appends past observations, tool calls, and reflections to every prompt, which makes prior context easy to access but also turns it into a jumbled mixture in which the effect of any single memory component is hard to isolate. We introduce and instrument an alternative bounded contract: every decision is made from a fresh user message assembled by typed retrieval, with no raw cross-decision transcript appended. The prompt thus stays bounded across runs of any length, and any single layer can be ablated in isolation. We instantiate the contract in Slay the Spire 2, a closed-rule stochastic deck-building game whose runs require hundreds of tactical and strategic decisions. A public online benchmark of frontier LLMs on the same game reports zero wins at the lowest difficulty across five configurations, and the developer-reported human win rate at the same difficulty is 16%; the task is hard but not saturated. Within our harness, a fixed-A0 ablation shows the largest observed difference when triggered strategic skills are enabled: the no-store baseline wins 3/10 games and adding the skill layer 6/10. At this sample size the comparison is directional rather than statistically decisive (Fisher exact p\\approx0.37); a cross-backbone probe and public accumulating-context baselines are reported as operational comparisons rather than controlled tests of the contract variable itself. We release a reproducible testbed: 298 completed trajectories with condition tags, frozen memory/skill snapshots, prompt records, and analysis scripts -- an agent design and a validated, reusable methodology for studying how explicit memory layers shape long-horizon LLM-agent decisions.", "upvotes": 39, "discussionId": "6a4737d06ee372f6920de3af", "projectPage": "https://alayalab.github.io/AgenticSTS/", "githubRepo": "https://github.com/AlayaLab/AgenticSTS", "githubRepoAddedBy": "user", "ai_summary": "A bounded contract approach for long-horizon LLM agents uses typed retrieval to assemble fresh prompts, enabling isolated analysis of memory components and demonstrating improved performance in complex decision-making tasks.", "ai_keywords": ["long-horizon LLM agent", "bounded contract", "typed retrieval", "prompt assembly", "memory layers", "strategic skills", "ablation study", "Slay the Spire 2", "conditional reasoning", "explicit memory"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 16, "organization": {"_id": "689f08c50df4fcf7fddc0b08", "name": "AlayaLab", "fullname": "Alaya Studio", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63342778d92c5842ae728aef/dNCvNz9MMshksG2xspIbM.png"}, "summary_zh": "<ul>\n    <li>\u957f\u65f6\u95f4\u8bb0\u5fc6\u7684LLM\u4ee3\u7406\u662f\u5173\u4e8e\u672a\u6765\u51b3\u7b56\u7684\u5408\u540c\uff0c\u7b80\u5355\u7684\u5408\u540c\u5c06\u8fc7\u53bb\u7684\u89c2\u5bdf\u3001\u5de5\u5177\u8c03\u7528\u548c\u53cd\u601d\u9644\u52a0\u5230\u6bcf\u4e2a\u63d0\u793a\u4e2d\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u66ff\u4ee3\u7684\u6709\u9650\u5408\u540c\uff1a\u6bcf\u4e2a\u51b3\u7b56\u90fd\u57fa\u4e8e\u65b0\u7528\u6237\u6d88\u606f\uff0c\u800c\u4e0d\u9644\u52a0\u8de8\u51b3\u7b56\u7684\u539f\u59cb\u8bb0\u5f55\u3002</li>\n    <li>\u6211\u4eec\u5728\u4e00\u6b3e\u9700\u8981\u5927\u91cf\u7b56\u7565\u51b3\u7b56\u7684\u6e38\u620f\u300aSlay the Spire 2\u300b\u4e2d\u5e94\u7528\u4e86\u8fd9\u79cd\u5408\u540c\uff0c\u7ed3\u679c\u663e\u793aLLM\u5728\u4f4e\u96be\u5ea6\u4e0b\u80dc\u7387\u4e3a\u96f6\u3002</li>\n    <li>\u5728\u6211\u4eec\u7684\u6d4b\u8bd5\u4e2d\uff0c\u542f\u7528\u7b56\u7565\u6280\u80fd\u540e\uff0cLLM\u7684\u80dc\u7387\u4ece30%\u63d0\u9ad8\u523060%\uff0c\u4f46\u7ed3\u679c\u5c1a\u672a\u8fbe\u5230\u7edf\u8ba1\u663e\u8457\u6027\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86\u4e00\u4e2a\u53ef\u91cd\u590d\u7684\u6d4b\u8bd5\u5e73\u53f0\uff0c\u5305\u62ec298\u4e2a\u5b8c\u6210\u7684\u8f68\u8ff9\u548c\u5206\u6790\u811a\u672c\uff0c\u4f9b\u7814\u7a76\u8bb0\u5fc6\u5c42\u5982\u4f55\u5f71\u54cdLLM\u4ee3\u7406\u51b3\u7b56\u4f7f\u7528\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Memory for long-term decision-making in LLM agents can be structured as a contract that defines what past information can influence future choices.</li>\n    <li>The traditional method combines all past experiences into each new prompt, which makes it hard to identify the influence of individual memories.</li>\n    <li>This study introduces a new approach where each decision uses a fresh message created from specific past data, keeping the prompt manageable and allowing for easier analysis of memory effects.</li>\n    <li>The new method was tested in the game Slay the Spire 2, where previous LLM models struggled to win even at the easiest level, while the new approach showed improved performance.</li>\n    <li>The researchers provided a detailed testbed with data and scripts to help others study how memory impacts the decisions of LLM agents over time.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "AgenticSTS: A Bounded-Memory Testbed for Long-Horizon LLM Agents", "summary": "Memory for a long-horizon LLM agent is a contract about what each future decision is allowed to see. The simplest contract appends past observations, tool calls, and reflections to every prompt, which makes prior context easy to access but also turns it into a jumbled mixture in which the effect of any single memory component is hard to isolate. We introduce and instrument an alternative bounded contract: every decision is made from a fresh user message assembled by typed retrieval, with no raw cross-decision transcript appended. The prompt thus stays bounded across runs of any length, and any single layer can be ablated in isolation. We instantiate the contract in Slay the Spire 2, a closed-rule stochastic deck-building game whose runs require hundreds of tactical and strategic decisions. A public online benchmark of frontier LLMs on the same game reports zero wins at the lowest difficulty across five configurations, and the developer-reported human win rate at the same difficulty is 16%; the task is hard but not saturated. Within our harness, a fixed-A0 ablation shows the largest observed difference when triggered strategic skills are enabled: the no-store baseline wins 3/10 games and adding the skill layer 6/10. At this sample size the comparison is directional rather than statistically decisive (Fisher exact p\\approx0.37); a cross-backbone probe and public accumulating-context baselines are reported as operational comparisons rather than controlled tests of the contract variable itself. We release a reproducible testbed: 298 completed trajectories with condition tags, frozen memory/skill snapshots, prompt records, and analysis scripts -- an agent design and a validated, reusable methodology for studying how explicit memory layers shape long-horizon LLM-agent decisions.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65f1713552c38a91e0a445e8/VfdW9Ibqn4VsFUc2vbBDG.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02255.png", "numComments": 2, "submittedBy": {"_id": "65f1713552c38a91e0a445e8", "avatarUrl": "/avatars/47ab3ada51c9b9976ac1cd0c4301c373.svg", "fullname": "kaipeng", "name": "kpzhang996", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 10, "isUserFollowing": false}, "organization": {"_id": "689f08c50df4fcf7fddc0b08", "name": "AlayaLab", "fullname": "Alaya Studio", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63342778d92c5842ae728aef/dNCvNz9MMshksG2xspIbM.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.02501", "authors": [{"_id": "6a4a68cfd66e8ea154bc8079", "name": "Ling Xu", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807a", "name": "Chuyu Han", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807b", "user": {"_id": "64c9bced3a3f428da6902741", "avatarUrl": "/avatars/897e149b0d661944e2d75fa708ae4b92.svg", "isPro": false, "fullname": "Borui Li", "user": "libr6", "type": "user", "name": "libr6"}, "name": "Borui Li", "status": "claimed_verified", "statusLastChangedAt": "2026-07-05T21:06:24.932Z", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807c", "name": "Hao Wu", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807d", "name": "Shiqi Jiang", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807e", "name": "Ting Cao", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc807f", "name": "Chuanyou Li", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc8080", "name": "Sheng Zhong", "hidden": false}, {"_id": "6a4a68cfd66e8ea154bc8081", "name": "Shuai Wang", "hidden": false}], "publishedAt": "2026-07-02T00:00:00.000Z", "submittedOnDailyAt": "2026-07-06T00:00:00.000Z", "title": "Embodied.cpp: A Portable Inference Runtime of Embodied AI Models on Heterogeneous Robots", "submittedOnDailyBy": {"_id": "64c9bced3a3f428da6902741", "avatarUrl": "/avatars/897e149b0d661944e2d75fa708ae4b92.svg", "isPro": false, "fullname": "Borui Li", "user": "libr6", "type": "user", "name": "libr6"}, "summary": "Embodied AI models now span vision-language-action (VLA) models and world-action models (WAMs), but practical deployment remains fragmented across model-specific Python stacks, backend assumptions, and robot-side glue code, especially on heterogeneous edge devices. Existing inference runtimes are designed mainly for request-response serving and therefore do not satisfy the runtime contract of embodied deployment: multi-rate execution inside closed-loop control, latency-first batch-1 inference on heterogeneous hardware, and extensible embodied interfaces beyond fixed token I/O. We present Embodied.cpp, a portable C++ inference runtime for embodied models. Based on an architectural analysis of representative VLA models and WAMs, Embodied.cpp captures a shared execution path and organizes it into five layers: input adapters, sequence builders, backbone execution, head plugins, and deployment adapters. The runtime provides modular multi-rate execution, latency-first fused inference, and extensible operator and I/O support, enabling deployment across heterogeneous devices, robots, and simulators through one backend abstraction. We evaluate Embodied.cpp on two VLA models, HY-VLA and pi0.5, and on a preliminary WAM benchmark using a LingBot-VA Transformer block. The VLA deployments achieve successful closed-loop execution with 100.0% and 91.0% task success rates, respectively. The WAM benchmark reduces block memory from 312.2 MiB to 88.1 MiB. These results show that Embodied.cpp improves deployment efficiency while preserving high accuracy across diverse embodied model architectures.", "upvotes": 36, "discussionId": "6a4a68cfd66e8ea154bc8082", "githubRepo": "https://github.com/SEU-PAISys/Embodied.cpp", "githubRepoAddedBy": "user", "ai_summary": "Embodied.cpp is a portable C++ runtime that enables efficient deployment of vision-language-action and world-action models across heterogeneous edge devices through modular execution layers and optimized inference.", "ai_keywords": ["Vision-language-action models", "world-action models", "inference runtime", "closed-loop control", "multi-rate execution", "latency-first inference", "fused inference", "embodied interfaces", "hardware heterogeneity", "model deployment"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 61, "organization": {"_id": "6a4a1ed8d0349cf4af0141f0", "name": "SEU-PAISys", "fullname": "PhysicalAI System Group @ SAIL Lab, Southeast University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64c9bced3a3f428da6902741/rVDcprqI4aVzfGcujJfn-.jpeg"}, "summary_zh": "<ul>\n    <li>Embodied AI\u6a21\u578b\u5305\u62ec\u89c6\u89c9-\u8bed\u8a00-\u52a8\u4f5c\u548c\u4e16\u754c-\u52a8\u4f5c\u6a21\u578b\uff0c\u4f46\u5b9e\u9645\u90e8\u7f72\u4ecd\u5b58\u5728\u95ee\u9898\uff0c\u5c24\u5176\u662f\u5728\u591a\u79cd\u8bbe\u5907\u4e0a\u3002</li>\n    <li>\u73b0\u6709\u63a8\u7406\u8fd0\u884c\u65f6\u4e3b\u8981\u7528\u4e8e\u8bf7\u6c42-\u54cd\u5e94\u670d\u52a1\uff0c\u4e0d\u9002\u5408\u95ed\u73af\u63a7\u5236\u548c\u5f02\u6784\u786c\u4ef6\u7684\u5b9e\u65f6\u9700\u6c42\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86Embodied.cpp\uff0c\u4e00\u4e2a\u53ef\u79fb\u690d\u7684C++\u63a8\u7406\u8fd0\u884c\u65f6\uff0c\u4e13\u4e3a\u8fd9\u4e9b\u6a21\u578b\u8bbe\u8ba1\u3002</li>\n    <li>Embodied.cpp\u5177\u6709\u6a21\u5757\u5316\u7684\u591a\u901f\u7387\u6267\u884c\u548c\u5ef6\u8fdf\u4f18\u5148\u63a8\u7406\uff0c\u652f\u6301\u591a\u79cd\u8bbe\u5907\u548c\u673a\u5668\u4eba\u3002</li>\n    <li>\u7ecf\u8fc7\u6d4b\u8bd5\uff0cEmbodied.cpp\u5728VLA\u6a21\u578b\u548cWAM\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u9ad8\u4efb\u52a1\u6210\u529f\u7387\u548c\u663e\u8457\u7684\u5185\u5b58\u4f18\u5316\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Embodied AI models, like VLA and WAM, face challenges in deployment due to different coding setups and hardware requirements.</li>\n    <li>Current systems are mainly designed for simple request-response tasks, not suited for complex, real-time robot controls.</li>\n    <li>Embodied.cpp is a new C++ runtime that simplifies deploying these models by organizing their execution into five layers.</li>\n    <li>This runtime allows for flexible execution and efficient use of resources across various devices and robots.</li>\n    <li>Tests show that Embodied.cpp improves deployment efficiency and maintains high accuracy in task performance.</li>\n</ul>"}, "publishedAt": "2026-07-01T20:00:00.000Z", "title": "Embodied.cpp: A Portable Inference Runtime of Embodied AI Models on Heterogeneous Robots", "summary": "Embodied AI models now span vision-language-action (VLA) models and world-action models (WAMs), but practical deployment remains fragmented across model-specific Python stacks, backend assumptions, and robot-side glue code, especially on heterogeneous edge devices. Existing inference runtimes are designed mainly for request-response serving and therefore do not satisfy the runtime contract of embodied deployment: multi-rate execution inside closed-loop control, latency-first batch-1 inference on heterogeneous hardware, and extensible embodied interfaces beyond fixed token I/O. We present Embodied.cpp, a portable C++ inference runtime for embodied models. Based on an architectural analysis of representative VLA models and WAMs, Embodied.cpp captures a shared execution path and organizes it into five layers: input adapters, sequence builders, backbone execution, head plugins, and deployment adapters. The runtime provides modular multi-rate execution, latency-first fused inference, and extensible operator and I/O support, enabling deployment across heterogeneous devices, robots, and simulators through one backend abstraction. We evaluate Embodied.cpp on two VLA models, HY-VLA and pi0.5, and on a preliminary WAM benchmark using a LingBot-VA Transformer block. The VLA deployments achieve successful closed-loop execution with 100.0% and 91.0% task success rates, respectively. The WAM benchmark reduces block memory from 312.2 MiB to 88.1 MiB. These results show that Embodied.cpp improves deployment efficiency while preserving high accuracy across diverse embodied model architectures.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.02501.png", "numComments": 1, "submittedBy": {"_id": "64c9bced3a3f428da6902741", "avatarUrl": "/avatars/897e149b0d661944e2d75fa708ae4b92.svg", "fullname": "Borui Li", "name": "libr6", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6a4a1ed8d0349cf4af0141f0", "name": "SEU-PAISys", "fullname": "PhysicalAI System Group @ SAIL Lab, Southeast University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64c9bced3a3f428da6902741/rVDcprqI4aVzfGcujJfn-.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2607.03973", "authors": [{"_id": "6a4cdda725849b193a834559", "user": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "isPro": false, "fullname": "Matan Avitan", "user": "MatanAvitan", "type": "user", "name": "MatanAvitan"}, "name": "Matan Avitan", "status": "claimed_verified", "statusLastChangedAt": "2026-07-07T12:10:26.755Z", "hidden": false}, {"_id": "6a4cdda725849b193a83455a", "name": "Yoav Goldberg", "hidden": false}, {"_id": "6a4cdda725849b193a83455b", "name": "Yanai Elazar", "hidden": false}], "publishedAt": "2026-07-04T00:00:00.000Z", "submittedOnDailyAt": "2026-07-07T00:00:00.000Z", "title": "MANCE: Manifold Aware Concept Erasure", "submittedOnDailyBy": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "isPro": false, "fullname": "Matan Avitan", "user": "MatanAvitan", "type": "user", "name": "MatanAvitan"}, "summary": "Concept erasure aims to remove a target concept from a representation while preserving the other information encoded in it. This is difficult because representations encode many concepts that are often correlated with the erasure target, so removing the target risks damaging them. We propose the Manifold Constraint Hypothesis (MCH): if natural representations concentrate on a structured, lower-dimensional manifold, then interventions should be constrained to that manifold and better preserve other information encoded in the representation during interventions. We instantiate MCH in a new concept erasure method: MANifold aware Concept Erasure (MANCE). MANCE performs iterative updates to the representations using signals from a classifier that predicts a target concept. We estimate the manifold using representations obtained from natural inputs, and then we project the concept removal update to the estimated manifold. We perform extensive evaluation on 119 settings spanning text and vision, including 13 language models, three NLP concepts, and 40 CelebA-CLIP attributes. Employing MANCE on top of previous methods shows consistent improved leakage results. We also introduce MANCE+ and MANCE++, which prepend a closed-form erasure algorithm before employing MANCE, achieving better leakage--surgicality tradeoffs relative to matched full-space updates. MANCE++, our best method, achieves state-of-the-art results on nonlinear concept erasure. These results support MCH in the erasure setting: interventions should be constrained to the natural representation manifold.", "upvotes": 32, "discussionId": "6a4cdda725849b193a83455c", "githubRepo": "https://github.com/MatanAvitan/mance", "githubRepoAddedBy": "user", "ai_summary": "Manifold constraint hypothesis enables improved concept erasure by projecting updates onto estimated representation manifolds, achieving state-of-the-art results in nonlinear concept removal.", "ai_keywords": ["concept erasure", "manifold constraint hypothesis", "representation manifold", "iterative updates", "classifier prediction", "projection", "natural representations", "nonlinear concept erasure", "surgicality"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 2, "organization": {"_id": "634a981ccf84e1cc3f610ca1", "name": "barilan", "fullname": "Bar-Ilan University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/MRvtAhVBzuzijH-vDGBjr.png"}, "summary_zh": "<ul>\n    <li>\u6982\u5ff5\u6d88\u9664\u65e8\u5728\u4ece\u8868\u793a\u4e2d\u79fb\u9664\u76ee\u6807\u6982\u5ff5\uff0c\u540c\u65f6\u4fdd\u7559\u5176\u4ed6\u4fe1\u606f\uff0c\u8fd9\u5f88\u56f0\u96be\uff0c\u56e0\u4e3a\u8868\u793a\u4e2d\u5f80\u5f80\u6709\u8bb8\u591a\u4e0e\u76ee\u6807\u6982\u5ff5\u76f8\u5173\u7684\u6982\u5ff5\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u6d41\u5f62\u7ea6\u675f\u5047\u8bbe\uff08MCH\uff09\uff0c\u8ba4\u4e3a\u81ea\u7136\u8868\u793a\u96c6\u4e2d\u5728\u4e00\u4e2a\u7ed3\u6784\u5316\u7684\u4f4e\u7ef4\u6d41\u5f62\u4e0a\uff0c\u56e0\u6b64\u5e72\u9884\u5e94\u8be5\u9650\u5236\u5728\u8fd9\u4e2a\u6d41\u5f62\u4e0a\uff0c\u4ee5\u66f4\u597d\u5730\u4fdd\u7559\u5176\u4ed6\u4fe1\u606f\u3002</li>\n    <li>\u6211\u4eec\u57fa\u4e8eMCH\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u6982\u5ff5\u6d88\u9664\u65b9\u6cd5\uff0c\u79f0\u4e3aMANifold aware Concept Erasure\uff08MANCE\uff09\uff0c\u901a\u8fc7\u5206\u7c7b\u5668\u7684\u4fe1\u53f7\u8fdb\u884c\u8fed\u4ee3\u66f4\u65b0\u3002</li>\n    <li>MANCE\u5728119\u4e2a\u8bbe\u7f6e\u4e2d\u8fdb\u884c\u4e86\u5e7f\u6cdb\u8bc4\u4f30\uff0c\u5305\u62ec\u6587\u672c\u548c\u89c6\u89c9\u4efb\u52a1\uff0c\u7ed3\u679c\u663e\u793a\u5728\u6cc4\u6f0f\u7ed3\u679c\u4e0a\u6709\u663e\u8457\u6539\u8fdb\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u4ecb\u7ecd\u4e86MANCE+\u548cMANCE++\uff0c\u524d\u8005\u5728\u4f7f\u7528MANCE\u4e4b\u524d\u5f15\u5165\u4e86\u5c01\u95ed\u5f62\u5f0f\u7684\u6d88\u9664\u7b97\u6cd5\uff0c\u540e\u8005\u662f\u6211\u4eec\u6700\u597d\u7684\u65b9\u6cd5\uff0c\u5728\u975e\u7ebf\u6027\u6982\u5ff5\u6d88\u9664\u4e0a\u8fbe\u5230\u4e86\u6700\u5148\u8fdb\u7684\u7ed3\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Concept erasure tries to remove specific information from a data representation while keeping other relevant details intact.</li>\n    <li>The Manifold Constraint Hypothesis (MCH) suggests that if data representations are organized in a lower-dimensional space, targeted changes should stay within that space to avoid losing other important information.</li>\n    <li>We developed a new method called MANifold aware Concept Erasure (MANCE) that updates data representations while using insights from a classifier to ensure better erasure without damaging other information.</li>\n    <li>MANCE was tested extensively across different models and tasks, showing improved results in preventing unwanted information leakage compared to previous methods.</li>\n    <li>We also introduced enhanced versions, MANCE+ and MANCE++, which further improve the balance between effective erasure and preserving important details, with MANCE++ achieving the best results in nonlinear concept erasure.</li>\n</ul>"}, "publishedAt": "2026-07-03T20:00:00.000Z", "title": "MANCE: Manifold Aware Concept Erasure", "summary": "Concept erasure aims to remove a target concept from a representation while preserving the other information encoded in it. This is difficult because representations encode many concepts that are often correlated with the erasure target, so removing the target risks damaging them. We propose the Manifold Constraint Hypothesis (MCH): if natural representations concentrate on a structured, lower-dimensional manifold, then interventions should be constrained to that manifold and better preserve other information encoded in the representation during interventions. We instantiate MCH in a new concept erasure method: MANifold aware Concept Erasure (MANCE). MANCE performs iterative updates to the representations using signals from a classifier that predicts a target concept. We estimate the manifold using representations obtained from natural inputs, and then we project the concept removal update to the estimated manifold. We perform extensive evaluation on 119 settings spanning text and vision, including 13 language models, three NLP concepts, and 40 CelebA-CLIP attributes. Employing MANCE on top of previous methods shows consistent improved leakage results. We also introduce MANCE+ and MANCE++, which prepend a closed-form erasure algorithm before employing MANCE, achieving better leakage--surgicality tradeoffs relative to matched full-space updates. MANCE++, our best method, achieves state-of-the-art results on nonlinear concept erasure. These results support MCH in the erasure setting: interventions should be constrained to the natural representation manifold.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.03973.png", "numComments": 2, "submittedBy": {"_id": "656a501bb4020389029476bc", "avatarUrl": "/avatars/eaf37224879355ad2dfd2afacddcca61.svg", "fullname": "Matan Avitan", "name": "MatanAvitan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "634a981ccf84e1cc3f610ca1", "name": "barilan", "fullname": "Bar-Ilan University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/MRvtAhVBzuzijH-vDGBjr.png"}, "isAuthorParticipating": true}],
    "month": [{"paper": {"id": "2606.30534", "authors": [{"_id": "6a4334fd763f63ca3757e917", "user": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "name": "Yihao Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:27.650Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e918", "user": {"_id": "668f5478b3991ac0c3fc9c2f", "avatarUrl": "/avatars/a775853d3b88e7b1c8494ca837b5495c.svg", "isPro": false, "fullname": "yuhengji", "user": "yuheng2000", "type": "user", "name": "yuheng2000"}, "name": "Yuheng Ji", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:25.392Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e919", "user": {"_id": "668fa476cbcaf7ab0e4c58b3", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/668fa476cbcaf7ab0e4c58b3/F5Jj-nPCjU6uxZyfkY3qw.jpeg", "isPro": false, "fullname": "Mingyu Cao", "user": "cmyopu", "type": "user", "name": "cmyopu"}, "name": "Mingyu Cao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:12.327Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91a", "user": {"_id": "671fa0de0a34a05602094909", "avatarUrl": "/avatars/e35890e1f71a8c3f4e33b35a027e180a.svg", "isPro": false, "fullname": "Yanqing Shen", "user": "syq1105", "type": "user", "name": "syq1105"}, "name": "Yanqing Shen", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:16.531Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91b", "name": "Runze Xiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91c", "user": {"_id": "67ecd5dc6b33c72fba1fc70f", "avatarUrl": "/avatars/27ff8fb1534f1d277ae03e8adc64ffba.svg", "isPro": false, "fullname": "huaihai lyu", "user": "HuaihaiLyu", "type": "user", "name": "HuaihaiLyu"}, "name": "Huaihai Lyu", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:10.262Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91d", "user": {"_id": "643613fdaaef013d1af18717", "avatarUrl": "/avatars/b4689886eaf2103d8e92f90ea5e5bc5e.svg", "isPro": false, "fullname": "Senwei Xie", "user": "jsw19", "type": "user", "name": "jsw19"}, "name": "Senwei Xie", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:51.559Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91e", "name": "Euan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91f", "name": "Klara Tian", "hidden": false}, {"_id": "6a4334fd763f63ca3757e920", "name": "Tianfeng Long", "hidden": false}, {"_id": "6a4334fd763f63ca3757e921", "name": "Yichi Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e922", "name": "Zhengliang Cai", "hidden": false}, {"_id": "6a4334fd763f63ca3757e923", "name": "Ruike Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e924", "name": "Jifan Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e925", "name": "Ruochuan Shi", "hidden": false}, {"_id": "6a4334fd763f63ca3757e926", "user": {"_id": "65fce52cb6fa00949682d41b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65fce52cb6fa00949682d41b/RZ6J1Ovix-jJW9KSiWcEk.jpeg", "isPro": false, "fullname": "Zihan Tang", "user": "tzh21", "type": "user", "name": "tzh21"}, "name": "Zihan Tang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:14.193Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e927", "name": "Jing Lyu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e928", "name": "Wenxing Tan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e929", "name": "Ningbo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92a", "name": "Yangtao Hu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92b", "name": "Yuming Gao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92c", "name": "Xiansheng Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92d", "name": "Junkai Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92e", "name": "Congsheng Xu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92f", "name": "Boan Zhu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e930", "name": "Ziqi Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e931", "name": "Yupu Feng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e932", "name": "Qiongqiong Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e933", "name": "Yingli Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e934", "name": "Yulong Ao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e935", "name": "Shaoxuan Xie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e936", "name": "You Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e937", "name": "Guocai Yao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e938", "name": "Leiduo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e939", "name": "Xiaodan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93a", "name": "Yunyan Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93b", "name": "Yance Jiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93c", "name": "Xinyan Yang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93d", "name": "Jiaxing Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93e", "name": "Xu Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93f", "name": "Tengfei Pan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e940", "name": "Shaokai Nie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e941", "name": "Chunlei Men", "hidden": false}, {"_id": "6a4334fd763f63ca3757e942", "name": "Sen Cui", "hidden": false}, {"_id": "6a4334fd763f63ca3757e943", "name": "Xiaojie Jin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e944", "name": "Hongyang Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e945", "name": "Jianlan Luo", "hidden": false}, {"_id": "6a4334fd763f63ca3757e946", "name": "Yao Mu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e947", "name": "Yunchao Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e948", "name": "Jun Yan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e949", "name": "Hang Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94a", "name": "Xiaolong Zheng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94b", "name": "Jiaming Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94c", "name": "Yonghua Lin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94d", "name": "Tiejun Huang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94e", "name": "Zhongyuan Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94f", "name": "Pengwei Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Orca: The World is in Your Mind", "submittedOnDailyBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "upvotes": 176, "discussionId": "6a4334fd763f63ca3757e950", "projectPage": "https://orca-wm.github.io/", "ai_summary": "Orca establishes a unified world latent space through next-state-prediction modeling using multimodal data and demonstrates superior performance in downstream tasks compared to specialized baselines.", "ai_keywords": ["world foundation model", "world latent space", "multimodal readout interfaces", "next-state-prediction modeling", "unconscious learning", "conscious learning", "world-learning inventory data", "embodied action generation", "downstream readouts", "modality-specific decoders"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>Orca\u662f\u4e00\u4e2a\u901a\u7528\u4e16\u754c\u57fa\u7840\u6a21\u578b\uff0c\u901a\u8fc7\u591a\u6a21\u6001\u4fe1\u53f7\u5b66\u4e60\u7edf\u4e00\u7684\u4e16\u754c\u6f5c\u5728\u7a7a\u95f4\u3002</li>\n    <li>\u5b83\u7684\u6838\u5fc3\u662f\u4e0b\u4e00\u72b6\u6001\u9884\u6d4b\u5efa\u6a21\uff0c\u800c\u4e0d\u662f\u5355\u72ec\u9884\u6d4b\u4e0b\u4e00\u4e2a\u8bcd\u3001\u5e27\u6216\u52a8\u4f5c\u3002</li>\n    <li>Orca\u901a\u8fc7\u65e0\u610f\u8bc6\u5b66\u4e60\u548c\u6709\u610f\u8bc6\u5b66\u4e60\u4e24\u79cd\u65b9\u5f0f\u8fdb\u884c\u5b66\u4e60\uff0c\u6355\u6349\u81ea\u7136\u72b6\u6001\u8f6c\u53d8\u548c\u8bed\u8a00\u63cf\u8ff0\u7684\u4e8b\u4ef6\u3002</li>\n    <li>\u9884\u8bad\u7ec3\u4f7f\u7528\u4e86125K\u5c0f\u65f6\u7684\u89c6\u9891\u6570\u636e\u548c160M\u4e8b\u4ef6\u6807\u6ce8\uff0c\u53d6\u5f97\u4e86\u826f\u597d\u7684\u6548\u679c\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cOrca\u5728\u6587\u672c\u751f\u6210\u3001\u56fe\u50cf\u9884\u6d4b\u548c\u52a8\u4f5c\u751f\u6210\u7b49\u4efb\u52a1\u4e0a\u8868\u73b0\u4f18\u4e8e\u540c\u7c7b\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Orca is a new model that learns about the world using various types of data, like videos and text.</li>\n    <li>It focuses on predicting the next state of the world instead of just predicting the next word or action.</li>\n    <li>Orca learns in two ways: by watching continuous videos (unconscious learning) and by understanding specific events described in language (conscious learning).</li>\n    <li>It was trained on a large dataset with 125,000 hours of video and 160 million event annotations.</li>\n    <li>Orca shows better performance in tasks like text generation and image prediction compared to similar models, but there are still some limitations to improve upon.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "Orca: The World is in Your Mind", "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30534.png", "numComments": 5, "submittedBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "fullname": "yh-wang", "name": "yh-wang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7684\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u63d0\u5347\u957f\u89c6\u9891\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u4e86DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\u6280\u672f\uff0c\u80fd\u591f\u5904\u7406\u9ad8\u8fbe256K\u7684\u4e0a\u4e0b\u6587\uff0c\u4e14\u4fdd\u7559\u5173\u952e\u5e27\u548c\u957f\u65f6\u95f4\u4f9d\u8d56\u4fe1\u606f\u3002</li>\n    <li>Keye-VL-2.0\u7684\u67b6\u6784\u4f18\u5316\u4e86\u8bad\u7ec3\u548c\u63a8\u7406\u57fa\u7840\u8bbe\u65bd\uff0c\u63d0\u9ad8\u4e86\u89c6\u9891\u8f93\u5165\u8f93\u51fa\u7684\u53ef\u6269\u5c55\u6027\u548c\u8ba1\u7b97\u6548\u7387\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u591a\u4efb\u52a1\u5bf9\u9f50\u4e2d\u7684\u9057\u5fd8\u95ee\u9898\uff0c\u6211\u4eec\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\u65b9\u6cd5\uff0c\u589e\u5f3a\u4e86\u6a21\u578b\u7684\u81ea\u6211\u4fee\u6b63\u80fd\u529b\u3002</li>\n    <li>\u5e7f\u6cdb\u8bc4\u4f30\u663e\u793a\uff0cKeye-VL-2.0\u5728\u89c6\u9891\u7406\u89e3\u548c\u957f\u89c6\u9891\u7406\u89e3\u65b9\u9762\u8868\u73b0\u4f18\u8d8a\uff0c\u5c24\u5176\u5728\u65f6\u95f4\u5b9a\u4f4d\u548c\u591a\u6a21\u6001\u5e94\u7528\u4e2d\u8868\u73b0\u51fa\u8272\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Kwai Keye-VL-2.0-30B-A3B is a new open-source model for understanding long videos and intelligent agents.</li>\n    <li>It uses a unique method called DeepSeek Sparse Attention to process long video contexts efficiently, handling up to 256K frames without losing important information.</li>\n    <li>The model is built on advanced technology that improves video processing and reduces computational costs.</li>\n    <li>To avoid losing important knowledge when learning multiple tasks, it uses a technique called Cross-Modal Multi-Teacher On-Policy Distillation.</li>\n    <li>Keye-VL-2.0 shows top performance in several benchmarks related to video understanding and temporal reasoning, and its resources are available for community use.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.14777", "authors": [{"_id": "6a30c3bfa0d4daae4285fefd", "name": "Dingyu Yao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285fefe", "name": "Junhao Zhou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285feff", "user": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "name": "Chenxu Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T16:15:00.215Z", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff00", "name": "Chuanyu Qin", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff01", "name": "Haowen Hou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff02", "name": "Zheming Liang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff03", "name": "Congcong Wang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff04", "name": "Yuhang Cao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff05", "name": "Shenglong Ye", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff06", "name": "Shuai Xie", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff07", "name": "Shuhuan Gu", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff08", "name": "Haoyang Huang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff09", "name": "Qingyi Si", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0a", "name": "Nan Duan", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0b", "user": {"_id": "64b4eec4faa3181a5eab9c46", "avatarUrl": "/avatars/bcc9bf5cbf67546ad2b4c9ec8b96ac96.svg", "isPro": true, "fullname": "Jiaqi Wang", "user": "myownskyW7", "type": "user", "name": "myownskyW7"}, "name": "Jiaqi Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T12:05:58.790Z", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "submittedOnDailyBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "upvotes": 157, "discussionId": "6a30c3bfa0d4daae4285ff0c", "projectPage": "https://joyai-vl-video-future-academy-jd.github.io/JoyAI-VL-Interaction/", "githubRepo": "https://github.com/jd-opensource/JoyAI-VL-Interaction", "githubRepoAddedBy": "user", "ai_summary": "A vision-language model operates continuously in real-time, making autonomous decisions about when to respond or delegate, enabling interactive systems that perceive and act upon environmental changes without user prompting.", "ai_keywords": ["vision-language model", "real-time interaction", "autonomous decision-making", "vision-triggered responsiveness", "time awareness", "background model", "deployable system", "video streaming", "interactive AI", "continuous perception"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 209, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u5b9e\u4e16\u754c\u4e2d\u8bb8\u591a\u65f6\u523b\u5e76\u4e0d\u7b49\u4eba\u53d1\u95ee\uff0c\u800c\u662f\u9700\u8981\u6a21\u578b\u4e3b\u52a8\u54cd\u5e94\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u6a21\u5f0f\u7684\u6a21\u578b\uff0c\u5b83\u50cf\u4eba\u4e00\u6837\uff0c\u6301\u7eed\u89c2\u5bdf\u5e76\u5b9e\u65f6\u4e92\u52a8\u3002</li>\n    <li>\u53d1\u5e03\u4e86\u4e00\u4e2a\u5f00\u6e90\u7684\u4ea4\u4e92\u6a21\u578bJoyAI-VL-Interaction\uff0c\u80fd\u591f\u6839\u636e\u60c5\u51b5\u51b3\u5b9a\u4f55\u65f6\u56de\u5e94\u3001\u4fdd\u6301\u6c89\u9ed8\u6216\u59d4\u6d3e\u7ed9\u540e\u53f0\u6a21\u578b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5728\u89c6\u89c9\u89e6\u53d1\u54cd\u5e94\u548c\u65f6\u95f4\u610f\u8bc6\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u5e76\u4e14\u53ef\u4ee5\u5f15\u5bfc\u8d2d\u7269\u6216\u5373\u5174\u8bb2\u5ea7\u7b49\u672a\u8bad\u7ec3\u7684\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u53d1\u5e03\u4e86\u4e00\u4e2a\u5b8c\u6574\u7684\u53ef\u90e8\u7f72\u7cfb\u7edf\uff0c\u80fd\u591f\u5b9e\u65f6\u5904\u7406\u89c6\u9891\u6d41\uff0c\u5e76\u5728\u591a\u4e2a\u771f\u5b9e\u573a\u666f\u4e2d\u8868\u73b0\u4f18\u4e8e\u73b0\u6709\u89c6\u9891\u901a\u8bdd\u52a9\u624b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current AI models only respond when asked, similar to a question-answer system.</li>\n    <li>The new model, JoyAI-VL-Interaction, continuously observes its environment and decides when to interact.</li>\n    <li>It has a vision-first approach and can choose to remain silent, respond, or ask a background model for help.</li>\n    <li>JoyAI-VL-Interaction includes a complete system that streams video and can connect to various tools and APIs.</li>\n    <li>In tests, users preferred JoyAI-VL-Interaction over existing video-call assistants significantly.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.14777.png", "numComments": 2, "submittedBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "fullname": "steven young", "name": "iieycx", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.29526", "authors": [{"_id": "6a48ce6bd66e8ea154bc7e29", "name": "Jing Liang", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2a", "name": "Hongyao Tang", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2b", "name": "Yi Ma", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2c", "name": "Yancheng He", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2d", "name": "Weixun Wang", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2e", "name": "Xiaoyang Li", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e2f", "name": "Ju Huang", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e30", "name": "Wenbo Su", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e31", "name": "Jinyi Liu", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e32", "name": "Yan Zheng", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e33", "name": "Jianye Hao", "hidden": false}, {"_id": "6a48ce6bd66e8ea154bc7e34", "name": "Bo Zheng", "hidden": false}], "publishedAt": "2026-06-28T00:00:00.000Z", "submittedOnDailyAt": "2026-07-06T00:00:00.000Z", "title": "The Mirage of Optimizing Training Policies: Monotonic Inference Policies as the Real Objective for LLM Reinforcement Learning", "submittedOnDailyBy": {"_id": "6778da4a1788ddf1c1ef323b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/AttI7uQyC151_1592Lc2H.png", "isPro": false, "fullname": "Jing Liang", "user": "AnitaLeung", "type": "user", "name": "AnitaLeung"}, "summary": "Reinforcement learning (RL) has gained growing attention in large language model (LLM) post-training, yet RL training remains fragile and can suffer from instability or collapse. One vital cause is training-inference mismatch: LLM adopts separate inference and training engines for generation efficiency and training precision, which in practice exhibits inconsistent probabilities for the same trajectories on training and inference sides, even with synchronized model parameters. This naturally induces a special type of off-policyness ever existing and poisoning the training. Prior works have made various efforts in addressing the off-policyness to stabilize the training policies under the mismatch. In this paper, we point out the objective misalignment neglected by existing works that an effective update to the policy in the training engine not necessarily ensures the improvement of the inference policy, i.e., the one used in deployment. To this end, we propose a new policy optimization objective for LLM RL, named Monotonic Inference Policy Improvement (MIPI). Following this principle, we introduce Monotonic Inference Policy Update (MIPU), a two-step LLM RL framework that constructs sampler-referenced candidate updates and selectively accepts synchronized candidates using an inference-side gap proxy. Experiments conducted on two model scales under high mismatch show that MIPU improves average reasoning performance and training stability.", "upvotes": 141, "discussionId": "6a48ce6cd66e8ea154bc7e35", "projectPage": "https://anitaleungxx.github.io/MIPU/", "ai_summary": "Training-inference mismatch in reinforcement learning for large language models leads to instability, which is addressed through a new policy optimization objective and framework that ensures consistent policy improvements between training and inference phases.", "ai_keywords": ["reinforcement learning", "large language models", "training-inference mismatch", "off-policy", "policy optimization", "policy improvement", "inference policy", "training stability", "reasoning performance"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u5f3a\u5316\u5b66\u4e60\uff08RL\uff09\u5728\u5927\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u7684\u540e\u8bad\u7ec3\u4e2d\u8d8a\u6765\u8d8a\u53d7\u5230\u5173\u6ce8\uff0c\u4f46\u8bad\u7ec3\u8fc7\u7a0b\u4e0d\u7a33\u5b9a\uff0c\u53ef\u80fd\u4f1a\u5d29\u6e83\u3002</li>\n    <li>\u8bad\u7ec3\u548c\u63a8\u7406\u4e4b\u95f4\u7684\u4e0d\u5339\u914d\u662f\u5bfc\u81f4\u4e0d\u7a33\u5b9a\u7684\u4e00\u4e2a\u91cd\u8981\u539f\u56e0\uff0c\u5373\u8bad\u7ec3\u548c\u63a8\u7406\u4f7f\u7528\u4e0d\u540c\u7684\u5f15\u64ce\uff0c\u5bfc\u81f4\u6982\u7387\u4e0d\u4e00\u81f4\u3002</li>\n    <li>\u73b0\u6709\u7814\u7a76\u4e3b\u8981\u5173\u6ce8\u89e3\u51b3\u8fd9\u79cd\u4e0d\u5339\u914d\u5bfc\u81f4\u7684\u8bad\u7ec3\u653f\u7b56\u4e0d\u7a33\u5b9a\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u653f\u7b56\u4f18\u5316\u76ee\u6807\uff0c\u79f0\u4e3a\u5355\u8c03\u63a8\u7406\u653f\u7b56\u6539\u8fdb\uff08MIPI\uff09\uff0c\u4ee5\u89e3\u51b3\u653f\u7b56\u66f4\u65b0\u4e0d\u4e00\u5b9a\u6539\u5584\u63a8\u7406\u653f\u7b56\u7684\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u63d0\u51fa\u4e86\u5355\u8c03\u63a8\u7406\u653f\u7b56\u66f4\u65b0\uff08MIPU\uff09\uff0c\u4e00\u79cd\u4e24\u6b65\u7684RL\u6846\u67b6\uff0c\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\u5b83\u80fd\u63d0\u9ad8\u63a8\u7406\u6027\u80fd\u548c\u8bad\u7ec3\u7a33\u5b9a\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement learning (RL) is important for improving large language models (LLMs), but it can be unstable and ineffective.</li>\n    <li>A key issue is the mismatch between the training and inference processes, leading to inconsistent results even with the same model parameters.</li>\n    <li>Previous research has tried to fix this mismatch, but they overlooked how updates in training don't always help the inference process used in real applications.</li>\n    <li>The authors propose a new method called Monotonic Inference Policy Improvement (MIPI) to better align training and inference objectives.</li>\n    <li>They developed a two-step framework, Monotonic Inference Policy Update (MIPU), which has shown to improve reasoning performance and stability in experiments.</li>\n</ul>"}, "publishedAt": "2026-06-27T20:00:00.000Z", "title": "The Mirage of Optimizing Training Policies: Monotonic Inference Policies as the Real Objective for LLM Reinforcement Learning", "summary": "Reinforcement learning (RL) has gained growing attention in large language model (LLM) post-training, yet RL training remains fragile and can suffer from instability or collapse. One vital cause is training-inference mismatch: LLM adopts separate inference and training engines for generation efficiency and training precision, which in practice exhibits inconsistent probabilities for the same trajectories on training and inference sides, even with synchronized model parameters. This naturally induces a special type of off-policyness ever existing and poisoning the training. Prior works have made various efforts in addressing the off-policyness to stabilize the training policies under the mismatch. In this paper, we point out the objective misalignment neglected by existing works that an effective update to the policy in the training engine not necessarily ensures the improvement of the inference policy, i.e., the one used in deployment. To this end, we propose a new policy optimization objective for LLM RL, named Monotonic Inference Policy Improvement (MIPI). Following this principle, we introduce Monotonic Inference Policy Update (MIPU), a two-step LLM RL framework that constructs sampler-referenced candidate updates and selectively accepts synchronized candidates using an inference-side gap proxy. Experiments conducted on two model scales under high mismatch show that MIPU improves average reasoning performance and training stability.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.29526.png", "numComments": 1, "submittedBy": {"_id": "6778da4a1788ddf1c1ef323b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/AttI7uQyC151_1592Lc2H.png", "fullname": "Jing Liang", "name": "AnitaLeung", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.28733", "authors": [{"_id": "6a43896919e14c76c1bfad0b", "name": "Han Luo", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0c", "name": "Bingbing Wen", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0d", "name": "Lucy Lu Wang", "hidden": false}], "publishedAt": "2026-06-27T00:00:00.000Z", "submittedOnDailyAt": "2026-06-30T00:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "submittedOnDailyBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "isPro": false, "fullname": "Han Luo", "user": "sxcn", "type": "user", "name": "sxcn"}, "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "upvotes": 120, "discussionId": "6a43896919e14c76c1bfad0e", "projectPage": "https://lhannnn.github.io/agentic-abstention", "ai_summary": "Agentic abstention involves determining when an AI agent should cease interaction under uncertainty, requiring sequential decision-making across multiple environments and task types.", "ai_keywords": ["agentic abstention", "LLM-as-agent systems", "sequential decision problem", "web shopping", "terminal environments", "question answering", "context engineering", "CONVOLVE", "stopping rules"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "summary_zh": "<ul>\n    <li>LLM\u4ee3\u7406\u9700\u5728\u591a\u8f6e\u4ea4\u4e92\u4e2d\u4f7f\u7528\u641c\u7d22\u3001\u6d4f\u89c8\u548c\u7ec8\u7aef\u5de5\u5177\u6765\u5b8c\u6210\u7528\u6237\u76ee\u6807\u3002</li>\n    <li>\u5b9a\u4e49\u4e86\u201c\u4ee3\u7406\u6027\u653e\u5f03\u201d\uff0c\u6307\u7684\u662f\u5728\u4e0d\u786e\u5b9a\u60c5\u51b5\u4e0b\u51b3\u5b9a\u4f55\u65f6\u505c\u6b62\u64cd\u4f5c\u7684\u95ee\u9898\u3002</li>\n    <li>\u7814\u7a76\u4e8613\u4e2aLLM\u4ee3\u7406\u7cfb\u7edf\u548c2\u4e2a\u4ee3\u7406\u6846\u67b6\u572828,000\u591a\u4e2a\u4efb\u52a1\u4e2d\u7684\u8868\u73b0\u3002</li>\n    <li>\u53d1\u73b0\u4e00\u4e9b\u4ee3\u7406\u5728\u5e94\u8be5\u653e\u5f03\u65f6\u4ece\u4e0d\u653e\u5f03\uff0c\u800c\u5176\u4ed6\u4ee3\u7406\u5219\u5728\u4e0d\u5fc5\u8981\u7684\u4e92\u52a8\u540e\u624d\u653e\u5f03\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u540d\u4e3aCONVOLVE\u7684\u65b9\u6cd5\uff0c\u901a\u8fc7\u63d0\u70bc\u5b8c\u6574\u7684\u4ea4\u4e92\u8f68\u8ff9\u6765\u6539\u8fdb\u4ee3\u7406\u6027\u653e\u5f03\uff0c\u63d0\u9ad8\u4e86\u53ca\u65f6\u653e\u5f03\u7684\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>LLM agents need to decide when to stop trying to achieve user goals if they are uncertain about success.</li>\n    <li>This problem, called Agentic Abstention, involves multiple rounds of actions where agents can answer, abstain, or seek more information.</li>\n    <li>Research analyzed 13 LLM agents and 2 supporting systems across over 28,000 tasks in areas like web shopping and question answering.</li>\n    <li>Findings show that some agents fail to abstain when needed, while others do so only after unnecessary attempts, especially when tasks seem possible initially.</li>\n    <li>A new method called CONVOLVE helps improve timely abstention without changing the agent's model, significantly increasing performance on certain tasks.</li>\n</ul>"}, "publishedAt": "2026-06-26T20:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.28733.png", "numComments": 8, "submittedBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "fullname": "Han Luo", "name": "sxcn", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.18023", "authors": [{"_id": "6a3201f3bc818ff14e453d61", "name": "Jian Yang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d62", "name": "Shawn Guo", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d63", "name": "Wei Zhang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d64", "user": {"_id": "64ab99dcb76bfd863eba64c1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ab99dcb76bfd863eba64c1/UBXwDPx17X-gl-SzBPvrc.jpeg", "isPro": false, "fullname": "TY.Zheng", "user": "aaabiao", "type": "user", "name": "aaabiao"}, "name": "Tianyu Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:10.407Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d65", "name": "Yaxin Du", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d66", "name": "Haau-Sing Li", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d67", "user": {"_id": "66a8e2538407031e388c501f", "avatarUrl": "/avatars/d16d51f7b1e111efd6d0985995b614be.svg", "isPro": false, "fullname": "wjj", "user": "wuyuverse", "type": "user", "name": "wuyuverse"}, "name": "Jiajun Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:12.507Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d68", "name": "Yue Song", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d69", "name": "Yan Xing", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6a", "name": "Qingsong Cai", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6b", "name": "Zelong Huang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6c", "name": "Chuan Hao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6d", "name": "Ran Tao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6e", "name": "Xianglong Liu", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6f", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d70", "name": "Mingjie Tang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d71", "name": "Weifeng Lv", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d72", "name": "Ming Zhou", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d73", "name": "Bryan Dai", "hidden": false}], "publishedAt": "2026-06-16T00:00:00.000Z", "submittedOnDailyAt": "2026-06-17T00:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "upvotes": 113, "discussionId": "6a3201f3bc818ff14e453d74", "ai_summary": "Parallel loop Transformers achieve better code generation performance with two loops due to refined representations, while additional loops cause diminishing returns and increased positional mismatch costs.", "ai_keywords": ["Looped Transformers", "parallel loop Transformers", "cross-loop position offsets", "shared-KV gated sliding-window attention", "loop-count selection", "LoopCoder-v2", "instruction tuning", "SWE-bench", "Multi-SWE"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u5faa\u73af\u53d8\u6362\u5668\u901a\u8fc7\u91cd\u590d\u5e94\u7528\u5171\u4eab\u6a21\u5757\u6765\u63d0\u9ad8\u6f5c\u5728\u8ba1\u7b97\u80fd\u529b\uff0c\u4f46\u589e\u52a0\u7684\u5faa\u73af\u6b21\u6570\u4f1a\u589e\u52a0\u5ef6\u8fdf\u548c\u5185\u5b58\u9700\u6c42\u3002</li>\n    <li>\u5e76\u884c\u5faa\u73af\u53d8\u6362\u5668\uff08PLT\uff09\u901a\u8fc7\u4ea4\u53c9\u5faa\u73af\u4f4d\u7f6e\u504f\u79fb\uff08CLP\uff09\u548c\u5171\u4eabKV\u95e8\u63a7\u6ed1\u52a8\u7a97\u53e3\u6ce8\u610f\u529b\u6765\u51cf\u8f7b\u8fd9\u4e9b\u6210\u672c\u3002</li>\n    <li>\u6211\u4eec\u7814\u7a76\u4e86PLT\u5faa\u73af\u6b21\u6570\u7684\u9009\u62e9\uff0c\u53d1\u73b0\u589e\u52a0\u5faa\u73af\u6b21\u6570\u53ef\u4ee5\u63d0\u5347\u8868\u793a\u80fd\u529b\uff0c\u4f46\u4e5f\u4f1a\u5f15\u5165\u4f4d\u7f6e\u4e0d\u5339\u914d\u7684\u95ee\u9898\u3002</li>\n    <li>\u901a\u8fc7\u8bad\u7ec3LoopCoder-v2\uff0c\u6211\u4eec\u53d1\u73b0\u4e24\u6b21\u5faa\u73af\u7684\u6548\u679c\u663e\u8457\u4f18\u4e8e\u4e0d\u5faa\u73af\u7684\u57fa\u7ebf\uff0c\u800c\u4e09\u6b21\u6216\u66f4\u591a\u5faa\u73af\u5219\u6548\u679c\u4e0b\u964d\u3002</li>\n    <li>\u7814\u7a76\u663e\u793a\uff0c\u4e24\u6b21\u5faa\u73af\u63d0\u4f9b\u4e3b\u8981\u7684\u6709\u6548\u63d0\u5347\uff0c\u540e\u7eed\u5faa\u73af\u5219\u5e26\u6765\u6536\u76ca\u9012\u51cf\u548c\u591a\u6837\u6027\u964d\u4f4e\u7684\u95ee\u9898\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Looped Transformers improve performance by using shared blocks repeatedly, but doing this in a sequence can slow things down and require more memory.</li>\n    <li>Parallel loop Transformers (PLT) help reduce these costs by using special techniques that allow for better handling of loop counts.</li>\n    <li>We studied how many loops to use in PLT by looking at the benefits and downsides of adding more loops.</li>\n    <li>Training a model called LoopCoder-v2 showed that using two loops significantly improved performance in various coding tasks, while using three or more loops led to worse results.</li>\n    <li>The study found that the second loop helped enhance model quality, but additional loops did not add much value and could even harm performance due to mismatches in data handling.</li>\n</ul>"}, "publishedAt": "2026-06-15T20:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.18023.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 319, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u5728\u9759\u6001\u73af\u5883\u4e0b\u8868\u73b0\u826f\u597d\uff0c\u4f46\u73b0\u5b9e\u73af\u5883\u662f\u52a8\u6001\u7684\uff0c\u9700\u8981\u6301\u7eed\u8c03\u6574\u3002</li>\n    <li>\u6211\u4eec\u5f15\u5165EvoArena\uff0c\u4e00\u4e2a\u8bc4\u4f30\u5de5\u5177\uff0c\u7528\u4e8e\u6a21\u62df\u73af\u5883\u53d8\u5316\uff0c\u5305\u62ec\u7ec8\u7aef\u3001\u8f6f\u4ef6\u548c\u793e\u4ea4\u9886\u57df\u7684\u6e10\u8fdb\u66f4\u65b0\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51faEvoMem\uff0c\u4e00\u79cd\u57fa\u4e8e\u8865\u4e01\u7684\u8bb0\u5fc6\u6a21\u5f0f\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u6f14\u53d8\u7684\u7ed3\u6784\u5316\u5386\u53f2\uff0c\u5e2e\u52a9\u4ee3\u7406\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5f53\u524d\u4ee3\u7406\u5728EvoArena\u4e0a\u7684\u5e73\u5747\u51c6\u786e\u7387\u4ec5\u4e3a39.6%\uff0c\u800cEvoMem\u80fd\u63d0\u9ad81.5%\u7684\u8868\u73b0\u3002</li>\n    <li>EvoMem\u8fd8\u5728\u6807\u51c6\u57fa\u51c6\u6d4b\u8bd5\uff08\u5982GAIA\u548cLoCoMo\uff09\u4e2d\u63d0\u9ad8\u4e86\u6027\u80fd\uff0c\u5f3a\u8c03\u4e86\u5efa\u6a21\u6f14\u53d8\u7684\u91cd\u8981\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model (LLM) agents perform well in tests, but most tests do not reflect real-life changing environments.</li>\n    <li>EvoArena is a new benchmark that simulates changing environments in different areas like technology and social preferences.</li>\n    <li>EvoMem is a memory system that helps agents keep track of changes in the environment, allowing them to adapt better.</li>\n    <li>Current agents only achieved about 39.6% accuracy on EvoArena, but EvoMem improved their performance by an average of 1.5%.</li>\n    <li>EvoMem also boosted performance on other standard tests and helped agents complete related tasks more effectively.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.11176", "authors": [{"_id": "6a28e548e7d78ea7587e5537", "user": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "name": "Kevin Qinghong Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:42:18.205Z", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5538", "name": "Batu EI", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5539", "name": "Yuhong Shi", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553a", "name": "Pan Lu", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553b", "name": "Philip Torr", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553c", "name": "James Zou", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "submittedOnDailyBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "upvotes": 100, "discussionId": "6a28e548e7d78ea7587e553d", "projectPage": "https://data2story.github.io/", "githubRepo": "https://github.com/QinghongLin/data2story-skill", "githubRepoAddedBy": "user", "ai_summary": "A multi-agent framework automates data journalism by generating evidence-grounded, multimodal news stories while maintaining transparency and verifiability.", "ai_keywords": ["multi-agent framework", "data journalism", "evidence-grounded", "multimodal generation", "verifiability", "article generation", "data storytelling"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 45, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "summary_zh": "<ul>\n    <li>\u6570\u636e\u8bb0\u8005\u7684\u4efb\u52a1\u662f\u5c06\u539f\u59cb\u4fe1\u606f\u8f6c\u5316\u4e3a\u53ef\u4fe1\u7684\u6545\u4e8b\u3002</li>\n    <li>Data2Story\u662f\u4e00\u4e2a\u591a\u4ee3\u7406\u6846\u67b6\uff0c\u80fd\u591f\u534f\u8c03\u4e0d\u540c\u89d2\u8272\uff0c\u5f62\u6210\u4e00\u4e2a\u865a\u62df\u65b0\u95fb\u7f16\u8f91\u5ba4\u3002</li>\n    <li>Data2Story\u7684\u521b\u65b0\u5305\u62ec\uff1a\u6bcf\u4e2a\u6570\u636e\u3001\u89d2\u5ea6\u548c\u7d20\u6750\u90fd\u6709\u8bc1\u636e\u652f\u6301\uff0c\u4e14\u6587\u7ae0\u53ef\u4ee5\u751f\u6210\u591a\u79cd\u5a92\u4f53\u5f62\u5f0f\u3002</li>\n    <li>\u5728\u6d4b\u8bd5\u4e2d\uff0cData2Story\u4ea7\u751f\u4e86\u53ef\u7ade\u4e89\u7684\u591a\u5a92\u4f53\u6545\u4e8b\uff0c\u7279\u522b\u5728\u900f\u660e\u6027\u548c\u53ef\u5ba1\u6838\u6027\u65b9\u9762\u8868\u73b0\u51fa\u8272\u3002</li>\n    <li>\u5c3d\u7ba1Data2Story\u8868\u73b0\u826f\u597d\uff0c\u4f46\u4eba\u7c7b\u8bb0\u8005\u5728\u7f16\u8f91\u89c6\u89d2\u3001\u521b\u610f\u8bbe\u8ba1\u548c\u5448\u73b0\u65b9\u9762\u4ecd\u6709\u4f18\u52bf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Data journalists turn raw data into trustworthy stories for the public.</li>\n    <li>Data2Story is a new tool that combines different roles in journalism into one system.</li>\n    <li>It connects every claim in an article back to original data for better transparency.</li>\n    <li>Data2Story can create multimedia articles using tools like interactive maps and audio.</li>\n    <li>While it does well in transparency and evidence, human journalists still excel in creativity and presentation.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.11176.png", "numComments": 4, "submittedBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "fullname": "Qinghong (Kevin) Lin", "name": "KevinQHLin", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 49, "isUserFollowing": false}, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.19195", "authors": [{"_id": "6a3407a3fc3a8b1102d9442a", "user": {"_id": "66d0ba2420e64fc408564bbb", "avatarUrl": "/avatars/355566cfb6347750a5faab7c87fcb79c.svg", "isPro": false, "fullname": "Anduin Dan", "user": "AnduinD", "type": "user", "name": "AnduinD"}, "name": "Kangsheng Duan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:45.706Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442b", "user": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "name": "Ziyang Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:28.418Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442c", "name": "Wenyu Liu", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442d", "name": "Xiaohu Ruan", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442e", "name": "Xiaoxin Chen", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442f", "name": "Xinggang Wang", "hidden": false}], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "submittedOnDailyBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "upvotes": 97, "discussionId": "6a3407a3fc3a8b1102d94430", "projectPage": "https://hustvl.github.io/Moebius", "githubRepo": "https://github.com/hustvl/Moebius", "githubRepoAddedBy": "user", "ai_summary": "A lightweight image inpainting framework achieves high-fidelity results with significantly reduced parameters and inference time through novel local-global interaction blocks and adaptive distillation strategies.", "ai_keywords": ["diffusion backbone", "Local-\u03bb Mix Interaction", "L\u03bbMI block", "spatial contexts", "global semantic priors", "fixed-size linear matrices", "representation bottleneck", "adaptive multi-granularity distillation", "latent space", "gradient-based losses", "high-fidelity inpainting", "parameter-efficient fine-tuning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 52, "summary_zh": "<ul>\n    <li>Moebius\u662f\u4e00\u4e2a\u9ad8\u6548\u7684\u8f7b\u91cf\u7ea7\u56fe\u50cf\u4fee\u590d\u6846\u67b6\uff0c\u65e8\u5728\u964d\u4f4e\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u5b83\u901a\u8fc7Local-\u03bb Mix Interaction (L\u03bbMI)\u6a21\u5757\u91cd\u6784\u6269\u6563\u7f51\u7edc\uff0c\u4fdd\u6301\u590d\u6742\u7684\u6f5c\u5728\u4ea4\u4e92\u3002</li>\n    <li>\u7ed3\u5408\u81ea\u9002\u5e94\u591a\u7c92\u5ea6\u84b8\u998f\u7b56\u7565\uff0cMoebius\u5728\u6f5c\u5728\u7a7a\u95f4\u5185\u64cd\u4f5c\uff0c\u907f\u514d\u6602\u8d35\u7684\u50cf\u7d20\u7a7a\u95f4\u89e3\u7801\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cMoebius\u5728\u751f\u6210\u8d28\u91cf\u4e0a\u53ef\u4e0e10B\u7ea7\u7684FLUX.1-Fill-Dev\u76f8\u6bd4\uff0c\u751a\u81f3\u8d85\u8d8a\u3002</li>\n    <li>Moebius\u4f7f\u7528\u7684\u53c2\u6570\u4e0d\u52302%\uff0c\u63a8\u7406\u65f6\u95f4\u52a0\u5feb\u8d85\u8fc715\u500d\uff0c\u8bbe\u5b9a\u4e86\u9ad8\u4fdd\u771f\u4fee\u590d\u7684\u65b0\u6807\u51c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Moebius is a new lightweight framework for image inpainting, designed to be more efficient than larger models.</li>\n    <li>It uses a unique structure called the Local-\u03bb Mix Interaction (L\u03bbMI) block to summarize important image information while reducing the number of parameters needed.</li>\n    <li>The framework includes a special technique for fine-tuning, which helps to improve image quality without costly computations.</li>\n    <li>Moebius performs comparably or better than a much larger model, FLUX.1-Fill-Dev, while using significantly fewer resources.</li>\n    <li>It achieves over 15 times faster processing, setting a new standard for efficient and high-quality image inpainting.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19195.png", "numComments": 4, "submittedBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "fullname": "Ziyang Xu", "name": "Uyoung", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13432", "authors": [{"_id": "6a2b941e4957fcdd3aac074c", "name": "Jiwen Liu", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074d", "user": {"_id": "64e57e521412b511e4388310", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64e57e521412b511e4388310/1DL-B1TJL9jEcnsy4N_46.jpeg", "isPro": false, "fullname": "Shujuan Li", "user": "lisj575", "type": "user", "name": "lisj575"}, "name": "Shujuan Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:24.073Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074e", "name": "Zhixue Fang", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074f", "name": "Xiaohan Li", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0750", "name": "Yan Zhou", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0751", "name": "Zijie Meng", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0752", "user": {"_id": "65e67be231de1c098be18f5f", "avatarUrl": "/avatars/1dfc363140f5161d8b06ba0ad948530b.svg", "isPro": false, "fullname": "Zhimin Zhang", "user": "zmmm", "type": "user", "name": "zmmm"}, "name": "Zhimin Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-15T12:23:04.022Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0753", "user": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "isPro": false, "fullname": "yawenluo", "user": "yawenluo", "type": "user", "name": "yawenluo"}, "name": "Yawen Luo", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T08:13:30.433Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0754", "name": "Guoxin Zhang", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0755", "name": "Yu-Shen Liu", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0756", "name": "Pengfei Wan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66743477ab975c859114d410/DZYTYGj5Ahz1xIFKDRkIZ.mp4"], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-15T00:00:00.000Z", "title": "OmniDirector: General Multi-Shot Camera Cloning without Cross-Paired Data", "submittedOnDailyBy": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "isPro": false, "fullname": "yawenluo", "user": "yawenluo", "type": "user", "name": "yawenluo"}, "summary": "Cloning camera motion from reference videos is an important task in video generation, as videos provide intuitive and precise control. Existing methods either directly use parametric representations that fail to handle multi-shot generation or synthesize cross-paired data, which suffer from data scarcity, resulting in poor performance in complicated camera motion cloning. To address these issues, we introduce a general camera motion representation that encodes cameras as grid motion videos. This camera grid represents the camera parameters visually and supports the integration of diverse trajectories for multi-shot video generation. Building upon this, we propose OmniDirector, a unified framework trained on a million-scale camera grid-video pairs that coordinates characters, actions, and cameras to provide director-level control for multimodal diffusion transformers. Furthermore, we design a novel hierarchical prompt expansion agent that harmoniously integrates different control signals by systematically describing camera motion and visual content through understanding signal relationships. Extensive experiments demonstrate the superior performance and outstanding controllability of our framework. Project page: https://ymlinfeng.github.io/OmniDirector.github.io/", "upvotes": 91, "discussionId": "6a2b941f4957fcdd3aac0757", "projectPage": "https://ymlinfeng.github.io/OmniDirector.github.io/", "githubRepo": "https://github.com/lisj575/OmniDirector", "githubRepoAddedBy": "user", "ai_summary": "A unified framework for camera motion cloning that uses grid motion videos as representation and integrates multimodal diffusion transformers for enhanced video generation control.", "ai_keywords": ["camera motion cloning", "camera grid", "multimodal diffusion transformers", "hierarchical prompt expansion agent", "video generation", "parametric representations", "cross-paired data", "camera parameters", "grid motion videos", "director-level control"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 27, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "summary_zh": "<ul>\n    <li>\u514b\u9686\u76f8\u673a\u8fd0\u52a8\u662f\u89c6\u9891\u751f\u6210\u4e2d\u7684\u91cd\u8981\u4efb\u52a1\uff0c\u53ef\u4ee5\u63d0\u4f9b\u76f4\u89c2\u548c\u7cbe\u786e\u7684\u63a7\u5236\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u5b58\u5728\u5904\u7406\u591a\u955c\u5934\u751f\u6210\u80fd\u529b\u4e0d\u8db3\u548c\u6570\u636e\u7a00\u7f3a\u7684\u95ee\u9898\uff0c\u5bfc\u81f4\u590d\u6742\u76f8\u673a\u8fd0\u52a8\u514b\u9686\u6548\u679c\u5dee\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u76f8\u673a\u8fd0\u52a8\u8868\u793a\u65b9\u5f0f\uff0c\u901a\u8fc7\u7f51\u683c\u8fd0\u52a8\u89c6\u9891\u6765\u7f16\u7801\u76f8\u673a\u53c2\u6570\uff0c\u652f\u6301\u591a\u955c\u5934\u89c6\u9891\u751f\u6210\u3002</li>\n    <li>\u5f00\u53d1\u4e86OmniDirector\u6846\u67b6\uff0c\u5229\u7528\u767e\u4e07\u89c4\u6a21\u7684\u76f8\u673a\u7f51\u683c\u89c6\u9891\u5bf9\u8fdb\u884c\u8bad\u7ec3\uff0c\u5b9e\u73b0\u89d2\u8272\u3001\u52a8\u4f5c\u548c\u76f8\u673a\u7684\u534f\u8c03\u63a7\u5236\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u5c42\u6b21\u5316\u63d0\u793a\u6269\u5c55\u4ee3\u7406\uff0c\u7cfb\u7edf\u6027\u5730\u63cf\u8ff0\u76f8\u673a\u8fd0\u52a8\u548c\u89c6\u89c9\u5185\u5bb9\uff0c\u63d0\u9ad8\u4e86\u63a7\u5236\u4fe1\u53f7\u7684\u6574\u5408\u6548\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Cloning camera motion from videos is important for creating videos with precise control.</li>\n    <li>Current methods struggle with multi-shot video generation and often have data limitations.</li>\n    <li>We developed a new way to represent camera motion using grid motion videos, allowing for better multi-shot integration.</li>\n    <li>Our framework, called OmniDirector, uses a large dataset to coordinate characters, actions, and camera movements for better video control.</li>\n    <li>We also created a unique system to combine different control signals for improved camera motion and visual content understanding.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "OmniDirector: General Multi-Shot Camera Cloning without Cross-Paired Data", "summary": "Cloning camera motion from reference videos is an important task in video generation, as videos provide intuitive and precise control. Existing methods either directly use parametric representations that fail to handle multi-shot generation or synthesize cross-paired data, which suffer from data scarcity, resulting in poor performance in complicated camera motion cloning. To address these issues, we introduce a general camera motion representation that encodes cameras as grid motion videos. This camera grid represents the camera parameters visually and supports the integration of diverse trajectories for multi-shot video generation. Building upon this, we propose OmniDirector, a unified framework trained on a million-scale camera grid-video pairs that coordinates characters, actions, and cameras to provide director-level control for multimodal diffusion transformers. Furthermore, we design a novel hierarchical prompt expansion agent that harmoniously integrates different control signals by systematically describing camera motion and visual content through understanding signal relationships. Extensive experiments demonstrate the superior performance and outstanding controllability of our framework. Project page: https://ymlinfeng.github.io/OmniDirector.github.io/", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66743477ab975c859114d410/DZYTYGj5Ahz1xIFKDRkIZ.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13432.png", "numComments": 3, "submittedBy": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "fullname": "yawenluo", "name": "yawenluo", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "isAuthorParticipating": true}]
};
